  { id: 'p1', address: '123 Maple St', unit: 'Apt 4B', monthlyRent: 1500 },
  { id: 'p2', address: '456 Oak Ave', unit: 'Unit 2', monthlyRent: 2200 },
  { id: 'p3', address: '789 Pine Ln', unit: 'House', monthlyRent: 3100 },
];

export const INITIAL_TENANTS: Tenant[] = [
  { id: 't1', name: 'John Doe', email: 'john@example.com', phone: '555-0101', propertyId: 'p1', leaseStart: '2023-01-01', leaseEnd: '2024-01-01' },
