                activeTab === item.id
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20'
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span className="font-medium">{item.label}</span>
            </button>
          ))}
        </nav>
        <div className="p-6 border-t border-slate-800">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-indigo-500 flex items-center justify-center font-bold">JD</div>
            <div>
              <p className="text-sm font-medium">John Landlord</p>
              <p className="text-xs text-slate-400">Manager Account</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto relative p-8">
        <div className="max-w-7xl mx-auto">
          {children}
        </div>
      </main>
    </div>
  );
};

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Tenant, Property, Invoice } from '../types';

interface DashboardProps {
  tenants: Tenant[];
  properties: Property[];
  invoices: Invoice[];
}

export const Dashboard: React.FC<DashboardProps> = ({ tenants, properties, invoices }) => {
  const totalRevenue = invoices
    .filter(i => i.status === 'Paid')
    .reduce((sum, i) => sum + i.amount, 0);

  const outstandingBalance = invoices
    .filter(i => i.status !== 'Paid')
    .reduce((sum, i) => sum + i.amount, 0);

  const occupancyRate = properties.length > 0 
    ? (tenants.length / properties.length) * 100 
    : 0;

  const data = [
    { name: 'Jan', revenue: 4000 },
    { name: 'Feb', revenue: 3000 },
    { name: 'Mar', revenue: 2000 },
    { name: 'Apr', revenue: 2780 },
    { name: 'May', revenue: 1890 },
    { name: 'Jun', revenue: 2390 },
    { name: 'Jul', revenue: 3490 },
  ];

  const statusData = [
    { name: 'Paid', value: invoices.filter(i => i.status === 'Paid').length },
    { name: 'Pending', value: invoices.filter(i => i.status === 'Pending').length },
    { name: 'Overdue', value: invoices.filter(i => i.status === 'Overdue').length },
  ];

  const COLORS = ['#10b981', '#f59e0b', '#ef4444'];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header>
        <h2 className="text-3xl font-bold text-slate-900">Dashboard</h2>
        <p className="text-slate-500 mt-1">Overview of your property portfolio.</p>
      </header>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Collected" value={`$${totalRevenue.toLocaleString()}`} icon="💰" color="bg-emerald-50 text-emerald-600" />
        <StatCard title="Outstanding" value={`$${outstandingBalance.toLocaleString()}`} icon="⏳" color="bg-amber-50 text-amber-600" />
        <StatCard title="Active Tenants" value={tenants.length.toString()} icon="👥" color="bg-blue-50 text-blue-600" />
        <StatCard title="Occupancy Rate" value={`${occupancyRate.toFixed(1)}%`} icon="🏠" color="bg-indigo-50 text-indigo-600" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Revenue Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold mb-6">Revenue Trend</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b'}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b'}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="revenue" fill="#4f46e5" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Status Distribution */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold mb-6">Invoice Status</h3>
          <div className="h-[300px] flex flex-col items-center justify-center">
            <ResponsiveContainer width="100%" height="80%">
              <PieChart>
                <Pie
                  data={statusData}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="flex gap-4 mt-4">
              {statusData.map((entry, index) => (
                <div key={entry.name} className="flex items-center gap-1.5">
                  <div className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[index]}}></div>
                  <span className="text-xs text-slate-500 font-medium">{entry.name}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Recent Activity */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
          <h3 className="font-semibold text-slate-800">Latest Invoices</h3>
          <button className="text-indigo-600 text-sm font-medium hover:underline">View All</button>
        </div>
        <div className="divide-y divide-slate-50">
          {invoices.slice(0, 5).map((invoice) => {
            const tenant = tenants.find(t => t.id === invoice.tenantId);
            return (
              <div key={invoice.id} className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg ${
                    invoice.status === 'Paid' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'
                  }`}>
                    📄
                  </div>
                  <div>
                    <p className="font-medium text-slate-900">{tenant?.name || 'Unknown Tenant'}</p>
                    <p className="text-xs text-slate-500">{invoice.description} • Due {invoice.dueDate}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="font-semibold text-slate-900">${invoice.amount}</p>
                  <span className={`inline-block px-2 py-0.5 text-[10px] font-bold rounded-full uppercase tracking-wider ${
                    invoice.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                    invoice.status === 'Pending' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                  }`}>
                    {invoice.status}
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color }: { title: string, value: string, icon: string, color: string }) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 transition-transform hover:scale-[1.02]">
    <div className="flex justify-between items-start">
      <div>
        <p className="text-slate-500 text-sm font-medium">{title}</p>
        <p className="text-2xl font-bold text-slate-900 mt-1">{value}</p>
      </div>
      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl ${color}`}>
        {icon}
      </div>
    </div>
  </div>
);

import React, { useState } from 'react';
import { Tenant, Property } from '../types';

interface TenantsProps {
  tenants: Tenant[];
  properties: Property[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
}

export const Tenants: React.FC<TenantsProps> = ({ tenants, properties, setTenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newTenant, setNewTenant] = useState<Partial<Tenant>>({
    name: '',
    email: '',
    phone: '',
    propertyId: '',
    leaseStart: '',
    leaseEnd: '',
  });

  const handleAddTenant = (e: React.FormEvent) => {
    e.preventDefault();
    const tenant: Tenant = {
      id: `t${Date.now()}`,
      name: newTenant.name!,
      email: newTenant.email!,
      phone: newTenant.phone!,
      propertyId: newTenant.propertyId!,
      leaseStart: newTenant.leaseStart!,
      leaseEnd: newTenant.leaseEnd!,
    };
    setTenants(prev => [...prev, tenant]);
    setIsModalOpen(false);
    setNewTenant({});
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Tenants</h2>
          <p className="text-slate-500 mt-1">Manage your tenant information and leases.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-200"
        >
          <span>➕</span> Add Tenant
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {tenants.map((tenant) => {
          const property = properties.find(p => p.id === tenant.propertyId);
          return (
            <div key={tenant.id} className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 hover:shadow-md transition-shadow group">
              <div className="flex justify-between items-start mb-4">
                <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center text-xl font-bold text-slate-600 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors">
                  {tenant.name.charAt(0)}
                </div>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button className="text-slate-400 hover:text-indigo-600">✏️</button>
                  <button className="text-slate-400 hover:text-red-600">🗑️</button>
                </div>
              </div>
              <h3 className="text-lg font-bold text-slate-900">{tenant.name}</h3>
              <p className="text-sm text-slate-500 mb-4">{property?.address} - {property?.unit}</p>

              <div className="space-y-3">
                <div className="flex items-center gap-3 text-sm text-slate-600">
                  <span className="text-slate-400">📧</span> {tenant.email}
                </div>
                <div className="flex items-center gap-3 text-sm text-slate-600">
                  <span className="text-slate-400">📞</span> {tenant.phone}
                </div>
                <div className="pt-4 border-t border-slate-50 mt-4 flex justify-between items-center">
                  <div className="text-[10px] uppercase font-bold tracking-wider text-slate-400">Lease Ends</div>
                  <div className="text-sm font-semibold text-slate-700">{tenant.leaseEnd}</div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Add Tenant Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-900">Register New Tenant</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleAddTenant} className="p-8 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Full Name</label>
                  <input 
                    required 
                    className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none" 
                    placeholder="Jane Doe"
                    onChange={e => setNewTenant({...newTenant, name: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Email</label>
                  <input 
                    required 
                    type="email"
                    className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none" 
                    placeholder="jane@example.com"
                    onChange={e => setNewTenant({...newTenant, email: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Phone</label>
                  <input 
                    required 
                    className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none" 
                    placeholder="555-0000"
                    onChange={e => setNewTenant({...newTenant, phone: e.target.value})}
                  />
                </div>
                <div className="col-span-2">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Property</label>
                  <select 
                    required 
                    className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none"
                    onChange={e => setNewTenant({...newTenant, propertyId: e.target.value})}
                  >
                    <option value="">Select a property</option>
                    {properties.map(p => <option key={p.id} value={p.id}>{p.address} ({p.unit})</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Lease Start</label>
                  <input 
                    required 
                    type="date"
                    className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none"
                    onChange={e => setNewTenant({...newTenant, leaseStart: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Lease End</label>
                  <input 
                    required 
                    type="date"
                    className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none"
                    onChange={e => setNewTenant({...newTenant, leaseEnd: e.target.value})}
                  />
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-2.5 rounded-xl border border-slate-200 font-semibold text-slate-600 hover:bg-slate-50">Cancel</button>
                <button type="submit" className="flex-1 px-4 py-2.5 rounded-xl bg-indigo-600 text-white font-semibold hover:bg-indigo-700">Add Tenant</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Invoice, Tenant, InvoiceStatus } from '../types';

interface InvoicesProps {
  invoices: Invoice[];
  tenants: Tenant[];
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
}

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, setInvoices }) => {
  const [filter, setFilter] = useState<InvoiceStatus | 'All'>('All');

  const filteredInvoices = filter === 'All' 
    ? invoices 
    : invoices.filter(i => i.status === filter);

  const toggleStatus = (id: string) => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id === id) {
        const nextStatus: Record<InvoiceStatus, InvoiceStatus> = {
          'Pending': 'Paid',
          'Paid': 'Overdue',
          'Overdue': 'Pending'
        };
        return { ...inv, status: nextStatus[inv.status] };
      }
      return inv;
    }));
  };

