import React, { useState } from 'react';
import { generateCommunication, getFinancialInsights } from '../services/geminiService';
import { Tenant, Invoice, Property } from '../types';

interface AIAssistantProps {
  tenants: Tenant[];
  invoices: Invoice[];
  properties: Property[];
}

export const AIAssistant: React.FC<AIAssistantProps> = ({ tenants, invoices, properties }) => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [mode, setMode] = useState<'insights' | 'comm'>('insights');
  const [selectedTenantId, setSelectedTenantId] = useState('');

  const handleGetInsights = async () => {
    setLoading(true);
    const insights = await getFinancialInsights({ tenants, invoices, properties });
    setResult(insights);
    setLoading(false);
  };

  const handleGenerateComm = async () => {
    if (!selectedTenantId) return;
    setLoading(true);
    const tenant = tenants.find(t => t.id === selectedTenantId);
    const lastInvoice = invoices.filter(i => i.tenantId === selectedTenantId).pop();

    if (tenant && lastInvoice) {
      const comm = await generateCommunication(tenant.name, lastInvoice.status, lastInvoice.amount);
      setResult(comm);
    } else {
      setResult("Could not find relevant tenant or invoice data.");
    }
    setLoading(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header>
        <h2 className="text-3xl font-bold text-slate-900">AI Portfolio Assistant</h2>
        <p className="text-slate-500 mt-1">Harness the power of Gemini to manage your business.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <span className="text-indigo-600">⚡</span> Quick Actions
            </h3>
            <div className="space-y-3">
              <button 
                onClick={() => { setMode('insights'); handleGetInsights(); }}
                disabled={loading}
                className="w-full flex items-center justify-between p-4 rounded-xl border border-indigo-50 hover:bg-indigo-50/50 text-left transition-all group disabled:opacity-50"
              >
                <div>
                  <p className="font-bold text-slate-800">Portfolio Health Check</p>
                  <p className="text-xs text-slate-500">Analyze cash flow and risk trends</p>
                </div>
                <span className="group-hover:translate-x-1 transition-transform">→</span>
              </button>

              <div className="p-4 rounded-xl border border-slate-100">
                <p className="font-bold text-slate-800 mb-2">Draft Notification</p>
                <p className="text-xs text-slate-500 mb-4">Auto-generate a message for a tenant based on status</p>
                <div className="flex gap-2">
                  <select 
                    value={selectedTenantId}
                    onChange={(e) => setSelectedTenantId(e.target.value)}
