                  >
                    <option value="">Select tenant...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                  <button 
                    onClick={() => { setMode('comm'); handleGenerateComm(); }}
                    disabled={loading || !selectedTenantId}
                    className="bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-slate-800 disabled:opacity-50 transition-colors"
                  >
                    Draft
                  </button>
                </div>
              </div>
            </div>
          </div>

          <div className="bg-indigo-600 rounded-2xl p-6 text-white shadow-xl shadow-indigo-200">
            <h4 className="font-bold mb-2">Pro Tip</h4>
            <p className="text-indigo-100 text-sm leading-relaxed">
              Use the insights tool after adding new properties or invoices to see how your ROI is shifting in real-time.
            </p>
          </div>
        </div>

        {/* Result Area */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden min-h-[400px] flex flex-col">
