import { INITIAL_TENANTS, INITIAL_PROPERTIES, INITIAL_INVOICES } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [tenants, setTenants] = useState<Tenant[]>(() => {
    const saved = localStorage.getItem('tenants');
    return saved ? JSON.parse(saved) : INITIAL_TENANTS;
  });
  const [properties, setProperties] = useState<Property[]>(() => {
    const saved = localStorage.getItem('properties');
    return saved ? JSON.parse(saved) : INITIAL_PROPERTIES;
  });
  const [invoices, setInvoices] = useState<Invoice[]>(() => {
    const saved = localStorage.getItem('invoices');
    return saved ? JSON.parse(saved) : INITIAL_INVOICES;
  });

  useEffect(() => {
    localStorage.setItem('tenants', JSON.stringify(tenants));
    localStorage.setItem('properties', JSON.stringify(properties));
    localStorage.setItem('invoices', JSON.stringify(invoices));
  }, [tenants, properties, invoices]);

  const clearAllData = () => {
    if (window.confirm("WARNING: This will permanently delete all tenants, properties, and invoices. This action cannot be undone. Are you sure?")) {
      setTenants([]);
      setProperties([]);
      setInvoices([]);
      localStorage.clear();
      setActiveTab('dashboard');
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
      case 'tenants':
        return <Tenants tenants={tenants} properties={properties} setTenants={setTenants} />;
      case 'invoices':
        return <Invoices invoices={invoices} tenants={tenants} setInvoices={setInvoices} />;
      case 'properties':
        return <Properties properties={properties} setProperties={setProperties} />;
      case 'assistant':
        return <AIAssistant tenants={tenants} invoices={invoices} properties={properties} />;
      case 'settings':
        return <SystemSettings onReset={clearAllData} />;
      default:
        return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

