  const statusData = [
    { name: 'Paid', value: invoices.filter(i => i.status === 'Paid').length },
    { name: 'Pending', value: invoices.filter(i => i.status === 'Pending').length },
    { name: 'Overdue', value: invoices.filter(i => i.status === 'Overdue').length },
