import React, { useState, useRef } from 'react';
import { Tenant, Property } from '../types';

interface TenantsProps {
  tenants: Tenant[];
  properties: Property[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
}

export const Tenants: React.FC<TenantsProps> = ({ tenants, properties, setTenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [newTenant, setNewTenant] = useState<Partial<Tenant>>({
    name: '',
    email: '',
    phone: '',
    propertyId: '',
    leaseStart: '',
    leaseEnd: '',
  });

  const handleAddTenant = (e: React.FormEvent) => {
    e.preventDefault();
    const tenant: Tenant = {
      id: `t${Date.now()}`,
      name: newTenant.name!,
      email: newTenant.email!,
      phone: newTenant.phone!,
      propertyId: newTenant.propertyId!,
      leaseStart: newTenant.leaseStart!,
      leaseEnd: newTenant.leaseEnd!,
    };
    setTenants(prev => [...prev, tenant]);
    setIsModalOpen(false);
    setNewTenant({});
  };

  const exportCSV = () => {
    const headers = ['id', 'name', 'email', 'phone', 'propertyId', 'leaseStart', 'leaseEnd'];
    const rows = tenants.map(t => [t.id, t.name, t.email, t.phone, t.propertyId, t.leaseStart, t.leaseEnd].join(','));
    const csvContent = [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `tenants_export_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const [headerLine, ...lines] = text.split('\n');
      const importedTenants: Tenant[] = lines
        .filter(line => line.trim())
        .map(line => {
          const [id, name, email, phone, propertyId, leaseStart, leaseEnd] = line.split(',');
          return { id, name, email, phone, propertyId, leaseStart, leaseEnd };
        });

      if (window.confirm(`Found ${importedTenants.length} tenants. Replace current list?`)) {
        setTenants(importedTenants);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Tenants</h2>
          <p className="text-slate-500 mt-1">Manage your tenant information and leases.</p>
        </div>
        <div className="flex items-center gap-2">
          <input type="file" accept=".csv" ref={fileInputRef} className="hidden" onChange={handleImportCSV} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="bg-white border border-slate-200 text-slate-700 px-4 py-2.5 rounded-xl font-medium hover:bg-slate-50 transition-colors flex items-center gap-2 shadow-sm"
          >
            📥 Import
          </button>
          <button 
            onClick={exportCSV}
            className="bg-white border border-slate-200 text-slate-700 px-4 py-2.5 rounded-xl font-medium hover:bg-slate-50 transition-colors flex items-center gap-2 shadow-sm"
          >
            📤 Export
          </button>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>➕</span> Add Tenant
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {tenants.map((tenant) => {
          const property = properties.find(p => p.id === tenant.propertyId);
          return (
            <div key={tenant.id} className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 hover:shadow-md transition-shadow group">
              <div className="flex justify-between items-start mb-4">
                <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center text-xl font-bold text-slate-600 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors">
                  {tenant.name?.charAt(0) || '?'}
                </div>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button className="text-slate-400 hover:text-indigo-600">✏️</button>
                  <button 
                    onClick={() => setTenants(prev => prev.filter(t => t.id !== tenant.id))}
                    className="text-slate-400 hover:text-red-600"
                  >
                    🗑️
                  </button>
                </div>
              </div>
              <h3 className="text-lg font-bold text-slate-900">{tenant.name}</h3>
              <p className="text-sm text-slate-500 mb-4">{property?.address || 'No Property'} - {property?.unit || 'No Unit'}</p>

              <div className="space-y-3">
