        <p className="text-slate-500 mt-1">Real-time overview of your collections.</p>
      </header>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Total Collected" value={`₹${totalCollected.toLocaleString()}`} icon="💵" color="bg-emerald-50 text-emerald-600" />
        <StatCard title="Total Pending" value={`₹${totalPending.toLocaleString()}`} icon="⏳" color="bg-amber-50 text-amber-600" />
        <StatCard title="Total Overdue" value={`₹${totalOverdue.toLocaleString()}`} icon="🚨" color="bg-rose-50 text-rose-600" />
        <StatCard title="Occupancy" value={`${occupancyRate.toFixed(1)}%`} icon="🏠" color="bg-slate-50 text-slate-600" />
      </div>

