import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { Tenants } from './components/Tenants';
import { Invoices } from './components/Invoices';
import { Properties } from './components/Properties';
import { Expenses } from './components/Expenses';
import { AIAssistant } from './components/AIAssistant';
import { SystemSettings } from './components/SystemSettings';
import { Reports } from './components/Reports';
import { Tenant, Property, Invoice, CompanyInfo, Expense } from './types';
import { INITIAL_TENANTS, INITIAL_PROPERTIES, INITIAL_INVOICES, INITIAL_EXPENSES } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');

  const [tenants, setTenants] = useState<Tenant[]>(() => {
    const saved = localStorage.getItem('tenants');
    return saved ? JSON.parse(saved) : INITIAL_TENANTS;
  });

  const [properties, setProperties] = useState<Property[]>(() => {
    const saved = localStorage.getItem('properties');
    return saved ? JSON.parse(saved) : INITIAL_PROPERTIES;
  });

  const [invoices, setInvoices] = useState<Invoice[]>(() => {
    const saved = localStorage.getItem('invoices');
    return saved ? JSON.parse(saved) : INITIAL_INVOICES;
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : INITIAL_EXPENSES;
  });

  const [company, setCompany] = useState<CompanyInfo>(() => {
    const saved = localStorage.getItem('company');
    return saved ? JSON.parse(saved) : { name: 'TenantFlow Property Management', address: '123 Landlord Way, Suite 100', email: 'billing@tenantflow.com' };
  });

  useEffect(() => {
    localStorage.setItem('tenants', JSON.stringify(tenants));
    localStorage.setItem('properties', JSON.stringify(properties));
    localStorage.setItem('invoices', JSON.stringify(invoices));
    localStorage.setItem('expenses', JSON.stringify(expenses));
    localStorage.setItem('company', JSON.stringify(company));
  }, [tenants, properties, invoices, expenses, company]);

  const clearAllData = () => {
    if (window.confirm("WARNING: This will permanently delete everything. Are you sure?")) {
      setTenants([]);
      setProperties([]);
      setInvoices([]);
      setExpenses([]);
      localStorage.clear();
      setActiveTab('dashboard');
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
      case 'tenants':
        return <Tenants tenants={tenants} properties={properties} setTenants={setTenants} />;
      case 'invoices':
        return <Invoices invoices={invoices} tenants={tenants} setInvoices={setInvoices} />;
      case 'expenses':
        return <Expenses expenses={expenses} properties={properties} setExpenses={setExpenses} />;
      case 'properties':
        return <Properties properties={properties} setProperties={setProperties} />;
      case 'assistant':
        return <AIAssistant tenants={tenants} invoices={invoices} properties={properties} expenses={expenses} />;
      case 'reports':
        return <Reports tenants={tenants} properties={properties} invoices={invoices} company={company} />;
      case 'settings':
        return <SystemSettings onReset={clearAllData} company={company} setCompany={setCompany} />;
      default:
        return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Property, PropertyType } from '../types';

interface PropertiesProps {
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
}

export const Properties: React.FC<PropertiesProps> = ({ properties, setProperties }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProp, setEditingProp] = useState<Property | null>(null);
  const [formData, setFormData] = useState<Partial<Property>>({
    name: '',
    address: '',
    type: 'Flat',
  });

  const handleOpenModal = (prop?: Property) => {
    if (prop) {
      setEditingProp(prop);
      setFormData(prop);
    } else {
      setEditingProp(null);
      setFormData({ name: '', address: '', type: 'Flat' });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProp) {
      setProperties(prev => prev.map(p => p.id === editingProp.id ? { ...p, ...formData } as Property : p));
    } else {
      const prop: Property = {
        id: `p${Date.now()}`,
        name: formData.name!,
        address: formData.address!,
        type: formData.type!,
      };
      setProperties(prev => [...prev, prop]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-top-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Properties</h2>
          <p className="text-slate-500 mt-1">Managed list of rental units.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-indigo-700 flex items-center gap-2 shadow-lg shadow-indigo-200"
        >
          <span>➕</span> Add Unit
        </button>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Property Name</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Address</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Type</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {properties.map((prop) => (
              <tr key={prop.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 font-bold text-slate-900">{prop.name}</td>
                <td className="px-6 py-4 text-sm text-slate-500">{prop.address}</td>
                <td className="px-6 py-4 text-center">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${
                    prop.type === 'Flat' ? 'bg-indigo-100 text-indigo-700' : 'bg-amber-100 text-amber-700'
                  }`}>
                    {prop.type}
                  </span>
                </td>
                <td className="px-6 py-4 text-right space-x-2">
                  <button onClick={() => handleOpenModal(prop)} className="text-slate-400 hover:text-indigo-600 p-1">✏️ Edit</button>
                  <button onClick={() => setProperties(prev => prev.filter(p => p.id !== prop.id))} className="text-slate-400 hover:text-red-600 p-1">🗑️ Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {properties.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">🏠</p>
            <p className="font-bold text-slate-400">No properties added yet.</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl animate-in zoom-in-95">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-900">{editingProp ? 'Edit Unit' : 'Add Property Unit'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Property Name / Label</label>
                <input required value={formData.name} className="w-full px-4 py-2 rounded-lg border outline-none" placeholder="Flat 101, Garage B, etc." onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Address</label>
                <input required value={formData.address} className="w-full px-4 py-2 rounded-lg border outline-none" placeholder="123 Main St, Apt 4" onChange={e => setFormData({...formData, address: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Type</label>
                <select required value={formData.type} className="w-full px-4 py-2 rounded-lg border outline-none" onChange={e => setFormData({...formData, type: e.target.value as PropertyType})}>
                  <option value="Flat">Flat</option>
                  <option value="Garage">Garage</option>
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 rounded-xl border font-semibold text-slate-600">Cancel</button>
                <button type="submit" className="flex-1 py-2.5 rounded-xl bg-indigo-600 text-white font-semibold">Save</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

