  const [formData, setFormData] = useState<Partial<Property>>({
    name: '',
    type: 'Flat',
  });

  const handleOpenModal = (prop?: Property) => {
    if (prop) {
      setEditingProp(prop);
      setFormData({ name: prop.name, type: prop.type });
    } else {
      setEditingProp(null);
      setFormData({ name: '', type: 'Flat' });
    }
    setIsModalOpen(true);
