import React, { useState, useRef, useMemo } from 'react';
import { Tenant, Property } from '../types';

interface TenantsProps {
  tenants: Tenant[];
  properties: Property[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
}

export const Tenants: React.FC<TenantsProps> = ({ tenants, properties, setTenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTenant, setEditingTenant] = useState<Tenant | null>(null);
  const [propertyFilter, setPropertyFilter] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState<string>('');

  const [formData, setFormData] = useState<Partial<Tenant>>({
    name: '',
    email: '',
    phone: '',
    address: '',
    propertyId: '',
  });

  const handleOpenModal = (tenant?: Tenant) => {
    if (tenant) {
      setEditingTenant(tenant);
      setFormData(tenant);
    } else {
      setEditingTenant(null);
      setFormData({ name: '', email: '', phone: '', address: '', propertyId: '' });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTenant) {
      setTenants(prev => prev.map(t => t.id === editingTenant.id ? { ...t, ...formData } as Tenant : t));
    } else {
      const tenant: Tenant = {
        id: `t${Date.now()}`,
        name: formData.name!,
        email: formData.email!,
        phone: formData.phone!,
        address: formData.address || '',
        propertyId: formData.propertyId!,
      };
      setTenants(prev => [...prev, tenant]);
    }
    setIsModalOpen(false);
  };

  const filteredAndSortedTenants = useMemo(() => {
    let result = [...tenants];

    // Search filter
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(t => 
        t.name.toLowerCase().includes(q) || 
        t.email.toLowerCase().includes(q) ||
        t.phone.toLowerCase().includes(q)
      );
    }

    // Property filter
    if (propertyFilter !== 'All') {
      result = result.filter(t => t.propertyId === propertyFilter);
    }

    // Sort by Property then Name
    return result.sort((a, b) => {
      const propA = properties.find(p => p.id === a.propertyId);
      const propB = properties.find(p => p.id === b.propertyId);
      const nameA = propA ? `${propA.type} ${propA.name}` : '';
      const nameB = propB ? `${propB.type} ${propB.name}` : '';

      if (nameA < nameB) return -1;
      if (nameA > nameB) return 1;
      return a.name.localeCompare(b.name);
    });
  }, [tenants, properties, propertyFilter, searchQuery]);

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Tenants</h2>
          <p className="text-slate-500 mt-1">Manage tenant contacts, addresses, and unit assignments.</p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>➕</span> Add Tenant
          </button>
        </div>
      </header>

      {/* Control Bar */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-64">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">🔍</span>
          <input 
            type="text" 
            placeholder="Search name, email..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm"
          />
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <label className="text-xs font-bold text-slate-400 uppercase whitespace-nowrap">Filter Property:</label>
          <select 
            value={propertyFilter}
            onChange={(e) => setPropertyFilter(e.target.value)}
            className="flex-1 md:flex-none px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium text-slate-700"
          >
            <option value="All">All Properties</option>
            {properties.map(p => (
              <option key={p.id} value={p.id}>{p.type} {p.name}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Tenant & Contact</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Address</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Property</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredAndSortedTenants.map((tenant) => {
              const prop = properties.find(p => p.id === tenant.propertyId);
              return (
                <tr key={tenant.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{tenant.name}</div>
                    <div className="text-xs text-slate-500">{tenant.email} • {tenant.phone}</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 truncate max-w-[200px]">
                    {tenant.address || <span className="text-slate-300 italic">No address</span>}
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-sm font-medium px-2.5 py-1 bg-indigo-50 rounded-lg text-indigo-700 whitespace-nowrap">
                      {prop ? `${prop.type} ${prop.name}` : 'Unassigned'}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button onClick={() => handleOpenModal(tenant)} className="text-indigo-600 hover:text-indigo-800 font-medium text-sm">✏️ Edit</button>
                    <button onClick={() => setTenants(prev => prev.filter(t => t.id !== tenant.id))} className="text-slate-400 hover:text-red-600 text-sm ml-2">🗑️ Delete</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredAndSortedTenants.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">👥</p>
            <p className="font-bold text-slate-400">
              {searchQuery || propertyFilter !== 'All' ? 'No matching tenants found.' : 'No tenants registered.'}
            </p>
            {(searchQuery || propertyFilter !== 'All') && (
              <button 
                onClick={() => { setSearchQuery(''); setPropertyFilter('All'); }}
                className="mt-4 text-indigo-600 text-sm font-bold hover:underline"
              >
                Clear all filters
              </button>
            )}
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl animate-in zoom-in-95">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-900">{editingTenant ? 'Edit Tenant' : 'New Tenant'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Full Name</label>
                <input value={formData.name} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Email</label>
                  <input type="email" value={formData.email} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, email: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Phone</label>
                  <input value={formData.phone} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, phone: e.target.value})} />
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tenant Address</label>
                <textarea value={formData.address} rows={2} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="Enter permanent or billing address" onChange={e => setFormData({...formData, address: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Assigned Property</label>
                <select value={formData.propertyId} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, propertyId: e.target.value})}>
                  <option value="">Select a property</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.type} {p.name}</option>)}
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 rounded-xl border font-semibold text-slate-600 hover:bg-slate-50 transition-colors">Cancel</button>
                <button type="submit" className="flex-1 py-2.5 rounded-xl bg-indigo-600 text-white font-semibold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Save Tenant</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { Tenants } from './components/Tenants';
import { Invoices } from './components/Invoices';
import { Properties } from './components/Properties';
import { AIAssistant } from './components/AIAssistant';
import { SystemSettings } from './components/SystemSettings';
import { Reports } from './components/Reports';
import { Tenant, Property, Invoice, CompanyInfo } from './types';
import { INITIAL_TENANTS, INITIAL_PROPERTIES, INITIAL_INVOICES } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');

  const [tenants, setTenants] = useState<Tenant[]>(() => {
    const saved = localStorage.getItem('tenants');
    return saved ? JSON.parse(saved) : INITIAL_TENANTS;
  });

  const [properties, setProperties] = useState<Property[]>(() => {
    const saved = localStorage.getItem('properties');
    return saved ? JSON.parse(saved) : INITIAL_PROPERTIES;
  });

  const [invoices, setInvoices] = useState<Invoice[]>(() => {
    const saved = localStorage.getItem('invoices');
    return saved ? JSON.parse(saved) : INITIAL_INVOICES;
  });

  const [company, setCompany] = useState<CompanyInfo>(() => {
    const saved = localStorage.getItem('company');
    return saved ? JSON.parse(saved) : { name: 'TenantFlow Property Management', address: '123 Landlord Way, Suite 100', email: 'billing@tenantflow.com' };
  });

  useEffect(() => {
    localStorage.setItem('tenants', JSON.stringify(tenants));
    localStorage.setItem('properties', JSON.stringify(properties));
    localStorage.setItem('invoices', JSON.stringify(invoices));
    localStorage.setItem('company', JSON.stringify(company));
  }, [tenants, properties, invoices, company]);

  const clearAllData = () => {
    if (window.confirm("WARNING: This will permanently delete everything. Are you sure?")) {
      setTenants([]);
      setProperties([]);
      setInvoices([]);
      localStorage.clear();
      setActiveTab('dashboard');
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
      case 'tenants':
        return <Tenants tenants={tenants} properties={properties} setTenants={setTenants} />;
      case 'invoices':
        return <Invoices invoices={invoices} tenants={tenants} properties={properties} company={company} setInvoices={setInvoices} />;
      case 'properties':
        return <Properties properties={properties} setProperties={setProperties} />;
      case 'assistant':
        return <AIAssistant tenants={tenants} invoices={invoices} properties={properties} />;
      case 'reports':
        return <Reports tenants={tenants} properties={properties} invoices={invoices} company={company} />;
      case 'settings':
        return <SystemSettings onReset={clearAllData} company={company} setCompany={setCompany} />;
      default:
        return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Invoice, Tenant, InvoiceStatus, InvoiceItem, Property, CompanyInfo } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface InvoicesProps {
  invoices: Invoice[];
  tenants: Tenant[];
  properties: Property[];
  company: CompanyInfo;
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
}

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, properties, company, setInvoices }) => {
  const [filter, setFilter] = useState<InvoiceStatus | 'All'>('All');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);

  const defaultItems: InvoiceItem[] = [
    { description: 'Rent Charges', amount: 0 },
    { description: 'Repair & Municipal Tax', amount: 0 },
    { description: 'Service charges for common area', amount: 0 }
  ];

  const [formData, setFormData] = useState<{
    tenantId: string;
    dueDate: string;
    items: InvoiceItem[];
    notes: string;
    bankDetails: string;
  }>({
    tenantId: '',
    dueDate: new Date().toISOString().split('T')[0],
    items: [...defaultItems],
    notes: '',
    bankDetails: ''
  });

  const handleOpenModal = (inv?: Invoice) => {
    if (inv) {
      setEditingInvoice(inv);
      setFormData({
        tenantId: inv.tenantId,
        dueDate: inv.dueDate,
        items: inv.items,
        notes: inv.notes || '',
        bankDetails: inv.bankDetails || ''
      });
    } else {
      setEditingInvoice(null);
      setFormData({
        tenantId: '',
        dueDate: new Date().toISOString().split('T')[0],
        items: [...defaultItems],
        notes: '',
        bankDetails: ''
      });
    }
    setIsModalOpen(true);
  };

  const addItem = () => setFormData({ ...formData, items: [...formData.items, { description: '', amount: 0 }] });
  const removeItem = (index: number) => setFormData({ ...formData, items: formData.items.filter((_, i) => i !== index) });
  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...formData.items];
    newItems[index] = { ...newItems[index], [field]: field === 'amount' ? Number(value) : value };
    setFormData({ ...formData, items: newItems });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = formData.items.reduce((sum, item) => sum + item.amount, 0);

    if (editingInvoice) {
      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? {
        ...inv,
        tenantId: formData.tenantId,
        dueDate: formData.dueDate,
        items: formData.items,
        totalAmount: total,
        notes: formData.notes,
        bankDetails: formData.bankDetails
      } : inv));
    } else {
      const newInvoice: Invoice = {
        id: `INV-${Date.now()}`,
        tenantId: formData.tenantId,
        items: formData.items,
        totalAmount: total,
        dueDate: formData.dueDate,
        status: 'Pending',
        createdAt: new Date().toISOString().split('T')[0],
        notes: formData.notes,
        bankDetails: formData.bankDetails
      };
      setInvoices(prev => [...prev, newInvoice]);
    }
    setIsModalOpen(false);
  };

  const toggleStatus = (id: string) => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id === id) {
        const nextStatus: Record<InvoiceStatus, InvoiceStatus> = {
          'Pending': 'Paid',
          'Paid': 'Overdue',
          'Overdue': 'Pending'
        };
        return { ...inv, status: nextStatus[inv.status] };
      }
      return inv;
    }));
  };

  const downloadPDF = (invoice: Invoice) => {
    const tenant = tenants.find(t => t.id === invoice.tenantId);
    const prop = properties.find(p => p.id === tenant?.propertyId);
    const doc = new jsPDF();

    // Company Header
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229); // Indigo-600
    doc.text(company.name, 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139); // Slate-500
    doc.text(company.address, 14, 26);
    doc.text(`Email: ${company.email}`, 14, 31);

    // Invoice Meta
    doc.setFontSize(24);
    doc.setTextColor(15, 23, 42); // Slate-900
    doc.text('INVOICE', 140, 20);
    doc.setFontSize(10);
    doc.text(`ID: ${invoice.id}`, 140, 26);
    doc.text(`Date: ${invoice.createdAt}`, 140, 31);
    doc.text(`Due: ${invoice.dueDate}`, 140, 36);

    doc.setDrawColor(226, 232, 240); // Slate-200
    doc.line(14, 45, 196, 45);

    // Bill To
    doc.setFontSize(12);
    doc.setTextColor(100, 116, 139);
    doc.text('BILL TO:', 14, 55);
    doc.setFontSize(14);
    doc.setTextColor(15, 23, 42);
    doc.text(tenant?.name || 'Valued Tenant', 14, 62);
    doc.setFontSize(10);
    doc.text(tenant?.address || 'No Address Provided', 14, 68);
    doc.setFontSize(11);
    doc.setTextColor(79, 70, 229);
    doc.text(`Property: ${prop ? `${prop.type} ${prop.name}` : 'Unassigned'}`, 14, 75);

    // Table
    const tableData = invoice.items.map(item => [item.description, `INR ${item.amount.toLocaleString()}`]);
    (doc as any).autoTable({
      startY: 85,
      head: [['Description', 'Amount']],
      body: tableData,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229], fontSize: 11 },
      styles: { fontSize: 10, cellPadding: 5 },
      foot: [['Total Amount', `INR ${invoice.totalAmount.toLocaleString()}`]],
      footStyles: { fillColor: [248, 250, 252], textColor: [15, 23, 42], fontStyle: 'bold', fontSize: 12 }
    });

    const finalY = (doc as any).lastAutoTable.finalY || 150;

    // Notes & Bank Details
    if (invoice.notes) {
      doc.setFontSize(11);
      doc.setTextColor(15, 23, 42);
      doc.text('Notes / Instructions:', 14, finalY + 15);
      doc.setFontSize(9);
      doc.setTextColor(100, 116, 139);
      const splitNotes = doc.splitTextToSize(invoice.notes, 180);
      doc.text(splitNotes, 14, finalY + 22);
    }

    if (invoice.bankDetails) {
      const bankY = finalY + (invoice.notes ? 40 : 15);
      doc.setFontSize(11);
      doc.setTextColor(15, 23, 42);
      doc.text('Payment Information:', 14, bankY);
      doc.setFontSize(9);
      doc.setTextColor(79, 70, 229);
      const splitBank = doc.splitTextToSize(invoice.bankDetails, 180);
      doc.text(splitBank, 14, bankY + 7);
    }

    // Save PDF
    doc.save(`${invoice.id}-${tenant?.name || 'Invoice'}.pdf`);
  };

  const filteredInvoices = filter === 'All' 
    ? invoices 
    : invoices.filter(i => i.status === filter);

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Invoices</h2>
          <p className="text-slate-500 mt-1">Create and manage billing statements with professional PDF export.</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>📄</span> Create New Invoice
          </button>
          <div className="flex gap-1 p-1 bg-slate-100 rounded-xl border border-slate-200">
            {(['All', 'Paid', 'Pending', 'Overdue'] as const).map((s) => (
              <button
                key={s}
                onClick={() => setFilter(s)}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                  filter === s ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Tenant</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Items Summary</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Amount</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Status</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredInvoices.map((inv) => {
              const tenant = tenants.find(t => t.id === inv.tenantId);
              return (
                <tr key={inv.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{tenant?.name || 'Unknown'}</div>
                    <div className="text-[10px] text-slate-400 font-mono">{inv.id}</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 font-medium">
                    <span className="truncate block max-w-[200px]">
                      {inv.items.map(i => i.description).join(', ')}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-center font-bold text-slate-900">₹{inv.totalAmount.toLocaleString()}</td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => toggleStatus(inv.id)}
                      className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider shadow-sm transition-all active:scale-95 ${
                        inv.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                        inv.status === 'Pending' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                      }`}
                    >
                      {inv.status}
                    </button>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button 
                        onClick={() => downloadPDF(inv)}
                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors group-hover:bg-indigo-50"
                        title="Download PDF"
                      >
                        📥 <span className="text-xs font-bold hidden md:inline ml-1">PDF</span>
                      </button>
                      <button onClick={() => handleOpenModal(inv)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✏️</button>
                      <button onClick={() => setInvoices(prev => prev.filter(i => i.id !== inv.id))} className="p-2 text-slate-400 hover:text-red-600 transition-colors">🗑️</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredInvoices.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">📄</p>
            <p className="font-bold text-slate-400">No invoices match your selection.</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden shadow-2xl animate-in zoom-in-95 flex flex-col">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-white">
              <h3 className="text-xl font-bold text-slate-900">{editingInvoice ? 'Edit Invoice' : 'Create Invoice'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Select Tenant</label>
                  <select required value={formData.tenantId} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, tenantId: e.target.value})}>
                    <option value="">Choose Tenant...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Due Date</label>
                  <input type="date" required value={formData.dueDate} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, dueDate: e.target.value})} />
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-bold text-slate-900 uppercase tracking-widest">Invoice Items</h4>
                  <button type="button" onClick={addItem} className="text-indigo-600 text-xs font-bold hover:underline">+ Add Item</button>
                </div>
                <div className="space-y-2">
                  {formData.items.map((item, index) => (
                    <div key={index} className="flex gap-2 items-center">
                      <input required className="flex-1 px-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="Description" value={item.description} onChange={e => updateItem(index, 'description', e.target.value)} />
                      <div className="relative w-32">
                        <span className="absolute left-3 top-2 text-slate-400 text-sm">₹</span>
                        <input type="number" required className="w-full pl-7 pr-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="0" value={item.amount || ''} onChange={e => updateItem(index, 'amount', e.target.value)} />
                      </div>
                      <button type="button" onClick={() => removeItem(index)} className="text-slate-400 hover:text-red-500 p-1">🗑️</button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Invoice Notes</label>
                  <textarea value={formData.notes} rows={3} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="Additional notes for the tenant..." onChange={e => setFormData({...formData, notes: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Bank Details</label>
                  <textarea value={formData.bankDetails} rows={3} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-mono" placeholder="IFSC: ... A/C: ..." onChange={e => setFormData({...formData, bankDetails: e.target.value})} />
                </div>
              </div>

              <div className="text-right pt-4 border-t border-slate-100 flex justify-end items-center gap-4">
                <span className="text-sm font-medium text-slate-500">Total: </span>
                <span className="text-2xl font-black text-slate-900">₹{formData.items.reduce((sum, item) => sum + item.amount, 0).toLocaleString()}</span>
              </div>

              <div className="flex gap-4 sticky bottom-0 bg-white pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 rounded-xl border border-slate-200 font-semibold text-slate-600 hover:bg-slate-50 transition-colors">Cancel</button>
                {editingInvoice && (
                   <button 
                     type="button" 
                     onClick={() => downloadPDF(editingInvoice)}
                     className="flex-1 py-3 rounded-xl border-2 border-indigo-600 text-indigo-600 font-bold hover:bg-indigo-50 transition-all flex items-center justify-center gap-2"
                   >
                     📥 Download PDF
                   </button>
                )}
                <button type="submit" className="flex-1 py-3 rounded-xl bg-indigo-600 text-white font-semibold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

