              <tr>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Date</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Tenant</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase text-right">Amount</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase text-center">Status</th>
              </tr>
            </thead>
            <tbody>
              {invoices.map(i => (
                <tr key={i.id}>
                  <td className="p-3 border border-slate-200 text-sm">{formatDate(i.createdAt)}</td>
                  <td className="p-3 border border-slate-200 text-sm">{tenants.find(t => t.id === i.tenantId)?.name || 'Unknown'}</td>
                  <td className="p-3 border border-slate-200 text-sm font-bold text-right">₹{i.totalAmount.toLocaleString()}</td>
                  <td className="p-3 border border-slate-200 text-sm text-center">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                      i.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'
                    }`}>
                      {i.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        );
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <style>{`
        @media print {
          body * { visibility: hidden; }
          #printable-report, #printable-report * { visibility: visible; }
          #printable-report { position: absolute; left: 0; top: 0; width: 100%; }
          .no-print { display: none !important; }
        }
      `}</style>

      <header className="no-print flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Reports</h2>
          <p className="text-slate-500 mt-1">Generate management reports for your portfolio.</p>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={printReport}
            className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center gap-2"
          >
            🖨️ Print Report
          </button>
        </div>
      </header>

      <div className="no-print flex gap-2 p-1 bg-slate-100 rounded-xl border border-slate-200 w-fit">
        {(['tenants', 'properties', 'invoices'] as const).map((type) => (
          <button
            key={type}
            onClick={() => setReportType(type)}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all capitalize ${
              reportType === type ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            {type}
          </button>
        ))}
      </div>

      <div id="printable-report" className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
        <div className="mb-8 flex justify-between items-start">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">{company.name}</h1>
            <p className="text-sm text-slate-500">5th Floor, Flat A, 89 Maharshi Karve Road,</p>
            <p className="text-sm text-slate-500">Marine Lines, Mumbai - 400020</p>
            <p className="text-sm text-slate-500">{company.email}</p>
          </div>
          <div className="text-right">
            <h2 className="text-xl font-bold text-indigo-600 uppercase tracking-widest">{reportType} Report</h2>
            <p className="text-sm text-slate-500">Generated: {formatDate(new Date().toISOString().split('T')[0])}</p>
          </div>
        </div>

        {renderReportTable()}

        <div className="mt-8 text-xs text-slate-400 border-t border-slate-100 pt-4">
          Report generated by QUEENS CHAMBERS Management Portal.
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Invoice, Tenant, InvoiceStatus, InvoiceItem, Property, CompanyInfo } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface InvoicesProps {
  invoices: Invoice[];
  tenants: Tenant[];
  properties: Property[];
  company: CompanyInfo;
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
}

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const [year, month, day] = dateStr.split('-');
  return `${day}-${month}-${year}`;
};

const getDueDateForPeriod = (period: string) => {
  const currentYear = new Date().getFullYear();
  if (period === 'April to September') {
    return `${currentYear}-04-30`;
  } else {
    return `${currentYear}-10-31`;
  }
};

const numberToWords = (num: number): string => {
  const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
  const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];

  const inWords = (n: any): string => {
    if ((n = n.toString()).length > 9) return 'overflow';
    const n_arr = ('000000000' + n).substr(-9).match(/^(\d{2})(\d{2})(\d{2})(\d{1})(\d{2})$/);
    if (!n_arr) return '';
    let str = '';
    str += (Number(n_arr[1]) !== 0) ? (a[Number(n_arr[1])] || b[Number(n_arr[1][0])] + ' ' + a[Number(n_arr[1][1])]) + 'Crore ' : '';
    str += (Number(n_arr[2]) !== 0) ? (a[Number(n_arr[2])] || b[Number(n_arr[2][0])] + ' ' + a[Number(n_arr[2][1])]) + 'Lakh ' : '';
    str += (Number(n_arr[3]) !== 0) ? (a[Number(n_arr[3])] || b[Number(n_arr[3][0])] + ' ' + a[Number(n_arr[3][1])]) + 'Thousand ' : '';
    str += (Number(n_arr[4]) !== 0) ? (a[Number(n_arr[4])] || b[Number(n_arr[4][0])] + ' ' + a[Number(n_arr[4][1])]) + 'Hundred ' : '';
    str += (Number(n_arr[5]) !== 0) ? ((str !== '') ? 'and ' : '') + (a[Number(n_arr[5])] || b[Number(n_arr[5][0])] + ' ' + a[Number(n_arr[5][1])]) + 'Only ' : 'Only';
    return str;
  };

  return inWords(num);
};

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, properties, company, setInvoices }) => {
  const [filter, setFilter] = useState<InvoiceStatus | 'All'>('All');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);

  const defaultItems: InvoiceItem[] = [
    { description: 'Rent Charges', amount: 0 },
    { description: 'Repair & Municipal Tax', amount: 0 },
    { description: 'Service charges for common area', amount: 0 }
  ];

  const [formData, setFormData] = useState<{
    tenantId: string;
    dueDate: string;
    items: InvoiceItem[];
    notes: string;
    bankDetails: string;
    billingPeriod: string;
  }>({
    tenantId: '',
    dueDate: getDueDateForPeriod('April to September'),
    items: [...defaultItems],
    notes: '',
    bankDetails: '',
    billingPeriod: 'April to September'
  });

  const generateNextInvoiceId = () => {
    if (invoices.length === 0) return 'INV-001';

    // Extract numbers from existing INV-XXX IDs
    const ids = invoices
      .map(inv => {
        const match = inv.id.match(/INV-(\d+)/);
        return match ? parseInt(match[1], 10) : 0;
      })
      .filter(num => !isNaN(num));

    const maxId = ids.length > 0 ? Math.max(...ids) : 0;
    const nextId = maxId + 1;
    return `INV-${nextId.toString().padStart(3, '0')}`;
  };

  const handleOpenModal = (inv?: Invoice) => {
    if (inv) {
      setEditingInvoice(inv);
      setFormData({
        tenantId: inv.tenantId,
        dueDate: inv.dueDate,
        items: inv.items,
        notes: inv.notes || '',
        bankDetails: inv.bankDetails || '',
        billingPeriod: inv.billingPeriod || 'April to September'
      });
    } else {
      setEditingInvoice(null);
      const initialPeriod = 'April to September';
      setFormData({
        tenantId: '',
        dueDate: getDueDateForPeriod(initialPeriod),
        items: [...defaultItems],
        notes: '',
        bankDetails: '',
        billingPeriod: initialPeriod
      });
    }
    setIsModalOpen(true);
  };

  const handlePeriodChange = (period: string) => {
    setFormData(prev => ({
      ...prev,
      billingPeriod: period,
      dueDate: getDueDateForPeriod(period)
    }));
  };

  const addItem = () => setFormData({ ...formData, items: [...formData.items, { description: '', amount: 0 }] });
  const removeItem = (index: number) => setFormData({ ...formData, items: formData.items.filter((_, i) => i !== index) });
  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...formData.items];
    newItems[index] = { ...newItems[index], [field]: field === 'amount' ? Number(value) : value };
    setFormData({ ...formData, items: newItems });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = formData.items.reduce((sum, item) => sum + item.amount, 0);

    if (editingInvoice) {
      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? {
        ...inv,
        tenantId: formData.tenantId,
        dueDate: formData.dueDate,
        items: formData.items,
        totalAmount: total,
        notes: formData.notes,
        bankDetails: formData.bankDetails,
        billingPeriod: formData.billingPeriod
      } : inv));
    } else {
      const nextId = generateNextInvoiceId();
      const newInvoice: Invoice = {
        id: nextId,
        tenantId: formData.tenantId,
        items: formData.items,
        totalAmount: total,
        dueDate: formData.dueDate,
        status: 'Pending',
        createdAt: new Date().toISOString().split('T')[0],
        notes: formData.notes,
        bankDetails: formData.bankDetails,
        billingPeriod: formData.billingPeriod
      };
      setInvoices(prev => [...prev, newInvoice]);
    }
    setIsModalOpen(false);
  };

  const toggleStatus = (id: string) => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id === id) {
        const nextStatus: Record<InvoiceStatus, InvoiceStatus> = {
          'Pending': 'Paid',
          'Paid': 'Overdue',
          'Overdue': 'Pending'
        };
        return { ...inv, status: nextStatus[inv.status] };
      }
      return inv;
    }));
  };

  const downloadPDF = (invoice: Invoice) => {
    const tenant = tenants.find(t => t.id === invoice.tenantId);
    const prop = properties.find(p => p.id === tenant?.propertyId);
    const doc = new jsPDF();

    // Company Header
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229); // Indigo-600
    doc.text(company.name, 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139); // Slate-500

    const addr1 = "5th Floor, Flat A, 89 Maharshi Karve Road,";
    const addr2 = "Marine Lines, Mumbai - 400020";
    doc.text(addr1, 14, 26);
    doc.text(addr2, 14, 31);
    doc.text(`Email: ${company.email}`, 14, 36);

    // Invoice Meta
    doc.setFontSize(24);
    doc.setTextColor(15, 23, 42); // Slate-900
    doc.text('Rental Invoice', 130, 20);
    doc.setFontSize(10);
    doc.text(`${invoice.id}`, 130, 26);
    doc.text(`Date: ${formatDate(invoice.createdAt)}`, 130, 31);
    doc.text(`Due: ${formatDate(invoice.dueDate)}`, 130, 36);
    doc.setFontSize(11);
    doc.setTextColor(79, 70, 229);
    doc.text(`Period: ${invoice.billingPeriod}`, 130, 42);

    doc.setDrawColor(226, 232, 240); // Slate-200
    doc.line(14, 48, 196, 48);

    // Bill To
    doc.setFontSize(12);
    doc.setTextColor(100, 116, 139);
    doc.text('TENANT:', 14, 58);
    doc.setFontSize(14);
    doc.setTextColor(15, 23, 42);
    doc.text(tenant?.name || 'Valued Tenant', 14, 65);
    doc.setFontSize(10);
    doc.text(tenant?.address || 'No Address Provided', 14, 71);
    doc.setFontSize(11);
    doc.setTextColor(79, 70, 229);
    doc.text(`Property: ${prop ? `${prop.type} ${prop.name}` : 'Unassigned'}`, 14, 78);

    // Table
    const tableData = invoice.items.map(item => [item.description, `₹${item.amount.toLocaleString()}`]);
    (doc as any).autoTable({
      startY: 85,
      head: [['Particulars', 'Amount']],
      body: tableData,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229], fontSize: 11 },
      styles: { fontSize: 10, cellPadding: 5 },
      foot: [['Total Amount', `₹${invoice.totalAmount.toLocaleString()}`]],
      footStyles: { fillColor: [248, 250, 252], textColor: [15, 23, 42], fontStyle: 'bold', fontSize: 12 }
    });

    const finalY = (doc as any).lastAutoTable.finalY || 150;

    // Amount in Words
    doc.setFontSize(11);
    doc.setTextColor(15, 23, 42);
    doc.text('Amount in words:', 14, finalY + 12);
    doc.setFontSize(10);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rupees ${numberToWords(invoice.totalAmount)}`, 14, finalY + 18);

    // Notes & Bank Details
    let nextY = finalY + 30;
    if (invoice.notes) {
      doc.setFontSize(11);
      doc.setTextColor(15, 23, 42);
      doc.text('Notes:', 14, nextY);
      doc.setFontSize(9);
      doc.setTextColor(100, 116, 139);
      const splitNotes = doc.splitTextToSize(invoice.notes, 180);
      doc.text(splitNotes, 14, nextY + 7);
      nextY += (splitNotes.length * 5) + 10;
    }

    if (invoice.bankDetails) {
      doc.setFontSize(11);
      doc.setTextColor(15, 23, 42);
      doc.text('Bank Details:', 14, nextY);
      doc.setFontSize(9);
      doc.setTextColor(79, 70, 229);
      const splitBank = doc.splitTextToSize(invoice.bankDetails, 180);
      doc.text(splitBank, 14, nextY + 7);
      nextY += (splitBank.length * 5) + 10;
    }

    // Signing Clause
    const pageHeight = doc.internal.pageSize.height;
    doc.setDrawColor(200, 200, 200);
    doc.line(130, pageHeight - 40, 186, pageHeight - 40);
    doc.setFontSize(9);
    doc.setTextColor(100, 116, 139);
    doc.text('Authorized Signatory', 145, pageHeight - 34);

    // Save PDF
    doc.save(`${invoice.id}-${tenant?.name || 'Invoice'}.pdf`);
  };

  const filteredInvoices = filter === 'All' 
    ? invoices 
    : invoices.filter(i => i.status === filter);

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Invoices</h2>
          <p className="text-slate-500 mt-1">Create and manage rental billing with professional PDF support.</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>📄</span> Create New Invoice
          </button>
          <div className="flex gap-1 p-1 bg-slate-100 rounded-xl border border-slate-200">
            {(['All', 'Paid', 'Pending', 'Overdue'] as const).map((s) => (
              <button
                key={s}
                onClick={() => setFilter(s)}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                  filter === s ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Tenant</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Period</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Amount</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Status</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredInvoices.map((inv) => {
              const tenant = tenants.find(t => t.id === inv.tenantId);
              return (
                <tr key={inv.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{tenant?.name || 'Unknown'}</div>
                    <div className="text-[10px] text-slate-400 font-mono">{inv.id}</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 font-medium">
                    {inv.billingPeriod}
                  </td>
                  <td className="px-6 py-4 text-center font-bold text-slate-900">₹{inv.totalAmount.toLocaleString()}</td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => toggleStatus(inv.id)}
                      className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider shadow-sm transition-all active:scale-95 ${
                        inv.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                        inv.status === 'Pending' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                      }`}
                    >
                      {inv.status}
                    </button>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button 
                        onClick={() => downloadPDF(inv)}
                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors group-hover:bg-indigo-50"
                        title="Download PDF"
                      >
                        📥 <span className="text-xs font-bold hidden md:inline ml-1">PDF</span>
                      </button>
                      <button onClick={() => handleOpenModal(inv)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✏️</button>
                      <button onClick={() => setInvoices(prev => prev.filter(i => i.id !== inv.id))} className="p-2 text-slate-400 hover:text-red-600 transition-colors">🗑️</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredInvoices.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">📄</p>
            <p className="font-bold text-slate-400">No invoices match your selection.</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden shadow-2xl animate-in zoom-in-95 flex flex-col">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-white">
              <h3 className="text-xl font-bold text-slate-900">{editingInvoice ? 'Edit Rental Invoice' : 'Create Rental Invoice'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-1">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Select Tenant</label>
                  <select required value={formData.tenantId} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, tenantId: e.target.value})}>
                    <option value="">Choose Tenant...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Billing Period</label>
                  <select required value={formData.billingPeriod} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => handlePeriodChange(e.target.value)}>
                    <option value="April to September">April to September</option>
                    <option value="October to March">October to March</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Due Date</label>
                  <input type="date" required value={formData.dueDate} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, dueDate: e.target.value})} />
                  <p className="text-[10px] text-slate-400 mt-1">Defaults to end of first billing month.</p>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-bold text-slate-900 uppercase tracking-widest">Particulars</h4>
                  <button type="button" onClick={addItem} className="text-indigo-600 text-xs font-bold hover:underline">+ Add Item</button>
                </div>
                <div className="space-y-2">
                  {formData.items.map((item, index) => (
                    <div key={index} className="flex gap-2 items-center">
                      <input required className="flex-1 px-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="Description" value={item.description} onChange={e => updateItem(index, 'description', e.target.value)} />
                      <div className="relative w-32">
                        <span className="absolute left-3 top-2 text-slate-400 text-sm">₹</span>
                        <input type="number" required className="w-full pl-7 pr-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="0" value={item.amount || ''} onChange={e => updateItem(index, 'amount', e.target.value)} />
                      </div>
                      <button type="button" onClick={() => removeItem(index)} className="text-slate-400 hover:text-red-500 p-1">🗑️</button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Notes</label>
                  <textarea value={formData.notes} rows={3} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="Internal or billing notes..." onChange={e => setFormData({...formData, notes: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Bank Details</label>
                  <textarea value={formData.bankDetails} rows={3} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-mono" placeholder="Bank Name, A/C, IFSC..." onChange={e => setFormData({...formData, bankDetails: e.target.value})} />
                </div>
              </div>

              <div className="pt-4 border-t border-slate-100">
                <div className="flex justify-end items-center gap-4 mb-2">
                  <span className="text-sm font-medium text-slate-500">Total: </span>
                  <span className="text-2xl font-black text-slate-900">₹{formData.items.reduce((sum, item) => sum + item.amount, 0).toLocaleString()}</span>
                </div>
                <p className="text-right text-xs text-indigo-600 font-medium italic">
                  Rupees {numberToWords(formData.items.reduce((sum, item) => sum + item.amount, 0))}
                </p>
              </div>

              <div className="flex gap-4 sticky bottom-0 bg-white pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 rounded-xl border border-slate-200 font-semibold text-slate-600 hover:bg-slate-50 transition-colors">Cancel</button>
                {editingInvoice && (
                   <button 
                     type="button" 
                     onClick={() => downloadPDF(editingInvoice)}
                     className="flex-1 py-3 rounded-xl border-2 border-indigo-600 text-indigo-600 font-bold hover:bg-indigo-50 transition-all flex items-center justify-center gap-2"
                   >
                     📥 Download PDF
                   </button>
                )}
                <button type="submit" className="flex-1 py-3 rounded-xl bg-indigo-600 text-white font-semibold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Invoice, Tenant, InvoiceStatus, InvoiceItem, Property, CompanyInfo } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface InvoicesProps {
  invoices: Invoice[];
  tenants: Tenant[];
  properties: Property[];
  company: CompanyInfo;
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
}

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const [year, month, day] = dateStr.split('-');
  return `${day}-${month}-${year}`;
};

const getDueDateForPeriod = (period: string) => {
  const currentYear = new Date().getFullYear();
  if (period === 'April to September') {
    return `${currentYear}-04-30`;
  } else {
    return `${currentYear}-10-31`;
  }
};

const numberToWords = (num: number): string => {
  const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
  const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];

  const inWords = (n: any): string => {
    if ((n = n.toString()).length > 9) return 'overflow';
    const n_arr = ('000000000' + n).substr(-9).match(/^(\d{2})(\d{2})(\d{2})(\d{1})(\d{2})$/);
    if (!n_arr) return '';
    let str = '';
    str += (Number(n_arr[1]) !== 0) ? (a[Number(n_arr[1])] || b[Number(n_arr[1][0])] + ' ' + a[Number(n_arr[1][1])]) + 'Crore ' : '';
    str += (Number(n_arr[2]) !== 0) ? (a[Number(n_arr[2])] || b[Number(n_arr[2][0])] + ' ' + a[Number(n_arr[2][1])]) + 'Lakh ' : '';
    str += (Number(n_arr[3]) !== 0) ? (a[Number(n_arr[3])] || b[Number(n_arr[3][0])] + ' ' + a[Number(n_arr[3][1])]) + 'Thousand ' : '';
    str += (Number(n_arr[4]) !== 0) ? (a[Number(n_arr[4])] || b[Number(n_arr[4][0])] + ' ' + a[Number(n_arr[4][1])]) + 'Hundred ' : '';
    str += (Number(n_arr[5]) !== 0) ? ((str !== '') ? 'and ' : '') + (a[Number(n_arr[5])] || b[Number(n_arr[5][0])] + ' ' + a[Number(n_arr[5][1])]) + 'Only ' : 'Only';
    return str;
  };

  return inWords(num);
};

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, properties, company, setInvoices }) => {
  const [filter, setFilter] = useState<InvoiceStatus | 'All'>('All');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);

  const defaultItems: InvoiceItem[] = [
    { description: 'Rent Charges', amount: 0 },
    { description: 'Repair & Municipal Tax', amount: 0 },
    { description: 'Service charges for common area', amount: 0 }
  ];

  const [formData, setFormData] = useState<{
    tenantId: string;
    dueDate: string;
    items: InvoiceItem[];
    notes: string;
    bankDetails: string;
    billingPeriod: string;
  }>({
    tenantId: '',
    dueDate: getDueDateForPeriod('April to September'),
    items: [...defaultItems],
    notes: '',
    bankDetails: '',
    billingPeriod: 'April to September'
  });

  const generateNextInvoiceId = () => {
    if (invoices.length === 0) return 'INV-001';

    // Extract numbers from existing INV-XXX IDs
    const ids = invoices
      .map(inv => {
        const match = inv.id.match(/INV-(\d+)/);
        return match ? parseInt(match[1], 10) : 0;
      })
      .filter(num => !isNaN(num));

    const maxId = ids.length > 0 ? Math.max(...ids) : 0;
    const nextId = maxId + 1;
    return `INV-${nextId.toString().padStart(3, '0')}`;
  };

  const handleOpenModal = (inv?: Invoice) => {
    if (inv) {
      setEditingInvoice(inv);
      setFormData({
        tenantId: inv.tenantId,
        dueDate: inv.dueDate,
        items: inv.items,
        notes: inv.notes || '',
        bankDetails: inv.bankDetails || '',
        billingPeriod: inv.billingPeriod || 'April to September'
      });
    } else {
      setEditingInvoice(null);
      const initialPeriod = 'April to September';
      setFormData({
        tenantId: '',
        dueDate: getDueDateForPeriod(initialPeriod),
        items: [...defaultItems],
        notes: '',
        bankDetails: '',
        billingPeriod: initialPeriod
      });
    }
    setIsModalOpen(true);
  };

  const handlePeriodChange = (period: string) => {
    setFormData(prev => ({
      ...prev,
      billingPeriod: period,
      dueDate: getDueDateForPeriod(period)
    }));
  };

  const addItem = () => setFormData({ ...formData, items: [...formData.items, { description: '', amount: 0 }] });
  const removeItem = (index: number) => setFormData({ ...formData, items: formData.items.filter((_, i) => i !== index) });
  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...formData.items];
    newItems[index] = { ...newItems[index], [field]: field === 'amount' ? Number(value) : value };
    setFormData({ ...formData, items: newItems });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = formData.items.reduce((sum, item) => sum + item.amount, 0);

    if (editingInvoice) {
      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? {
        ...inv,
        tenantId: formData.tenantId,
        dueDate: formData.dueDate,
        items: formData.items,
        totalAmount: total,
        notes: formData.notes,
        bankDetails: formData.bankDetails,
        billingPeriod: formData.billingPeriod
      } : inv));
    } else {
      const nextId = generateNextInvoiceId();
      const newInvoice: Invoice = {
        id: nextId,
        tenantId: formData.tenantId,
        items: formData.items,
        totalAmount: total,
        dueDate: formData.dueDate,
        status: 'Pending',
        createdAt: new Date().toISOString().split('T')[0],
        notes: formData.notes,
        bankDetails: formData.bankDetails,
        billingPeriod: formData.billingPeriod
      };
      setInvoices(prev => [...prev, newInvoice]);
    }
    setIsModalOpen(false);
  };

  const toggleStatus = (id: string) => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id === id) {
        const nextStatus: Record<InvoiceStatus, InvoiceStatus> = {
          'Pending': 'Paid',
          'Paid': 'Overdue',
          'Overdue': 'Pending'
        };
        return { ...inv, status: nextStatus[inv.status] };
      }
      return inv;
    }));
  };

  const downloadPDF = (invoice: Invoice) => {
    const tenant = tenants.find(t => t.id === invoice.tenantId);
    const prop = properties.find(p => p.id === tenant?.propertyId);
    const doc = new jsPDF();

    // Company Header
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229); // Indigo-600
    doc.text(company.name, 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139); // Slate-500

    const addr1 = "5th Floor, Flat A, 89 Maharshi Karve Road,";
    const addr2 = "Marine Lines, Mumbai - 400020";
    doc.text(addr1, 14, 26);
    doc.text(addr2, 14, 31);
    doc.text(`Email: ${company.email}`, 14, 36);

    // Invoice Meta
    doc.setFontSize(24);
    doc.setTextColor(15, 23, 42); // Slate-900
    doc.text('Rental Invoice', 130, 20);
    doc.setFontSize(10);
    doc.text(`${invoice.id}`, 130, 26);
    doc.text(`Date: ${formatDate(invoice.createdAt)}`, 130, 31);
    doc.text(`Due: ${formatDate(invoice.dueDate)}`, 130, 36);
    doc.setFontSize(11);
    doc.setTextColor(79, 70, 229);
    doc.text(`Period: ${invoice.billingPeriod}`, 130, 42);

    doc.setDrawColor(226, 232, 240); // Slate-200
    doc.line(14, 48, 196, 48);

    // Bill To
    doc.setFontSize(12);
    doc.setTextColor(100, 116, 139);
    doc.text('TENANT:', 14, 58);
    doc.setFontSize(14);
    doc.setTextColor(15, 23, 42);
    doc.text(tenant?.name || 'Valued Tenant', 14, 65);
    doc.setFontSize(10);
    doc.text(tenant?.address || 'No Address Provided', 14, 71);
    doc.setFontSize(11);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rented: ${prop ? `${prop.type} ${prop.name}` : 'Unassigned'}`, 14, 78);

    // Table
    const tableData = invoice.items.map(item => [item.description, `₹${item.amount.toLocaleString()}`]);
    (doc as any).autoTable({
      startY: 85,
      head: [['Particulars', 'Amount']],
      body: tableData,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229], fontSize: 11 },
      styles: { fontSize: 10, cellPadding: 5 },
      foot: [['Total Amount', `₹${invoice.totalAmount.toLocaleString()}`]],
      footStyles: { fillColor: [248, 250, 252], textColor: [15, 23, 42], fontStyle: 'bold', fontSize: 12 }
    });

    const finalY = (doc as any).lastAutoTable.finalY || 150;

    // Amount in Words
    doc.setFontSize(11);
    doc.setTextColor(15, 23, 42);
    doc.text('Amount in words:', 14, finalY + 12);
    doc.setFontSize(10);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rupees ${numberToWords(invoice.totalAmount)}`, 14, finalY + 18);

    // Notes & Bank Details
    let nextY = finalY + 30;
    if (invoice.notes) {
      doc.setFontSize(11);
      doc.setTextColor(15, 23, 42);
      doc.text('Notes:', 14, nextY);
      doc.setFontSize(9);
      doc.setTextColor(100, 116, 139);
      const splitNotes = doc.splitTextToSize(invoice.notes, 180);
      doc.text(splitNotes, 14, nextY + 7);
      nextY += (splitNotes.length * 5) + 10;
    }

    if (invoice.bankDetails) {
      doc.setFontSize(11);
      doc.setTextColor(15, 23, 42);
      doc.text('Bank Details:', 14, nextY);
      doc.setFontSize(9);
      doc.setTextColor(79, 70, 229);
      const splitBank = doc.splitTextToSize(invoice.bankDetails, 180);
      doc.text(splitBank, 14, nextY + 7);
      nextY += (splitBank.length * 5) + 10;
    }

    // Signing Clause
    const pageHeight = doc.internal.pageSize.height;
    doc.setDrawColor(200, 200, 200);
    doc.line(130, pageHeight - 40, 186, pageHeight - 40);
    doc.setFontSize(9);
    doc.setTextColor(100, 116, 139);
    doc.text('Authorized Signatory', 145, pageHeight - 34);

    // Save PDF
    doc.save(`${invoice.id}-${tenant?.name || 'Invoice'}.pdf`);
  };

  const filteredInvoices = filter === 'All' 
    ? invoices 
    : invoices.filter(i => i.status === filter);

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Invoices</h2>
          <p className="text-slate-500 mt-1">Create and manage rental billing with professional PDF support.</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>📄</span> Create New Invoice
          </button>
          <div className="flex gap-1 p-1 bg-slate-100 rounded-xl border border-slate-200">
            {(['All', 'Paid', 'Pending', 'Overdue'] as const).map((s) => (
              <button
                key={s}
                onClick={() => setFilter(s)}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                  filter === s ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Tenant</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Period</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Amount</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Status</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredInvoices.map((inv) => {
              const tenant = tenants.find(t => t.id === inv.tenantId);
              return (
                <tr key={inv.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{tenant?.name || 'Unknown'}</div>
                    <div className="text-[10px] text-slate-400 font-mono">{inv.id}</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 font-medium">
                    {inv.billingPeriod}
                  </td>
                  <td className="px-6 py-4 text-center font-bold text-slate-900">₹{inv.totalAmount.toLocaleString()}</td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => toggleStatus(inv.id)}
                      className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider shadow-sm transition-all active:scale-95 ${
                        inv.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                        inv.status === 'Pending' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                      }`}
                    >
                      {inv.status}
                    </button>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button 
                        onClick={() => downloadPDF(inv)}
                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors group-hover:bg-indigo-50"
                        title="Download PDF"
                      >
                        📥 <span className="text-xs font-bold hidden md:inline ml-1">PDF</span>
                      </button>
                      <button onClick={() => handleOpenModal(inv)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✏️</button>
                      <button onClick={() => setInvoices(prev => prev.filter(i => i.id !== inv.id))} className="p-2 text-slate-400 hover:text-red-600 transition-colors">🗑️</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredInvoices.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">📄</p>
            <p className="font-bold text-slate-400">No invoices match your selection.</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden shadow-2xl animate-in zoom-in-95 flex flex-col">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-white">
              <h3 className="text-xl font-bold text-slate-900">{editingInvoice ? 'Edit Rental Invoice' : 'Create Rental Invoice'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-1">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Select Tenant</label>
                  <select required value={formData.tenantId} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, tenantId: e.target.value})}>
                    <option value="">Choose Tenant...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Billing Period</label>
                  <select required value={formData.billingPeriod} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => handlePeriodChange(e.target.value)}>
                    <option value="April to September">April to September</option>
                    <option value="October to March">October to March</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Due Date</label>
                  <input type="date" required value={formData.dueDate} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, dueDate: e.target.value})} />
                  <p className="text-[10px] text-slate-400 mt-1">Defaults to end of first billing month.</p>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-bold text-slate-900 uppercase tracking-widest">Particulars</h4>
                  <button type="button" onClick={addItem} className="text-indigo-600 text-xs font-bold hover:underline">+ Add Item</button>
                </div>
                <div className="space-y-2">
                  {formData.items.map((item, index) => (
                    <div key={index} className="flex gap-2 items-center">
                      <input required className="flex-1 px-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="Description" value={item.description} onChange={e => updateItem(index, 'description', e.target.value)} />
                      <div className="relative w-32">
                        <span className="absolute left-3 top-2 text-slate-400 text-sm">₹</span>
                        <input type="number" required className="w-full pl-7 pr-3 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="0" value={item.amount || ''} onChange={e => updateItem(index, 'amount', e.target.value)} />
                      </div>
                      <button type="button" onClick={() => removeItem(index)} className="text-slate-400 hover:text-red-500 p-1">🗑️</button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Notes</label>
                  <textarea value={formData.notes} rows={3} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm" placeholder="Internal or billing notes..." onChange={e => setFormData({...formData, notes: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Bank Details</label>
                  <textarea value={formData.bankDetails} rows={3} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-mono" placeholder="Bank Name, A/C, IFSC..." onChange={e => setFormData({...formData, bankDetails: e.target.value})} />
                </div>
              </div>

              <div className="pt-4 border-t border-slate-100">
                <div className="flex justify-end items-center gap-4 mb-2">
                  <span className="text-sm font-medium text-slate-500">Total: </span>
                  <span className="text-2xl font-black text-slate-900">₹{formData.items.reduce((sum, item) => sum + item.amount, 0).toLocaleString()}</span>
                </div>
                <p className="text-right text-xs text-indigo-600 font-medium italic">
                  Rupees {numberToWords(formData.items.reduce((sum, item) => sum + item.amount, 0))}
                </p>
              </div>

              <div className="flex gap-4 sticky bottom-0 bg-white pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 rounded-xl border border-slate-200 font-semibold text-slate-600 hover:bg-slate-50 transition-colors">Cancel</button>
                {editingInvoice && (
                   <button 
                     type="button" 
                     onClick={() => downloadPDF(editingInvoice)}
                     className="flex-1 py-3 rounded-xl border-2 border-indigo-600 text-indigo-600 font-bold hover:bg-indigo-50 transition-all flex items-center justify-center gap-2"
                   >
                     📥 Download PDF
                   </button>
                )}
                <button type="submit" className="flex-1 py-3 rounded-xl bg-indigo-600 text-white font-semibold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Invoice, Tenant, InvoiceStatus, InvoiceItem, Property, CompanyInfo } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface InvoicesProps {
  invoices: Invoice[];
  tenants: Tenant[];
  properties: Property[];
  company: CompanyInfo;
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
}

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const [year, month, day] = dateStr.split('-');
  return `${day}-${month}-${year}`;
};

const getDueDateForPeriod = (period: string) => {
  const currentYear = new Date().getFullYear();
  if (period === 'April to September') {
    return `${currentYear}-04-30`;
  } else {
    return `${currentYear}-10-31`;
  }
};

const numberToWords = (num: number): string => {
  const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
  const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];

  const inWords = (n: any): string => {
    if ((n = n.toString()).length > 9) return 'overflow';
    const n_arr = ('000000000' + n).substr(-9).match(/^(\d{2})(\d{2})(\d{2})(\d{1})(\d{2})$/);
    if (!n_arr) return '';
    let str = '';
    str += (Number(n_arr[1]) !== 0) ? (a[Number(n_arr[1])] || b[Number(n_arr[1][0])] + ' ' + a[Number(n_arr[1][1])]) + 'Crore ' : '';
    str += (Number(n_arr[2]) !== 0) ? (a[Number(n_arr[2])] || b[Number(n_arr[2][0])] + ' ' + a[Number(n_arr[2][1])]) + 'Lakh ' : '';
    str += (Number(n_arr[3]) !== 0) ? (a[Number(n_arr[3])] || b[Number(n_arr[3][0])] + ' ' + a[Number(n_arr[3][1])]) + 'Thousand ' : '';
    str += (Number(n_arr[4]) !== 0) ? (a[Number(n_arr[4])] || b[Number(n_arr[4][0])] + ' ' + a[Number(n_arr[4][1])]) + 'Hundred ' : '';
    str += (Number(n_arr[5]) !== 0) ? ((str !== '') ? 'and ' : '') + (a[Number(n_arr[5])] || b[Number(n_arr[5][0])] + ' ' + a[Number(n_arr[5][1])]) + 'Only ' : 'Only';
    return str;
  };

  return inWords(num);
};

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, properties, company, setInvoices }) => {
  const [filter, setFilter] = useState<InvoiceStatus | 'All'>('All');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);

  const defaultNotes = "Issued by Landlord\nMr. Ayyub Bux\nMr. Yousuf Bux";
  const defaultBankDetails = "Ayyub Bux\nBank Name: ICICI Bank Ltd\nAccount No.: 055501081974\nIFSC Code: ICIC0005256";

  const defaultItems: InvoiceItem[] = [
    { description: 'Rent Charges', amount: 0 },
    { description: 'Repair & Municipal Tax', amount: 0 },
    { description: 'Service charges for common area', amount: 0 }
  ];

  const [formData, setFormData] = useState<{
    tenantId: string;
    dueDate: string;
    items: InvoiceItem[];
    notes: string;
    bankDetails: string;
    billingPeriod: string;
  }>({
    tenantId: '',
    dueDate: getDueDateForPeriod('April to September'),
    items: [...defaultItems],
    notes: defaultNotes,
    bankDetails: defaultBankDetails,
    billingPeriod: 'April to September'
  });

  const generateNextInvoiceId = () => {
    if (invoices.length === 0) return 'INV-001';
    const ids = invoices
      .map(inv => {
        const match = inv.id.match(/INV-(\d+)/);
        return match ? parseInt(match[1], 10) : 0;
      })
      .filter(num => !isNaN(num));
    const maxId = ids.length > 0 ? Math.max(...ids) : 0;
    const nextId = maxId + 1;
    return `INV-${nextId.toString().padStart(3, '0')}`;
  };

  const handleOpenModal = (inv?: Invoice) => {
    if (inv) {
      setEditingInvoice(inv);
      setFormData({
        tenantId: inv.tenantId,
        dueDate: inv.dueDate,
        items: inv.items,
        notes: inv.notes || defaultNotes,
        bankDetails: inv.bankDetails || defaultBankDetails,
        billingPeriod: inv.billingPeriod || 'April to September'
      });
    } else {
      setEditingInvoice(null);
      const initialPeriod = 'April to September';
      setFormData({
        tenantId: '',
        dueDate: getDueDateForPeriod(initialPeriod),
        items: [...defaultItems],
        notes: defaultNotes,
        bankDetails: defaultBankDetails,
        billingPeriod: initialPeriod
      });
    }
    setIsModalOpen(true);
  };

  const handlePeriodChange = (period: string) => {
    setFormData(prev => ({
      ...prev,
      billingPeriod: period,
      dueDate: getDueDateForPeriod(period)
    }));
  };

  const addItem = () => setFormData({ ...formData, items: [...formData.items, { description: '', amount: 0 }] });
  const removeItem = (index: number) => setFormData({ ...formData, items: formData.items.filter((_, i) => i !== index) });
  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...formData.items];
    newItems[index] = { ...newItems[index], [field]: field === 'amount' ? Number(value) : value };
    setFormData({ ...formData, items: newItems });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = formData.items.reduce((sum, item) => sum + item.amount, 0);

    if (editingInvoice) {
      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? {
        ...inv,
        tenantId: formData.tenantId,
        dueDate: formData.dueDate,
        items: formData.items,
        totalAmount: total,
        notes: formData.notes,
        bankDetails: formData.bankDetails,
        billingPeriod: formData.billingPeriod
      } : inv));
    } else {
      const nextId = generateNextInvoiceId();
      const newInvoice: Invoice = {
        id: nextId,
        tenantId: formData.tenantId,
        items: formData.items,
        totalAmount: total,
        dueDate: formData.dueDate,
        status: 'Pending',
        createdAt: new Date().toISOString().split('T')[0],
        notes: formData.notes,
        bankDetails: formData.bankDetails,
        billingPeriod: formData.billingPeriod
      };
      setInvoices(prev => [...prev, newInvoice]);
    }
    setIsModalOpen(false);
  };

  const toggleStatus = (id: string) => {
    setInvoices(prev => prev.map(inv => {
      if (inv.id === id) {
        const nextStatus: Record<InvoiceStatus, InvoiceStatus> = {
          'Pending': 'Paid',
          'Paid': 'Overdue',
          'Overdue': 'Pending'
        };
        return { ...inv, status: nextStatus[inv.status] };
      }
      return inv;
    }));
  };

  const downloadPDF = (invoice: Invoice) => {
    const tenant = tenants.find(t => t.id === invoice.tenantId);
    const prop = properties.find(p => p.id === tenant?.propertyId);
    const doc = new jsPDF();

    // Company Header
    doc.setFontSize(22);
    doc.setTextColor(79, 70, 229); // Indigo-600
    doc.text(company.name, 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139); // Slate-500

    const addr1 = "5th Floor, Flat A, 89 Maharshi Karve Road,";
    const addr2 = "Marine Lines, Mumbai - 400020";
    doc.text(addr1, 14, 26);
    doc.text(addr2, 14, 31);
    doc.text(`Email: ${company.email}`, 14, 36);

    // Invoice Meta
    doc.setFontSize(24);
    doc.setTextColor(15, 23, 42); // Slate-900
    doc.text('Rental Invoice', 130, 20);
    doc.setFontSize(10);
    doc.text(`${invoice.id}`, 130, 26);
    doc.text(`Date: ${formatDate(invoice.createdAt)}`, 130, 31);
    doc.text(`Due: ${formatDate(invoice.dueDate)}`, 130, 36);
    doc.setFontSize(11);
    doc.setTextColor(79, 70, 229);
    doc.text(`Period: ${invoice.billingPeriod}`, 130, 42);

    doc.setDrawColor(226, 232, 240); // Slate-200
    doc.line(14, 48, 196, 48);

    // Bill To
    doc.setFontSize(12);
    doc.setTextColor(100, 116, 139);
    doc.text('TENANT:', 14, 58);
    doc.setFontSize(14);
    doc.setTextColor(15, 23, 42);
    doc.text(tenant?.name || 'Valued Tenant', 14, 65);
    doc.setFontSize(10);
    doc.text(tenant?.address || 'No Address Provided', 14, 71);
    doc.setFontSize(11);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rented: ${prop ? `${prop.type} ${prop.name}` : 'Unassigned'}`, 14, 78);

    // Table - Using 'Rs.' for the PDF to ensure reliable printing without custom font dependencies
    const tableData = invoice.items.map(item => [item.description, `Rs. ${item.amount.toLocaleString()}`]);
    (doc as any).autoTable({
      startY: 85,
      head: [['Particulars', 'Amount']],
      body: tableData,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229], fontSize: 11 },
      styles: { fontSize: 10, cellPadding: 5 },
      foot: [['Total Amount', `Rs. ${invoice.totalAmount.toLocaleString()}`]],
      footStyles: { fillColor: [248, 250, 252], textColor: [15, 23, 42], fontStyle: 'bold', fontSize: 12 }
    });

    const finalY = (doc as any).lastAutoTable.finalY || 150;

    // Amount in Words
    doc.setFontSize(11);
    doc.setTextColor(15, 23, 42);
    doc.text('Amount in words:', 14, finalY + 12);
    doc.setFontSize(10);
    doc.setTextColor(79, 70, 229);
    doc.text(`Rupees ${numberToWords(invoice.totalAmount)}`, 14, finalY + 18);

    // Notes
    let nextY = finalY + 30;
    doc.setFontSize(11);
    doc.setTextColor(15, 23, 42);
    doc.text('Notes:', 14, nextY);
    doc.setFontSize(9);
    doc.setTextColor(100, 116, 139);
    const splitNotes = doc.splitTextToSize(invoice.notes || defaultNotes, 180);
    doc.text(splitNotes, 14, nextY + 7);
    nextY += (splitNotes.length * 5) + 12;

    // Bank Details
    doc.setFontSize(11);
    doc.setTextColor(15, 23, 42);
    doc.text('Bank Details:', 14, nextY);
    doc.setFontSize(9);
    doc.setTextColor(79, 70, 229);
    const splitBank = doc.splitTextToSize(invoice.bankDetails || defaultBankDetails, 180);
    doc.text(splitBank, 14, nextY + 7);

    // Signing Clause
    const pageHeight = doc.internal.pageSize.height;
    doc.setDrawColor(200, 200, 200);
    doc.line(130, pageHeight - 40, 186, pageHeight - 40);
    doc.setFontSize(9);
    doc.setTextColor(100, 116, 139);
    doc.text('Authorized Signatory', 145, pageHeight - 34);

    // Save PDF
    doc.save(`${invoice.id}-${tenant?.name || 'Invoice'}.pdf`);
  };

  const filteredInvoices = filter === 'All' 
    ? invoices 
    : invoices.filter(i => i.status === filter);

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Invoices</h2>
          <p className="text-slate-500 mt-1">Create and manage rental billing with professional PDF support.</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>📄</span> Create New Invoice
          </button>
          <div className="flex gap-1 p-1 bg-slate-100 rounded-xl border border-slate-200">
            {(['All', 'Paid', 'Pending', 'Overdue'] as const).map((s) => (
              <button
                key={s}
                onClick={() => setFilter(s)}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                  filter === s ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Tenant</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Period</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Amount</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Status</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredInvoices.map((inv) => {
              const tenant = tenants.find(t => t.id === inv.tenantId);
              return (
                <tr key={inv.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{tenant?.name || 'Unknown'}</div>
                    <div className="text-[10px] text-slate-400 font-mono">{inv.id}</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 font-medium">
                    {inv.billingPeriod}
                  </td>
                  <td className="px-6 py-4 text-center font-bold text-slate-900">₹{inv.totalAmount.toLocaleString()}</td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => toggleStatus(inv.id)}
                      className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-wider shadow-sm transition-all active:scale-95 ${
                        inv.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                        inv.status === 'Pending' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                      }`}
                    >
                      {inv.status}
                    </button>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button 
                        onClick={() => downloadPDF(inv)}
                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors group-hover:bg-indigo-50"
                        title="Download PDF"
                      >
                        📥 <span className="text-xs font-bold hidden md:inline ml-1">PDF</span>
                      </button>
                      <button onClick={() => handleOpenModal(inv)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✏️</button>
                      <button onClick={() => setInvoices(prev => prev.filter(i => i.id !== inv.id))} className="p-2 text-slate-400 hover:text-red-600 transition-colors">🗑️</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredInvoices.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">📄</p>
            <p className="font-bold text-slate-400">No invoices match your selection.</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden shadow-2xl animate-in zoom-in-95 flex flex-col">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-white">
              <h3 className="text-xl font-bold text-slate-900">{editingInvoice ? 'Edit Rental Invoice' : 'Create Rental Invoice'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-1">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Select Tenant</label>
                  <select required value={formData.tenantId} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, tenantId: e.target.value})}>
                    <option value="">Choose Tenant...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Billing Period</label>
                  <select required value={formData.billingPeriod} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => handlePeriodChange(e.target.value)}>
                    <option value="April to September">April to September</option>
                    <option value="October to March">October to March</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Due Date</label>
                  <input type="date" required value={formData.dueDate} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, dueDate: e.target.value})} />
                  <p className="text-[10px] text-slate-400 mt-1">Defaults to end of first billing month.</p>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-bold text-slate-900 uppercase tracking-widest">Particulars</h4>
