import React, { useState, useMemo, useRef } from 'react';
import { Tenant, Property } from '../types';

interface TenantsProps {
  tenants: Tenant[];
  properties: Property[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
}

export const Tenants: React.FC<TenantsProps> = ({ tenants, properties, setTenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTenant, setEditingTenant] = useState<Tenant | null>(null);
  const [propertyFilter, setPropertyFilter] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Partial<Tenant>>({
    name: '',
    email: '',
    phone: '',
    address: '',
    propertyId: '',
  });

  const handleOpenModal = (tenant?: Tenant) => {
    if (tenant) {
      setEditingTenant(tenant);
      setFormData(tenant);
    } else {
      setEditingTenant(null);
      setFormData({ name: '', email: '', phone: '', address: '', propertyId: '' });
    }
    setIsModalOpen(true);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      if (!text) return;

      const lines = text.split(/\r?\n/);
      if (lines.length < 2) return;

      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
      const newTenants: Tenant[] = [];

      for (let i = 1; i < lines.length; i++) {
        if (!lines[i].trim()) continue;
        const values = lines[i].split(',').map(v => v.trim());
        const data: any = {};
        headers.forEach((h, idx) => { data[h] = values[idx]; });

        // Match property by name if provided, otherwise leave blank or find first
        let propId = data.propertyid || '';
        if (!propId && data.property) {
          const match = properties.find(p => p.name.toLowerCase() === data.property.toLowerCase());
          if (match) propId = match.id;
        }

        newTenants.push({
          id: `t${Date.now()}-${i}`,
          name: data.name || 'Unknown',
          email: data.email || '',
          phone: data.phone || '',
          address: data.address || '',
          propertyId: propId || (properties.length > 0 ? properties[0].id : ''),
        });
      }

      if (newTenants.length > 0) {
        setTenants(prev => [...prev, ...newTenants]);
        alert(`Successfully imported ${newTenants.length} tenants.`);
      }
    };
    reader.readAsText(file);
    e.target.value = ''; // Reset input
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTenant) {
      setTenants(prev => prev.map(t => t.id === editingTenant.id ? { ...t, ...formData } as Tenant : t));
    } else {
      const tenant: Tenant = {
        id: `t${Date.now()}`,
        name: formData.name!,
        email: formData.email!,
        phone: formData.phone!,
        address: formData.address || '',
        propertyId: formData.propertyId!,
      };
      setTenants(prev => [...prev, tenant]);
    }
    setIsModalOpen(false);
  };

  const filteredAndSortedTenants = useMemo(() => {
    let result = [...tenants];

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(t => 
        t.name.toLowerCase().includes(q) || 
        t.email.toLowerCase().includes(q) ||
        t.phone.toLowerCase().includes(q)
      );
    }

    if (propertyFilter !== 'All') {
      result = result.filter(t => t.propertyId === propertyFilter);
    }

    return result.sort((a, b) => {
      const propA = properties.find(p => p.id === a.propertyId);
      const propB = properties.find(p => p.id === b.propertyId);
      const nameA = propA ? `${propA.type} ${propA.name}` : '';
      const nameB = propB ? `${propB.type} ${propB.name}` : '';

      if (nameA < nameB) return -1;
      if (nameA > nameB) return 1;
      return a.name.localeCompare(b.name);
    });
  }, [tenants, properties, propertyFilter, searchQuery]);

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Tenants</h2>
          <p className="text-slate-500 mt-1">Manage tenant contacts, addresses, and unit assignments.</p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".csv" 
            className="hidden" 
          />
          <button 
            onClick={handleImportClick}
            className="bg-slate-100 text-slate-700 px-5 py-2.5 rounded-xl font-medium hover:bg-slate-200 transition-colors flex items-center gap-2"
          >
            <span>📥</span> Import CSV
          </button>
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>➕</span> Add Tenant
          </button>
        </div>
      </header>

      {/* Control Bar */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-64">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">🔍</span>
          <input 
            type="text" 
            placeholder="Search name, email..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm"
          />
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <label className="text-xs font-bold text-slate-400 uppercase whitespace-nowrap">Filter Property:</label>
          <select 
            value={propertyFilter}
            onChange={(e) => setPropertyFilter(e.target.value)}
            className="flex-1 md:flex-none px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium text-slate-700"
          >
            <option value="All">All Properties</option>
            {properties.map(p => (
              <option key={p.id} value={p.id}>{p.type} {p.name}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Tenant & Contact</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Address</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Property</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredAndSortedTenants.map((tenant) => {
              const prop = properties.find(p => p.id === tenant.propertyId);
              return (
                <tr key={tenant.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{tenant.name}</div>
                    <div className="text-xs text-slate-500">{tenant.email} • {tenant.phone}</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 truncate max-w-[200px]">
                    {tenant.address || <span className="text-slate-300 italic">No address</span>}
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-sm font-medium px-2.5 py-1 bg-indigo-50 rounded-lg text-indigo-700 whitespace-nowrap">
                      {prop ? `${prop.type} ${prop.name}` : 'Unassigned'}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button onClick={() => handleOpenModal(tenant)} className="text-indigo-600 hover:text-indigo-800 font-medium text-sm">✏️ Edit</button>
                    <button onClick={() => setTenants(prev => prev.filter(t => t.id !== tenant.id))} className="text-slate-400 hover:text-red-600 text-sm ml-2">🗑️ Delete</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredAndSortedTenants.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">👥</p>
            <p className="font-bold text-slate-400">
              {searchQuery || propertyFilter !== 'All' ? 'No matching tenants found.' : 'No tenants registered.'}
            </p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl animate-in zoom-in-95">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-900">{editingTenant ? 'Edit Tenant' : 'New Tenant'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Full Name</label>
                <input value={formData.name} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Email</label>
                  <input type="email" value={formData.email} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, email: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Phone</label>
                  <input value={formData.phone} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, phone: e.target.value})} />
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tenant Address</label>
                <textarea value={formData.address} rows={2} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="Enter permanent or billing address" onChange={e => setFormData({...formData, address: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Assigned Property</label>
                <select value={formData.propertyId} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, propertyId: e.target.value})}>
                  <option value="">Select a property</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.type} {p.name}</option>)}
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 rounded-xl border font-semibold text-slate-600 hover:bg-slate-50 transition-colors">Cancel</button>
                <button type="submit" className="flex-1 py-2.5 rounded-xl bg-indigo-600 text-white font-semibold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Save Tenant</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Property, PropertyType } from '../types';

interface PropertiesProps {
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
}

export const Properties: React.FC<PropertiesProps> = ({ properties, setProperties }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProp, setEditingProp] = useState<Property | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [formData, setFormData] = useState<Partial<Property>>({
    name: '',
    type: 'Flat',
  });

  const handleOpenModal = (prop?: Property) => {
    if (prop) {
      setEditingProp(prop);
      setFormData({ name: prop.name, type: prop.type });
    } else {
      setEditingProp(null);
      setFormData({ name: '', type: 'Flat' });
    }
    setIsModalOpen(true);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      if (!text) return;

      const lines = text.split(/\r?\n/);
      if (lines.length < 2) return;

      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
      const newProperties: Property[] = [];

      for (let i = 1; i < lines.length; i++) {
        if (!lines[i].trim()) continue;
        const values = lines[i].split(',').map(v => v.trim());
        const data: any = {};
        headers.forEach((h, idx) => { data[h] = values[idx]; });

        const type = data.type as PropertyType;
        newProperties.push({
          id: `p${Date.now()}-${i}`,
          name: data.name || 'Unknown Unit',
          type: ['Flat', 'Garage', 'Godown'].includes(type) ? type : 'Flat',
        });
      }

      if (newProperties.length > 0) {
        setProperties(prev => [...prev, ...newProperties]);
        alert(`Successfully imported ${newProperties.length} units.`);
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProp) {
      setProperties(prev => prev.map(p => p.id === editingProp.id ? { ...p, ...formData } as Property : p));
    } else {
      const prop: Property = {
        id: `p${Date.now()}`,
        name: formData.name!,
        type: formData.type!,
      };
      setProperties(prev => [...prev, prop]);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-top-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Properties</h2>
          <p className="text-slate-500 mt-1">Managed list of rental units (Flat, Garage, or Godown).</p>
        </div>
        <div className="flex items-center gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".csv" 
            className="hidden" 
          />
          <button 
            onClick={handleImportClick}
            className="bg-slate-100 text-slate-700 px-5 py-2.5 rounded-xl font-medium hover:bg-slate-200 transition-colors flex items-center gap-2"
          >
            <span>📥</span> Import Units
          </button>
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-indigo-700 flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>➕</span> Add Unit
          </button>
        </div>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Property Name</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-center">Type</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {properties.map((prop) => (
              <tr key={prop.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4 font-bold text-slate-900">{prop.name}</td>
                <td className="px-6 py-4 text-center">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${
                    prop.type === 'Flat' ? 'bg-indigo-100 text-indigo-700' : 
                    prop.type === 'Garage' ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'
                  }`}>
                    {prop.type}
                  </span>
                </td>
                <td className="px-6 py-4 text-right space-x-2">
                  <button onClick={() => handleOpenModal(prop)} className="text-indigo-600 hover:underline text-sm font-medium">Edit</button>
                  <button onClick={() => setProperties(prev => prev.filter(p => p.id !== prop.id))} className="text-red-600 hover:underline text-sm font-medium ml-2">Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {properties.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">🏠</p>
            <p className="font-bold text-slate-400">No properties added yet.</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-md shadow-2xl animate-in zoom-in-95">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-900">{editingProp ? 'Edit Unit' : 'Add Property Unit'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Property Name / Label</label>
                <input required value={formData.name} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Flat 101, Garage B, Godown 1, etc." onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Type</label>
                <select required value={formData.type} className="w-full px-4 py-2 rounded-lg border outline-none focus:ring-2 focus:ring-indigo-500" onChange={e => setFormData({...formData, type: e.target.value as PropertyType})}>
                  <option value="Flat">Flat</option>
                  <option value="Garage">Garage</option>
                  <option value="Godown">Godown</option>
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 rounded-xl border font-semibold text-slate-600">Cancel</button>
                <button type="submit" className="flex-1 py-2.5 rounded-xl bg-indigo-600 text-white font-semibold">Save</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Tenant, Property, Invoice, CompanyInfo } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface ReportsProps {
  tenants: Tenant[];
  properties: Property[];
  invoices: Invoice[];
  company: CompanyInfo;
}

type ReportType = 'tenants' | 'properties' | 'invoices';

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const [year, month, day] = dateStr.split('-');
  return `${day}-${month}-${year}`;
};

export const Reports: React.FC<ReportsProps> = ({ tenants, properties, invoices, company }) => {
  const [reportType, setReportType] = useState<ReportType>('tenants');

  const printReport = () => {
    window.print();
  };

  const exportToCSV = () => {
    let csvContent = "";
    let filename = `report_${reportType}_${new Date().toISOString().split('T')[0]}.csv`;

    if (reportType === 'tenants') {
      csvContent = "Name,Address,Property,Email,Phone\n";
      tenants.forEach(t => {
        const prop = properties.find(p => p.id === t.propertyId);
        csvContent += `"${t.name}","${t.address || ''}","${prop ? `${prop.type} ${prop.name}` : ''}","${t.email}","${t.phone}"\n`;
      });
    } else if (reportType === 'properties') {
      csvContent = "Name,Type,Status\n";
      properties.forEach(p => {
        const status = tenants.some(t => t.propertyId === p.id) ? "Occupied" : "Vacant";
        csvContent += `"${p.name}","${p.type}","${status}"\n`;
      });
    } else if (reportType === 'invoices') {
      csvContent = "Date,Tenant,Amount,Status\n";
      invoices.forEach(i => {
        const tName = tenants.find(t => t.id === i.tenantId)?.name || 'Unknown';
        csvContent += `"${formatDate(i.createdAt)}","${tName}","${i.totalAmount}","${i.status}"\n`;
      });
    }

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportToPDF = () => {
    const doc = new jsPDF();
    const title = `${reportType.toUpperCase()} REPORT`;
    const date = formatDate(new Date().toISOString().split('T')[0]);

    // Header
    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text(company.name, 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139);
    doc.text(title, 14, 28);
    doc.text(`Generated: ${date}`, 14, 33);

    let head: string[][] = [];
    let body: string[][] = [];

    if (reportType === 'tenants') {
      head = [['Name', 'Address', 'Property', 'Contact']];
      body = tenants.map(t => {
        const prop = properties.find(p => p.id === t.propertyId);
        return [
          t.name, 
          t.address || 'N/A', 
          prop ? `${prop.type} ${prop.name}` : 'N/A', 
          `${t.email}\n${t.phone}`
        ];
      });
    } else if (reportType === 'properties') {
      head = [['Name', 'Type', 'Status']];
      body = properties.map(p => {
        const status = tenants.some(t => t.propertyId === p.id) ? "Occupied" : "Vacant";
        return [p.name, p.type, status];
      });
    } else if (reportType === 'invoices') {
      head = [['Date', 'Tenant', 'Amount', 'Status']];
      body = invoices.map(i => [
        formatDate(i.createdAt),
        tenants.find(t => t.id === i.tenantId)?.name || 'Unknown',
        `Rs. ${i.totalAmount.toLocaleString()}`,
        i.status
      ]);
    }

    (doc as any).autoTable({
      startY: 40,
      head: head,
      body: body,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229] },
      styles: { fontSize: 9 }
    });

    doc.save(`${reportType}_report_${date}.pdf`);
  };

  const renderReportTable = () => {
    switch (reportType) {
      case 'tenants':
        return (
          <table className="w-full text-left border-collapse border border-slate-200">
            <thead className="bg-slate-100">
              <tr>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Name</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Address</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase whitespace-nowrap">Property</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Contact</th>
              </tr>
            </thead>
            <tbody>
              {tenants.map(t => {
                const prop = properties.find(p => p.id === t.propertyId);
                return (
                  <tr key={t.id}>
                    <td className="p-3 border border-slate-200 text-sm font-bold">{t.name}</td>
                    <td className="p-3 border border-slate-200 text-sm">{t.address || 'N/A'}</td>
                    <td className="p-3 border border-slate-200 text-sm whitespace-nowrap">{prop ? `${prop.type} ${prop.name}` : 'N/A'}</td>
                    <td className="p-3 border border-slate-200 text-sm">{t.email}<br/><span className="text-xs text-slate-400">{t.phone}</span></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        );
      case 'properties':
        return (
          <table className="w-full text-left border-collapse border border-slate-200">
            <thead className="bg-slate-100">
              <tr>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Name</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Type</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase text-center">Status</th>
              </tr>
            </thead>
            <tbody>
              {properties.map(p => (
                <tr key={p.id}>
                  <td className="p-3 border border-slate-200 text-sm font-bold">{p.name}</td>
                  <td className="p-3 border border-slate-200 text-sm">{p.type}</td>
                  <td className="p-3 border border-slate-200 text-sm text-center">
                    {tenants.some(t => t.propertyId === p.id) ? (
                      <span className="text-emerald-600 font-bold uppercase text-[10px]">Occupied</span>
                    ) : (
                      <span className="text-amber-600 font-bold uppercase text-[10px]">Vacant</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        );
      case 'invoices':
        return (
          <table className="w-full text-left border-collapse border border-slate-200">
            <thead className="bg-slate-100">
              <tr>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Date</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Tenant</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase text-right">Amount</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase text-center">Status</th>
              </tr>
            </thead>
            <tbody>
              {invoices.map(i => (
                <tr key={i.id}>
                  <td className="p-3 border border-slate-200 text-sm">{formatDate(i.createdAt)}</td>
                  <td className="p-3 border border-slate-200 text-sm">{tenants.find(t => t.id === i.tenantId)?.name || 'Unknown'}</td>
                  <td className="p-3 border border-slate-200 text-sm font-bold text-right">₹{i.totalAmount.toLocaleString()}</td>
                  <td className="p-3 border border-slate-200 text-sm text-center">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                      i.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'
                    }`}>
                      {i.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        );
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <style>{`
        @media print {
          body * { visibility: hidden; }
          #printable-report, #printable-report * { visibility: visible; }
          #printable-report { position: absolute; left: 0; top: 0; width: 100%; }
          .no-print { display: none !important; }
        }
      `}</style>

      <header className="no-print flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Reports</h2>
          <p className="text-slate-500 mt-1">Generate management reports for your portfolio.</p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <button 
            onClick={exportToCSV}
            className="bg-white text-slate-700 border border-slate-200 px-5 py-2.5 rounded-xl font-bold hover:bg-slate-50 transition-all flex items-center gap-2"
          >
            📊 Excel (CSV)
          </button>
          <button 
            onClick={exportToPDF}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2"
          >
            📄 PDF Export
          </button>
          <button 
            onClick={printReport}
            className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center gap-2"
          >
            🖨️ Print
          </button>
        </div>
      </header>

      <div className="no-print flex gap-2 p-1 bg-slate-100 rounded-xl border border-slate-200 w-fit">
        {(['tenants', 'properties', 'invoices'] as const).map((type) => (
          <button
            key={type}
            onClick={() => setReportType(type)}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all capitalize ${
              reportType === type ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            {type}
          </button>
        ))}
      </div>

      <div id="printable-report" className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
        <div className="mb-8 flex justify-between items-start">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">{company.name}</h1>
            <p className="text-sm text-slate-500">5th Floor, Flat A, 89 Maharshi Karve Road,</p>
            <p className="text-sm text-slate-500">Marine Lines, Mumbai - 400020</p>
            <p className="text-sm text-slate-500">{company.email}</p>
          </div>
          <div className="text-right">
            <h2 className="text-xl font-bold text-indigo-600 uppercase tracking-widest">{reportType} Report</h2>
            <p className="text-sm text-slate-500">Generated: {formatDate(new Date().toISOString().split('T')[0])}</p>
          </div>
        </div>

        {renderReportTable()}

        <div className="mt-8 text-xs text-slate-400 border-t border-slate-100 pt-4">
          Report generated by QUEENS CHAMBERS Management Portal.
        </div>
      </div>
    </div>
  );
};

