const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const [year, month, day] = dateStr.split('-');
  return `${day}-${month}-${year}`;
};

const PERIOD_1 = "01 April 2026 to 30 September 2026";
const PERIOD_2 = "01 October 2026 to 31 March 2027";

const getDueDateForPeriod = (period: string) => {
  if (period === PERIOD_1) return `2026-04-30`;
  if (period === PERIOD_2) return `2026-10-31`;
  return new Date().toISOString().split('T')[0];
};

// World-class Indian Number to Words Converter (Lakhs/Crores)
const numberToWordsIndian = (num: number): string => {
  const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
  const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];

  const convert_less_than_thousand = (n: number): string => {
    if (n === 0) return '';
    if (n < 20) return a[n];
    const res = b[Math.floor(n / 10)] + ' ' + a[n % 10];
    return res.trim() + ' ';
  };

  if (num === 0) return 'Zero';

  let words = '';
  let n = Math.floor(num);

  if (Math.floor(n / 10000000) > 0) {
    words += convert_less_than_thousand(Math.floor(n / 10000000)) + 'Crore ';
    n %= 10000000;
  }
  if (Math.floor(n / 100000) > 0) {
    words += convert_less_than_thousand(Math.floor(n / 100000)) + 'Lakh ';
    n %= 100000;
  }
  if (Math.floor(n / 1000) > 0) {
    words += convert_less_than_thousand(Math.floor(n / 1000)) + 'Thousand ';
    n %= 1000;
  }
  if (Math.floor(n / 100) > 0) {
    words += a[Math.floor(n / 100)] + 'Hundred ';
    n %= 100;
  }
  if (n > 0) {
    if (words !== '') words += 'and ';
    words += convert_less_than_thousand(n);
  }

  return words.trim() + ' Only';
};

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, properties, company, setInvoices }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);

  const defaultNotes = "Issued by Landlord\nMr. Ayyub Bux\nMr. Yousuf Bux";
  const defaultBankDetails = "Name of Account: Ayyub Vali Bux\nBank Name: ICICI Bank Ltd\nAccount No.: 055501081974\nIFSC Code: ICIC0005256\nBranch Name: Umraj, Bharuch\n\nPlease prepare cheques or transfer through NEFT/RTGS to beneficiary account name - Ayyub Vali Bux";

  const defaultItems: InvoiceItem[] = [
    { description: 'Rent Charges', amount: 0 },
    { description: 'Repair & Municipal Tax', amount: 0 },
    { description: 'Service charges for common area', amount: 0 }
  ];

  const [formData, setFormData] = useState<Partial<Invoice>>({
    tenantId: '',
    dueDate: getDueDateForPeriod(PERIOD_1),
    items: [...defaultItems],
    notes: defaultNotes,
    bankDetails: defaultBankDetails,
    billingPeriod: PERIOD_1,
    invoiceType: 'Rent Invoice'
  });

  const generateNextInvoiceId = () => {
    if (invoices.length === 0) return 'INV-001';
    const ids = invoices.map(inv => parseInt(inv.id.replace('INV-', ''), 10)).filter(n => !isNaN(n));
    const maxId = ids.length > 0 ? Math.max(...ids) : 0;
    return `INV-${(maxId + 1).toString().padStart(3, '0')}`;
  };

  const handleOpenModal = (inv?: Invoice) => {
    if (inv) {
      setEditingInvoice(inv);
      setFormData(inv);
    } else {
      setEditingInvoice(null);
      setFormData({
        tenantId: '',
        dueDate: getDueDateForPeriod(PERIOD_1),
        items: [...defaultItems],
        notes: defaultNotes,
        bankDetails: defaultBankDetails,
        billingPeriod: PERIOD_1,
        invoiceType: 'Rent Invoice'
      });
    }
    setIsModalOpen(true);
  };

  const handlePeriodChange = (period: string) => {
    setFormData(prev => ({
      ...prev,
      billingPeriod: period,
      dueDate: getDueDateForPeriod(period)
    }));
  };

  const addItem = () => setFormData(prev => ({ ...prev, items: [...(prev.items || []), { description: '', amount: 0 }] }));
  const removeItem = (index: number) => setFormData(prev => ({ ...prev, items: prev.items?.filter((_, i) => i !== index) }));

  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...(formData.items || [])];
    newItems[index] = { ...newItems[index], [field]: field === 'amount' ? Number(value) : value };
    setFormData({ ...formData, items: newItems });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = formData.items?.reduce((sum, item) => sum + item.amount, 0) || 0;

    if (editingInvoice) {
      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? { ...inv, ...formData, totalAmount: total } as Invoice : inv));
    } else {
      const newInvoice: Invoice = {
        ...(formData as Invoice),
        id: generateNextInvoiceId(),
        totalAmount: total,
        createdAt: new Date().toISOString().split('T')[0],
      };
      setInvoices(prev => [...prev, newInvoice]);
    }
    setIsModalOpen(false);
  };

  const downloadPDF = (invoice: Invoice) => {
    const tenant = tenants.find(t => t.id === invoice.tenantId);
    const prop = properties.find(p => p.id === tenant?.propertyId);
    const settings = company.invoiceSettings || { primaryColor: '#4f46e5', fontFamily: 'helvetica' };

    const doc = new jsPDF();
    doc.setFont(settings.fontFamily);

    // Header Branding
    doc.setFillColor(settings.primaryColor);
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(24);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text(company.name, 15, 22);
    doc.setFontSize(9);
    doc.setFont(settings.fontFamily, 'normal');
    doc.text(company.address, 15, 29);
    doc.text(`Email: ${company.email}`, 15, 34);

    doc.setFontSize(14);
    doc.text(invoice.invoiceType.toUpperCase(), 195, 22, { align: 'right' });
    doc.setFontSize(10);
    doc.text(`No: ${invoice.id}`, 195, 29, { align: 'right' });
    doc.text(`Date: ${formatDate(invoice.createdAt)}`, 195, 34, { align: 'right' });

    // Body
    doc.setTextColor(40, 40, 40);
    doc.setFontSize(11);
    doc.text('BILL TO:', 15, 55);
    doc.setFontSize(12);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text(tenant?.name || 'N/A', 15, 62);
    doc.setFont(settings.fontFamily, 'normal');
    doc.setFontSize(9);
    const tenantAddr = doc.splitTextToSize(tenant?.address || '', 80);
    doc.text(tenantAddr, 15, 67);
    doc.text(`Property: ${prop ? `${prop.type} - ${prop.name}` : 'N/A'}`, 15, 67 + (tenantAddr.length * 5));

    doc.setFontSize(11);
    doc.setTextColor(settings.primaryColor);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text(`Billing Period: ${invoice.billingPeriod}`, 195, 62, { align: 'right' });
    doc.setTextColor(40, 40, 40);
    doc.text(`Due Date: ${formatDate(invoice.dueDate)}`, 195, 68, { align: 'right' });

    // Table
    const tableData = invoice.items.map(item => [item.description, `Rs. ${item.amount.toLocaleString()}`]);
    (doc as any).autoTable({
      startY: 85,
      head: [['Particulars', 'Amount']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: settings.primaryColor, fontStyle: 'bold' },
      styles: { fontSize: 10, cellPadding: 5 },
      foot: [['TOTAL AMOUNT', `Rs. ${invoice.totalAmount.toLocaleString()}`]],
      footStyles: { fillColor: [240, 240, 240], textColor: [0, 0, 0], fontStyle: 'bold' }
    });

    const finalY = (doc as any).lastAutoTable.finalY || 150;
    doc.setFontSize(11);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text('Amount in words:', 15, finalY + 12);
    doc.setFont(settings.fontFamily, 'normal');
    doc.setTextColor(settings.primaryColor);
    doc.text(`Rupees ${numberToWordsIndian(invoice.totalAmount)}`, 15, finalY + 18);

    doc.setTextColor(40, 40, 40);
    doc.setFontSize(9);
    doc.text('Notes:', 15, finalY + 30);
    doc.setFontSize(8);
    const notes = doc.splitTextToSize(invoice.notes || '', 180);
    doc.text(notes, 15, finalY + 35);

    if (invoice.bankDetails) {
      doc.setFontSize(9);
      doc.setFont(settings.fontFamily, 'bold');
      doc.text('Bank Details for Transfer:', 15, finalY + 55);
      doc.setFont(settings.fontFamily, 'normal');
      doc.setFontSize(8);
      const bank = doc.splitTextToSize(invoice.bankDetails, 180);
      doc.text(bank, 15, finalY + 60);
    }

    // Signature
    doc.setFontSize(10);
    doc.line(140, 270, 195, 270);
    doc.text('Authorized Signature', 145, 275);

    doc.save(`${invoice.id}_${tenant?.name}.pdf`);
  };

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Invoice Management</h2>
          <p className="text-slate-500 font-medium">Generate professional 6-month rental bills.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"
        >
          New Invoice
        </button>
      </header>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-4 text-[10px] font-black uppercase tracking-widest text-slate-400">Invoice / Tenant</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase tracking-widest text-slate-400">Period</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase tracking-widest text-slate-400 text-right">Total</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase tracking-widest text-slate-400 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {invoices.map(inv => {
              const tenant = tenants.find(t => t.id === inv.tenantId);
              return (
                <tr key={inv.id} className="hover:bg-indigo-50/30 transition-colors">
                  <td className="px-8 py-5">
                    <div className="font-black text-slate-900">{inv.id}</div>
                    <div className="text-xs text-slate-500 font-bold">{tenant?.name || 'Unknown'}</div>
                  </td>
                  <td className="px-8 py-5 text-sm font-bold text-slate-600">{inv.billingPeriod}</td>
                  <td className="px-8 py-5 text-right font-black text-indigo-600">₹{inv.totalAmount.toLocaleString()}</td>
                  <td className="px-8 py-5 text-right space-x-2">
                    <button onClick={() => downloadPDF(inv)} className="text-indigo-600 hover:text-indigo-800 font-black text-[10px] uppercase">PDF</button>
                    <button onClick={() => handleOpenModal(inv)} className="text-slate-400 hover:text-indigo-600 font-black text-[10px] uppercase">Edit</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {invoices.length === 0 && (
          <div className="p-20 text-center text-slate-300">
            <p className="text-4xl mb-2">📄</p>
            <p className="font-black text-xs uppercase tracking-widest">No invoices yet</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] w-full max-w-3xl max-h-[90vh] overflow-hidden shadow-2xl flex flex-col">
            <div className="px-10 py-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-900 tracking-tighter">
                {editingInvoice ? 'Update Invoice' : 'Draft New Invoice'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-300 hover:text-slate-900 transition-colors text-2xl">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-10 space-y-8 custom-scrollbar">
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Select Tenant</label>
                  <select 
                    required 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none focus:ring-4 focus:ring-indigo-500/10 font-bold transition-all"
                    value={formData.tenantId}
                    onChange={e => setFormData({...formData, tenantId: e.target.value})}
                  >
                    <option value="">Choose...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Billing Cycle</label>
                  <select 
                    required 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none focus:ring-4 focus:ring-indigo-500/10 font-bold transition-all"
                    value={formData.billingPeriod}
                    onChange={e => handlePeriodChange(e.target.value)}
                  >
                    <option value={PERIOD_1}>{PERIOD_1}</option>
                    <option value={PERIOD_2}>{PERIOD_2}</option>
                  </select>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Billing Particulars</label>
                  <button type="button" onClick={addItem} className="text-indigo-600 text-[10px] font-black uppercase tracking-widest hover:underline">+ Add Line</button>
                </div>
                <div className="space-y-3">
                  {formData.items?.map((item, idx) => (
                    <div key={idx} className="flex gap-4 group">
                      <input 
                        required 
                        className="flex-1 px-6 py-3 bg-slate-50 rounded-xl border-none focus:ring-4 focus:ring-indigo-500/10 font-medium" 
                        placeholder="Description"
                        value={item.description}
                        onChange={e => updateItem(idx, 'description', e.target.value)}
                      />
                      <div className="relative w-40">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">₹</span>
                        <input 
                          type="number" 
                          required 
                          className="w-full pl-10 pr-6 py-3 bg-slate-50 rounded-xl border-none focus:ring-4 focus:ring-indigo-500/10 font-black text-right" 
                          placeholder="0"
                          value={item.amount || ''}
                          onChange={e => updateItem(idx, 'amount', e.target.value)}
                        />
                      </div>
                      <button type="button" onClick={() => removeItem(idx)} className="text-slate-300 hover:text-rose-500 transition-colors">✕</button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Landlord Signature & Notes</label>
                  <textarea 
                    rows={4} 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none focus:ring-4 focus:ring-indigo-500/10 font-medium text-sm"
                    value={formData.notes}
                    onChange={e => setFormData({...formData, notes: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Bank Instructions</label>
                  <textarea 
                    rows={4} 
                    className="w-full px-6 py-4 bg-slate-50 rounded-2xl border-none focus:ring-4 focus:ring-indigo-500/10 font-mono text-xs"
                    value={formData.bankDetails}
                    onChange={e => setFormData({...formData, bankDetails: e.target.value})}
                  />
                </div>
              </div>

              <div className="flex justify-between items-center p-8 bg-indigo-50 rounded-3xl">
                <div>
                  <p className="text-[10px] font-black uppercase tracking-widest text-indigo-400">Total Calculation</p>
                  <p className="text-sm font-black text-indigo-900 mt-1 italic">
                    Rupees {numberToWordsIndian(formData.items?.reduce((s, i) => s + i.amount, 0) || 0)}
                  </p>
                </div>
                <p className="text-4xl font-black text-indigo-600 tracking-tighter">
                  ₹{(formData.items?.reduce((s, i) => s + i.amount, 0) || 0).toLocaleString()}
                </p>
              </div>

              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-slate-400 bg-slate-50 hover:bg-slate-100 transition-all">Cancel</button>
                <button type="submit" className="flex-[2] py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-white bg-indigo-600 shadow-xl shadow-indigo-200 hover:bg-indigo-700 active:scale-[0.98] transition-all">
                  {editingInvoice ? 'Update Record' : 'Create & Save'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Tenant, Invoice, Property } from '../types';

interface AIAssistantProps {
  tenants: Tenant[];
  invoices: Invoice[];
  properties: Property[];
}

export const AIAssistant: React.FC<AIAssistantProps> = ({ tenants, invoices, properties }) => {
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'ai', text: string }[]>([
    { role: 'ai', text: 'Welcome to the QUEENS CHAMBERS Intelligent Assistant. I have analyzed your portfolio of ' + properties.length + ' assets. How can I help you today?' }
  ]);
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || loading) return;

    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userText }]);
    setLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const context = {
        portfolio: {
          totalProperties: properties.length,
          tenants: tenants.length,
          revenue: invoices.reduce((s, i) => s + i.totalAmount, 0),
          types: properties.reduce((acc: any, p) => { acc[p.type] = (acc[p.type] || 0) + 1; return acc; }, {})
        }
      };

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Context: ${JSON.stringify(context)}. User: ${userText}`,
        config: {
          systemInstruction: "You are an elite property manager. Be professional, direct, and data-driven. Use ₹ for currency. Provide insights on occupancy, rental yield, and tenant relations. Format with clean bullet points."
        }
      });

      setMessages(prev => [...prev, { role: 'ai', text: response.text || "I apologize, I could not process that request." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', text: "Portfolio synchronization failed. Please check your network." }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="h-[calc(100vh-140px)] flex flex-col space-y-6">
      <header>
        <h2 className="text-3xl font-black text-slate-900 tracking-tight">AI Portfolio Analyst</h2>
        <p className="text-slate-500 font-medium">Real-time property insights and automation.</p>
      </header>

      <div className="flex-1 bg-white rounded-[2.5rem] shadow-2xl shadow-indigo-900/5 border border-slate-50 flex flex-col overflow-hidden">
        <div className="flex-1 overflow-y-auto p-10 space-y-6 custom-scrollbar">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] px-7 py-5 rounded-3xl text-[13px] leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white font-bold rounded-tr-none' 
                  : 'bg-slate-50 text-slate-800 rounded-tl-none border border-slate-100'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex gap-2 p-4 bg-slate-50 rounded-2xl w-fit animate-pulse">
              <div className="w-2 h-2 bg-indigo-400 rounded-full"></div>
              <div className="w-2 h-2 bg-indigo-400 rounded-full"></div>
              <div className="w-2 h-2 bg-indigo-400 rounded-full"></div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <div className="p-8 bg-slate-50/50 border-t border-slate-50">
          <form onSubmit={handleSend} className="flex gap-4">
            <input 
              value={input}
              onChange={e => setInput(e.target.value)}
              placeholder="Ask about revenue, vacancies, or draft a notice..."
              className="flex-1 px-8 py-5 rounded-[1.5rem] bg-white border border-slate-100 outline-none focus:ring-4 focus:ring-indigo-500/10 font-bold transition-all shadow-sm"
              disabled={loading}
            />
            <button 
              type="submit"
              disabled={loading || !input.trim()}
              className="bg-slate-900 text-white px-10 rounded-[1.5rem] font-black text-xs uppercase tracking-widest hover:bg-indigo-600 shadow-xl disabled:opacity-50 transition-all active:scale-95"
            >
              Analyze
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useRef } from 'react';
import { Tenant, Property } from '../types';

interface TenantsProps {
  tenants: Tenant[];
  properties: Property[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
}

export const Tenants: React.FC<TenantsProps> = ({ tenants, properties, setTenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTenant, setEditingTenant] = useState<Tenant | null>(null);
  const [propertyFilter, setPropertyFilter] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState<Partial<Tenant>>({
    name: '',
    email: '',
    phone: '',
    address: '',
    propertyId: '',
    // Fix: Added missing status to initial state
    status: 'Active',
  });

  const handleOpenModal = (tenant?: Tenant) => {
    if (tenant) {
      setEditingTenant(tenant);
      setFormData(tenant);
    } else {
      setEditingTenant(null);
      // Fix: Added missing status when resetting form
      setFormData({ name: '', email: '', phone: '', address: '', propertyId: '', status: 'Active' });
    }
    setIsModalOpen(true);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      if (!text) return;

      const lines = text.split(/\r?\n/);
      if (lines.length < 2) return;

      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
      const newTenants: Tenant[] = [];

      for (let i = 1; i < lines.length; i++) {
        if (!lines[i].trim()) continue;
        const values = lines[i].split(',').map(v => v.trim());
        const data: any = {};
        headers.forEach((h, idx) => { data[h] = values[idx]; });

        // Match property by name if provided, otherwise leave blank or find first
        let propId = data.propertyid || '';
        if (!propId && data.property) {
          const match = properties.find(p => p.name.toLowerCase() === data.property.toLowerCase());
          if (match) propId = match.id;
        }

        // Fix: Added missing status to imported tenants
        newTenants.push({
          id: `t${Date.now()}-${i}`,
          name: data.name || 'Unknown',
          email: data.email || '',
          phone: data.phone || '',
          address: data.address || '',
          propertyId: propId || (properties.length > 0 ? properties[0].id : ''),
          status: (data.status as any) || 'Active',
        });
      }

      if (newTenants.length > 0) {
        setTenants(prev => [...prev, ...newTenants]);
        alert(`Successfully imported ${newTenants.length} tenants.`);
      }
    };
    reader.readAsText(file);
    e.target.value = ''; // Reset input
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTenant) {
      setTenants(prev => prev.map(t => t.id === editingTenant.id ? { ...t, ...formData } as Tenant : t));
    } else {
      // Fix: Added missing status to new tenant object
      const tenant: Tenant = {
        id: `t${Date.now()}`,
        name: formData.name!,
        email: formData.email!,
        phone: formData.phone!,
        address: formData.address || '',
        propertyId: formData.propertyId!,
        status: formData.status || 'Active',
      };
      setTenants(prev => [...prev, tenant]);
    }
    setIsModalOpen(false);
  };

  const filteredAndSortedTenants = useMemo(() => {
    let result = [...tenants];

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(t => 
        t.name.toLowerCase().includes(q) || 
        t.email.toLowerCase().includes(q) ||
        t.phone.toLowerCase().includes(q)
      );
    }

    if (propertyFilter !== 'All') {
      result = result.filter(t => t.propertyId === propertyFilter);
    }

    return result.sort((a, b) => {
      const propA = properties.find(p => p.id === a.propertyId);
      const propB = properties.find(p => p.id === b.propertyId);
      const nameA = propA ? `${propA.type} ${propA.name}` : '';
      const nameB = propB ? `${propB.type} ${propB.name}` : '';

      if (nameA < nameB) return -1;
      if (nameA > nameB) return 1;
      return a.name.localeCompare(b.name);
    });
  }, [tenants, properties, propertyFilter, searchQuery]);

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Tenants</h2>
          <p className="text-slate-500 mt-1">Manage tenant contacts, addresses, and unit assignments.</p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".csv" 
            className="hidden" 
          />
          <button 
            onClick={handleImportClick}
            className="bg-slate-100 text-slate-700 px-5 py-2.5 rounded-xl font-medium hover:bg-slate-200 transition-colors flex items-center gap-2"
          >
            <span>📥</span> Import CSV
          </button>
          <button 
            onClick={() => handleOpenModal()}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 shadow-lg shadow-indigo-200"
          >
            <span>➕</span> Add Tenant
          </button>
        </div>
      </header>

      {/* Control Bar */}
      <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-64">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">🔍</span>
          <input 
            type="text" 
            placeholder="Search name, email..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm"
          />
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
          <label className="text-xs font-bold text-slate-400 uppercase whitespace-nowrap">Filter Property:</label>
          <select 
            value={propertyFilter}
            onChange={(e) => setPropertyFilter(e.target.value)}
            className="flex-1 md:flex-none px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium text-slate-700"
          >
            <option value="All">All Properties</option>
            {properties.map(p => (
              <option key={p.id} value={p.id}>{p.type} {p.name}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Tenant & Contact</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Address</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase">Property</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-400 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredAndSortedTenants.map((tenant) => {
              const prop = properties.find(p => p.id === tenant.propertyId);
              return (
                <tr key={tenant.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{tenant.name}</div>
                    <div className="text-xs text-slate-500">{tenant.email} • {tenant.phone}</div>
                  </td>
                  <td className="px-6 py-4 text-sm text-slate-600 truncate max-w-[200px]">
                    {tenant.address || <span className="text-slate-300 italic">No address</span>}
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-sm font-medium px-2.5 py-1 bg-indigo-50 rounded-lg text-indigo-700 whitespace-nowrap">
                      {prop ? `${prop.type} ${prop.name}` : 'Unassigned'}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button onClick={() => handleOpenModal(tenant)} className="text-indigo-600 hover:text-indigo-800 font-medium text-sm">✏️ Edit</button>
                    <button onClick={() => setTenants(prev => prev.filter(t => t.id !== tenant.id))} className="text-slate-400 hover:text-red-600 text-sm ml-2">🗑️ Delete</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredAndSortedTenants.length === 0 && (
          <div className="p-16 text-center text-slate-300">
            <p className="text-5xl mb-4">👥</p>
            <p className="font-bold text-slate-400">
              {searchQuery || propertyFilter !== 'All' ? 'No matching tenants found.' : 'No tenants registered.'}
            </p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl animate-in zoom-in-95">
            <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-900">{editingTenant ? 'Edit Tenant' : 'New Tenant'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Full Name</label>
                <input value={formData.name} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Email</label>
                  <input type="email" value={formData.email} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, email: e.target.value})} />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Phone</label>
                  <input value={formData.phone} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, phone: e.target.value})} />
                </div>
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Tenant Address</label>
                <textarea value={formData.address} rows={2} className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="Enter permanent or billing address" onChange={e => setFormData({...formData, address: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Assigned Property</label>
                <select value={formData.propertyId} required className="w-full px-4 py-2 rounded-lg border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 transition-all" onChange={e => setFormData({...formData, propertyId: e.target.value})}>
                  <option value="">Select a property</option>
                  {properties.map(p => <option key={p.id} value={p.id}>{p.type} {p.name}</option>)}
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-2.5 rounded-xl border font-semibold text-slate-600 hover:bg-slate-50 transition-colors">Cancel</button>
                <button type="submit" className="flex-1 py-2.5 rounded-xl bg-indigo-600 text-white font-semibold shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Save Tenant</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

{
  "name": "queens-chambers-manager",
  "version": "1.0.0",
  "private": true,
  "dependencies": {
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "@google/genai": "^1.3.0",
    "recharts": "^2.12.7",
    "jspdf": "^2.5.1",
    "jspdf-autotable": "^3.8.2"
  }
}

import React, { useState, useEffect } from 'react';
import { Invoice, Tenant, InvoiceItem, Property, CompanyInfo } from '../types';
import { jsPDF } from 'jspdf';
import 'jspdf-autotable';

interface InvoicesProps {
  invoices: Invoice[];
  tenants: Tenant[];
  properties: Property[];
  company: CompanyInfo;
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
}

const formatDate = (dateStr: string) => {
  if (!dateStr) return '';
  const [year, month, day] = dateStr.split('-');
  return `${day}-${month}-${year}`;
};

const getAutomatedPeriod = () => {
  const now = new Date();
  const month = now.getMonth(); // 0-indexed
  const year = now.getFullYear();

  if (month >= 3 && month <= 8) { // April to Sept
    return `01 April ${year} to 30 September ${year}`;
  } else if (month >= 9) { // Oct to Dec
    return `01 October ${year} to 31 March ${year + 1}`;
  } else { // Jan to March
    return `01 October ${year - 1} to 31 March ${year}`;
  }
};

const numberToWordsIndian = (num: number): string => {
  const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
  const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];

  const convert_less_than_thousand = (n: number): string => {
    if (n === 0) return '';
    if (n < 20) return a[n];
    const res = b[Math.floor(n / 10)] + ' ' + a[n % 10];
    return res.trim() + ' ';
  };

  if (num === 0) return 'Zero';

  let words = '';
  let n = Math.floor(num);

  if (Math.floor(n / 10000000) > 0) {
    words += convert_less_than_thousand(Math.floor(n / 10000000)) + 'Crore ';
    n %= 10000000;
  }
  if (Math.floor(n / 100000) > 0) {
    words += convert_less_than_thousand(Math.floor(n / 100000)) + 'Lakh ';
    n %= 100000;
  }
  if (Math.floor(n / 1000) > 0) {
    words += convert_less_than_thousand(Math.floor(n / 1000)) + 'Thousand ';
    n %= 1000;
  }
  if (Math.floor(n / 100) > 0) {
    words += a[Math.floor(n / 100)] + 'Hundred ';
    n %= 100;
  }
  if (n > 0) {
    if (words !== '') words += 'and ';
    words += convert_less_than_thousand(n);
  }

  return words.trim() + ' Only';
};

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, properties, company, setInvoices }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);

  const defaultNotes = "Issued by Landlord\nMr. Ayyub Bux\nMr. Yousuf Bux";
  const defaultBankDetails = "Name of Account: Ayyub Vali Bux\nBank Name: ICICI Bank Ltd\nAccount No.: 055501081974\nIFSC Code: ICIC0005256\nBranch Name: Umraj, Bharuch\n\nPlease prepare cheques or transfer through NEFT/RTGS to beneficiary account name - Ayyub Vali Bux";

  const defaultItems: InvoiceItem[] = [
    { description: 'Rent Charges', amount: 0 },
    { description: 'Repair & Municipal Tax', amount: 0 },
    { description: 'Service charges for common area', amount: 0 }
  ];

  const [formData, setFormData] = useState<Partial<Invoice>>({
    tenantId: '',
    dueDate: '',
    items: [...defaultItems],
    notes: defaultNotes,
    bankDetails: defaultBankDetails,
    billingPeriod: getAutomatedPeriod(),
    invoiceType: 'Rent Invoice'
  });

  const generateNextInvoiceId = () => {
    if (invoices.length === 0) return 'INV-001';
    const ids = invoices.map(inv => parseInt(inv.id.replace('INV-', ''), 10)).filter(n => !isNaN(n));
    const maxId = ids.length > 0 ? Math.max(...ids) : 0;
    return `INV-${(maxId + 1).toString().padStart(3, '0')}`;
  };

  const handleOpenModal = (inv?: Invoice) => {
    if (inv) {
      setEditingInvoice(inv);
      setFormData(inv);
    } else {
      setEditingInvoice(null);
      setFormData({
        tenantId: '',
        dueDate: new Date().toISOString().split('T')[0],
        items: [...defaultItems],
        notes: defaultNotes,
        bankDetails: defaultBankDetails,
        billingPeriod: getAutomatedPeriod(),
        invoiceType: 'Rent Invoice'
      });
    }
    setIsModalOpen(true);
  };

  const addItem = () => setFormData(prev => ({ ...prev, items: [...(prev.items || []), { description: '', amount: 0 }] }));
  const removeItem = (index: number) => setFormData(prev => ({ ...prev, items: prev.items?.filter((_, i) => i !== index) }));

  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...(formData.items || [])];
    newItems[index] = { ...newItems[index], [field]: field === 'amount' ? Number(value) : value };
    setFormData({ ...formData, items: newItems });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = formData.items?.reduce((sum, item) => sum + item.amount, 0) || 0;

    if (editingInvoice) {
      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? { ...inv, ...formData, totalAmount: total } as Invoice : inv));
    } else {
      const newInvoice: Invoice = {
        ...(formData as Invoice),
        id: generateNextInvoiceId(),
        totalAmount: total,
        createdAt: new Date().toISOString().split('T')[0],
      };
      setInvoices(prev => [...prev, newInvoice]);
    }
    setIsModalOpen(false);
  };

  const downloadPDF = (invoice: Invoice) => {
    const tenant = tenants.find(t => t.id === invoice.tenantId);
    const prop = properties.find(p => p.id === tenant?.propertyId);
    const settings = company.invoiceSettings || { primaryColor: '#4f46e5', fontFamily: 'helvetica' };

    const doc = new jsPDF();
    doc.setFont(settings.fontFamily);

    doc.setFillColor(settings.primaryColor);
    doc.rect(0, 0, 210, 45, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(26);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text(company.name, 15, 22);
    doc.setFontSize(9);
    doc.setFont(settings.fontFamily, 'normal');
    doc.text(company.address, 15, 31);
    doc.text(`Email: ${company.email}`, 15, 37);

    doc.setFontSize(14);
    doc.text(invoice.invoiceType.toUpperCase(), 195, 22, { align: 'right' });
    doc.setFontSize(10);
    doc.text(`Invoice No: ${invoice.id}`, 195, 31, { align: 'right' });
    doc.text(`Date: ${formatDate(invoice.createdAt)}`, 195, 37, { align: 'right' });

    doc.setTextColor(40, 40, 40);
    doc.setFontSize(11);
    doc.text('BILL TO:', 15, 60);
    doc.setFontSize(13);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text(tenant?.name || 'N/A', 15, 68);
    doc.setFont(settings.fontFamily, 'normal');
    doc.setFontSize(9);
    const tenantAddr = doc.splitTextToSize(tenant?.address || '', 80);
    doc.text(tenantAddr, 15, 74);
    doc.text(`Property: ${prop ? `${prop.type} - ${prop.name}` : 'N/A'}`, 15, 74 + (tenantAddr.length * 5) + 2);

    doc.setFontSize(11);
    doc.setTextColor(settings.primaryColor);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text(`Billing Period:`, 195, 68, { align: 'right' });
    doc.setFontSize(10);
    doc.text(invoice.billingPeriod, 195, 74, { align: 'right' });
    doc.setTextColor(40, 40, 40);
    doc.text(`Due Date: ${formatDate(invoice.dueDate)}`, 195, 80, { align: 'right' });

    (doc as any).autoTable({
      startY: 95,
      head: [['Particulars of Charges', 'Amount (INR)']],
      body: invoice.items.map(item => [item.description, `Rs. ${item.amount.toLocaleString()}`]),
      theme: 'grid',
      headStyles: { fillColor: settings.primaryColor, fontStyle: 'bold' },
      styles: { fontSize: 10, cellPadding: 6 },
      foot: [['TOTAL PAYABLE', `Rs. ${invoice.totalAmount.toLocaleString()}`]],
      footStyles: { fillColor: [245, 245, 245], textColor: [0, 0, 0], fontStyle: 'bold' }
    });

    const finalY = (doc as any).lastAutoTable.finalY || 160;
    doc.setFontSize(11);
    doc.setFont(settings.fontFamily, 'bold');
    doc.text('Amount in words:', 15, finalY + 15);
    doc.setFont(settings.fontFamily, 'normal');
    doc.setTextColor(settings.primaryColor);
    doc.text(`Rupees ${numberToWordsIndian(invoice.totalAmount)}`, 15, finalY + 22);

    doc.setTextColor(100, 116, 139);
    doc.setFontSize(9);
    doc.text('Instructions & Notes:', 15, finalY + 35);
    doc.setFontSize(8);
    const notes = doc.splitTextToSize(invoice.notes || '', 180);
    doc.text(notes, 15, finalY + 41);

    if (invoice.bankDetails) {
      doc.setFontSize(9);
      doc.setFont(settings.fontFamily, 'bold');
      doc.setTextColor(40, 40, 40);
      doc.text('Electronic Fund Transfer Details:', 15, finalY + 65);
      doc.setFont(settings.fontFamily, 'normal');
      doc.setFontSize(8);
      const bank = doc.splitTextToSize(invoice.bankDetails, 180);
      doc.text(bank, 15, finalY + 71);
    }

    doc.setFontSize(10);
    doc.line(140, 270, 195, 270);
    doc.text('Authorized Signature', 145, 275);

    doc.save(`${invoice.id}_${tenant?.name?.replace(/\s+/g, '_')}.pdf`);
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Invoicing</h2>
          <p className="text-slate-500 font-medium">Issue professional 6-month rental statements.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-2xl shadow-indigo-600/20 transition-all active:scale-95"
        >
          Generate New Invoice
        </button>
      </header>

      <div className="bg-white rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-10 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">Reference</th>
              <th className="px-10 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">Tenant / Unit</th>
              <th className="px-10 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">Period</th>
              <th className="px-10 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400 text-right">Total Payable</th>
              <th className="px-10 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400 text-right">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {invoices.map(inv => {
              const tenant = tenants.find(t => t.id === inv.tenantId);
              const prop = properties.find(p => p.id === tenant?.propertyId);
              return (
                <tr key={inv.id} className="hover:bg-indigo-50/40 transition-colors group">
                  <td className="px-10 py-6">
                    <div className="font-black text-slate-900">{inv.id}</div>
                    <div className="text-[10px] text-slate-400 font-bold">{formatDate(inv.createdAt)}</div>
                  </td>
                  <td className="px-10 py-6">
                    <div className="font-bold text-slate-700">{tenant?.name || 'Unknown'}</div>
                    <div className="text-[11px] text-indigo-500 font-black uppercase tracking-wider">{prop?.type} {prop?.name}</div>
                  </td>
                  <td className="px-10 py-6 text-sm font-bold text-slate-500">{inv.billingPeriod}</td>
                  <td className="px-10 py-6 text-right font-black text-slate-900 text-lg">₹{inv.totalAmount.toLocaleString()}</td>
                  <td className="px-10 py-6 text-right space-x-3">
                    <button onClick={() => downloadPDF(inv)} className="bg-white border border-slate-200 text-slate-600 hover:text-indigo-600 hover:border-indigo-600 p-2.5 rounded-xl transition-all shadow-sm">
                      📥
                    </button>
                    <button onClick={() => handleOpenModal(inv)} className="bg-white border border-slate-200 text-slate-600 hover:text-indigo-600 hover:border-indigo-600 p-2.5 rounded-xl transition-all shadow-sm">
                      ✏️
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {invoices.length === 0 && (
          <div className="p-32 text-center">
            <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-4xl">📄</div>
            <p className="font-black text-xs uppercase tracking-[0.2em] text-slate-300">No invoices generated yet</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-[3rem] w-full max-w-4xl max-h-[92vh] overflow-hidden shadow-[0_0_100px_rgba(0,0,0,0.2)] flex flex-col">
            <div className="px-12 py-10 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <div>
                <h3 className="text-3xl font-black text-slate-900 tracking-tighter">
                  {editingInvoice ? 'Modify Invoice' : 'New Billing Statement'}
                </h3>
                <p className="text-slate-400 text-sm font-medium mt-1">Drafting a official invoice for tenant records.</p>
              </div>
              <button onClick={() => setIsModalOpen(false)} className="w-12 h-12 flex items-center justify-center rounded-full hover:bg-slate-100 transition-colors text-2xl">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-12 space-y-10 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Select Tenant</label>
                  <select 
                    required 
                    className="w-full px-8 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-4 focus:ring-indigo-500/10 font-bold transition-all text-slate-700"
                    value={formData.tenantId}
                    onChange={e => setFormData({...formData, tenantId: e.target.value})}
                  >
                    <option value="">Choose tenant...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Billing Cycle (6-Month)</label>
                  <input 
                    required 
                    className="w-full px-8 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-4 focus:ring-indigo-500/10 font-bold transition-all text-slate-700"
                    value={formData.billingPeriod}
                    onChange={e => setFormData({...formData, billingPeriod: e.target.value})}
                    placeholder="e.g. 01 April 2026 to 30 Sept 2026"
                  />
                </div>
              </div>

              <div className="space-y-6">
                <div className="flex justify-between items-center border-b border-slate-100 pb-4">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Statement Particulars</label>
                  <button type="button" onClick={addItem} className="text-indigo-600 text-[10px] font-black uppercase tracking-widest hover:bg-indigo-50 px-4 py-2 rounded-full transition-all">+ Add Item</button>
                </div>
                <div className="space-y-4">
                  {formData.items?.map((item, idx) => (
                    <div key={idx} className="flex gap-4 items-center">
                      <div className="flex-1">
                        <input 
                          required 
                          className="w-full px-8 py-4 bg-slate-50 rounded-2xl border-none focus:ring-4 focus:ring-indigo-500/10 font-medium" 
                          placeholder="Particulars"
                          value={item.description}
                          onChange={e => updateItem(idx, 'description', e.target.value)}
                        />
                      </div>
                      <div className="w-48 relative">
                        <span className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400 font-black">₹</span>
                        <input 
                          type="number" 
                          required 
                          className="w-full pl-12 pr-8 py-4 bg-slate-50 rounded-2xl border-none focus:ring-4 focus:ring-indigo-500/10 font-black text-right" 
                          placeholder="0.00"
                          value={item.amount || ''}
                          onChange={e => updateItem(idx, 'amount', e.target.value)}
                        />
                      </div>
                      <button type="button" onClick={() => removeItem(idx)} className="w-10 h-10 flex items-center justify-center text-slate-300 hover:text-rose-500 transition-colors">✕</button>
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Notes / Signature Block</label>
                  <textarea 
                    rows={4} 
                    className="w-full px-8 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-4 focus:ring-indigo-500/10 font-medium text-sm text-slate-600"
                    value={formData.notes}
                    onChange={e => setFormData({...formData, notes: e.target.value})}
                  />
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Bank Payment Instructions</label>
                  <textarea 
                    rows={4} 
                    className="w-full px-8 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-4 focus:ring-indigo-500/10 font-mono text-[10px] text-slate-500"
                    value={formData.bankDetails}
                    onChange={e => setFormData({...formData, bankDetails: e.target.value})}
                  />
                </div>
              </div>

              <div className="flex flex-col md:flex-row justify-between items-center p-10 bg-indigo-600 rounded-[2.5rem] text-white shadow-2xl shadow-indigo-600/30">
                <div className="mb-6 md:mb-0">
                  <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-200">Total Amount in Words</p>
                  <p className="text-sm font-bold mt-2 opacity-90 max-w-md">
                    Rupees {numberToWordsIndian(formData.items?.reduce((s, i) => s + i.amount, 0) || 0)}
                  </p>
                </div>
                <div className="text-center md:text-right">
                  <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-200">Total Payable</p>
                  <p className="text-5xl font-black mt-1 tracking-tighter">
                    ₹{(formData.items?.reduce((s, i) => s + i.amount, 0) || 0).toLocaleString()}
                  </p>
                </div>
              </div>

              <div className="flex gap-6 pt-6">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-6 rounded-[1.5rem] font-black text-xs uppercase tracking-widest text-slate-400 bg-slate-50 hover:bg-slate-100 transition-all">Discard</button>
                <button type="submit" className="flex-[2] py-6 rounded-[1.5rem] font-black text-xs uppercase tracking-widest text-white bg-slate-900 shadow-2xl shadow-slate-900/20 hover:bg-indigo-600 active:scale-[0.98] transition-all">
