import React, { useState } from 'react';
import { Invoice, Tenant, InvoiceItem, Property, CompanyInfo, InvoiceStatus } from '../types';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface InvoicesProps {
  invoices: Invoice[];
  tenants: Tenant[];
  properties: Property[];
  company: CompanyInfo;
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
}

const numberToWordsIndian = (num: number): string => {
  const a = ['', 'One ', 'Two ', 'Three ', 'Four ', 'Five ', 'Six ', 'Seven ', 'Eight ', 'Nine ', 'Ten ', 'Eleven ', 'Twelve ', 'Thirteen ', 'Fourteen ', 'Fifteen ', 'Sixteen ', 'Seventeen ', 'Eighteen ', 'Nineteen '];
  const b = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
  const convert_less_than_thousand = (n: number): string => {
    if (n === 0) return '';
    if (n < 20) return a[n];
    return b[Math.floor(n / 10)] + ' ' + a[n % 10] + ' ';
  };
  if (num === 0) return 'Zero';
  let words = '';
  let n = Math.floor(num);
  if (Math.floor(n / 10000000) > 0) { words += convert_less_than_thousand(Math.floor(n / 10000000)) + 'Crore '; n %= 10000000; }
  if (Math.floor(n / 100000) > 0) { words += convert_less_than_thousand(Math.floor(n / 100000)) + 'Lakh '; n %= 100000; }
  if (Math.floor(n / 1000) > 0) { words += convert_less_than_thousand(Math.floor(n / 1000)) + 'Thousand '; n %= 1000; }
  if (Math.floor(n / 100) > 0) { words += a[Math.floor(n / 100)] + 'Hundred '; n %= 100; }
  if (n > 0) { if (words !== '') words += 'and '; words += convert_less_than_thousand(n); }
  return words.trim() + ' Only';
};

const getAutomatedCycle = () => {
  const now = new Date();
  const year = now.getFullYear();
  return now.getMonth() >= 3 && now.getMonth() <= 8 
    ? `01 April ${year} to 30 September ${year}`
    : `01 October ${year} to 31 March ${year + 1}`;
};

export const Invoices: React.FC<InvoicesProps> = ({ invoices, tenants, properties, company, setInvoices }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingInvoice, setEditingInvoice] = useState<Invoice | null>(null);
  const [formData, setFormData] = useState<Partial<Invoice>>({
    tenantId: '',
    items: [{ description: 'Rent Charges', amount: 0 }, { description: 'Municipal Tax', amount: 0 }],
    billingPeriod: getAutomatedCycle(),
    invoiceType: 'Rent Invoice',
    status: 'Draft'
  });

  const getNextInvoiceId = () => {
    if (!invoices || invoices.length === 0) return 'INV-001';

    // Extract numbers from all IDs like "INV-001"
    const ids = invoices.map(inv => {
      const match = inv.id.match(/\d+/);
      return match ? parseInt(match[0], 10) : 0;
    });

    const maxId = Math.max(...ids);
    const nextId = maxId + 1;

    // Pad to 3 digits minimum
    return `INV-${String(nextId).padStart(3, '0')}`;
  };

  const handleStatusChange = (id: string, newStatus: InvoiceStatus) => {
    setInvoices(prev => prev.map(inv => inv.id === id ? { ...inv, status: newStatus } : inv));
  };

  const handleEditClick = (invoice: Invoice) => {
    setEditingInvoice(invoice);
    setFormData({
      ...invoice,
      items: [...invoice.items]
    });
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingInvoice(null);
    setFormData({
      tenantId: '',
      items: [{ description: 'Rent Charges', amount: 0 }, { description: 'Municipal Tax', amount: 0 }],
      billingPeriod: getAutomatedCycle(),
      invoiceType: 'Rent Invoice',
      status: 'Draft'
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = formData.items?.reduce((sum, item) => sum + item.amount, 0) || 0;

    if (editingInvoice) {
      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? {
        ...formData as Invoice,
        totalAmount: total
      } : inv));
    } else {
      const newInvoice: Invoice = {
        ...formData as Invoice,
        id: getNextInvoiceId(),
        totalAmount: total,
        createdAt: new Date().toISOString().split('T')[0],
        dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]
      };
      setInvoices(prev => [newInvoice, ...prev]);
    }
    closeModal();
  };

  const downloadPDF = (invoice: Invoice) => {
    const tenant = tenants.find(t => t.id === invoice.tenantId);
    const prop = properties.find(p => p.id === tenant?.propertyId);
    const doc = new jsPDF();

    doc.setFillColor(15, 23, 42); 
    doc.rect(0, 0, 210, 45, 'F');
    doc.setTextColor(129, 140, 248); 
    doc.setFontSize(24);
    doc.setFont('helvetica', 'bold');
    doc.text(company.name, 15, 20);

    doc.setTextColor(255, 255, 255);
    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    const addressLines = [
      "5th Floor, Flat A, 89 Maharshi Karve Road,",
      "Marine Lines, Mumbai - 400020"
    ];
    doc.text(addressLines[0], 15, 30);
    doc.text(addressLines[1], 15, 35);
    doc.text(`Email: ${company.email}`, 15, 40);

    doc.setTextColor(15, 23, 42);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.text('TENANT / BILL TO:', 15, 60);

    doc.setFontSize(12);
    doc.text(tenant?.name || 'N/A', 15, 68);

    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');
    const tenantAddress = tenant?.address || 'Address not provided';
    const splitTenantAddress = doc.splitTextToSize(tenantAddress, 80);
    doc.text(splitTenantAddress, 15, 74);

    const nextY = 74 + (splitTenantAddress.length * 5);
    doc.setFont('helvetica', 'bold');
    doc.text(`Unit Reference: ${prop ? `${prop.type} ${prop.name}` : 'N/A'}`, 15, nextY + 2);

    doc.setFont('helvetica', 'normal');
    doc.text(`Invoice ID: ${invoice.id}`, 140, 60);
    doc.text(`Date: ${invoice.createdAt}`, 140, 65);
    doc.text(`Period: ${invoice.billingPeriod}`, 140, 70);

    autoTable(doc, {
      startY: nextY + 15,
      head: [['Description', 'Amount']],
      body: invoice.items.map(i => [i.description, `Rs. ${i.amount.toLocaleString()}`]),
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229], fontStyle: 'bold' },
      foot: [['GRAND TOTAL', `Rs. ${invoice.totalAmount.toLocaleString()}`]],
      footStyles: { fillColor: [241, 245, 249], textColor: [15, 23, 42], fontStyle: 'bold' }
    });

    const finalY = (doc as any).lastAutoTable?.finalY || 150;

    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.text(`Amount in words:`, 15, finalY + 10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Rupees ${numberToWordsIndian(invoice.totalAmount)}`, 15, finalY + 15);

    doc.setDrawColor(226, 232, 240);
    doc.line(15, finalY + 25, 195, finalY + 25);

    doc.setFontSize(8);
    doc.setFont('helvetica', 'bold');
    doc.text('Landlord Declaration:', 15, finalY + 32);
    doc.setFont('helvetica', 'normal');
    doc.text('Issued by Landlord, Mr. Ayyub Bux, Mr. Yousuf Bux', 15, finalY + 37);
    doc.text('This is a computer-generated document and does not require a physical signature.', 15, finalY + 42);

    doc.save(`${invoice.id}_Statement.pdf`);
  };

  const getStatusStyle = (status: InvoiceStatus) => {
    switch (status) {
      case 'Paid': return 'bg-emerald-50 text-emerald-600 border-emerald-100';
      case 'Overdue': return 'bg-rose-50 text-rose-600 border-rose-100';
      case 'Sent': return 'bg-blue-50 text-blue-600 border-blue-100';
      default: return 'bg-slate-50 text-slate-500 border-slate-100';
    }
  };

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-900">Statements</h2>
          <p className="text-slate-500 text-sm mt-1">Manage and track rental receivables.</p>
        </div>
        <button onClick={() => setIsModalOpen(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-indigo-200">New Statement</button>
      </header>

