                    <option value="">Choose tenant...</option>
                    {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-xs font-black uppercase text-slate-400 block mb-2">Billing Period</label>
                  <input 
                    className="w-full p-4 bg-slate-50 rounded-xl border border-transparent focus:border-indigo-500 outline-none font-medium" 
                    value={formData.billingPeriod} 
                    onChange={e => setFormData({...formData, billingPeriod: e.target.value})} 
                  />
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <label className="text-xs font-black uppercase text-slate-400 block">Particulars</label>
                  <button type="button" onClick={() => setFormData({...formData, items: [...(formData.items || []), {description: '', amount: 0}]})} className="text-[10px] font-black text-indigo-600 uppercase tracking-widest hover:underline">+ Add Row</button>
                </div>
                <div className="max-h-[200px] overflow-y-auto pr-2 custom-scrollbar space-y-3">
                  {formData.items?.map((item, idx) => (
                    <div key={idx} className="flex gap-4 animate-in fade-in duration-200">
                      <input placeholder="Description" className="flex-1 p-3 bg-slate-50 rounded-lg border border-transparent focus:border-indigo-500 outline-none text-sm font-medium" value={item.description} onChange={e => {
                        const newItems = [...formData.items!];
                        newItems[idx].description = e.target.value;
                        setFormData({...formData, items: newItems});
                      }} />
                      <input type="number" placeholder="0" className="w-32 p-3 bg-slate-50 rounded-lg border border-transparent focus:border-indigo-500 outline-none text-right font-bold text-indigo-600" value={item.amount} onChange={e => {
                        const newItems = [...formData.items!];
                        newItems[idx].amount = Number(e.target.value);
                        setFormData({...formData, items: newItems});
                      }} />
                      {formData.items!.length > 1 && (
                        <button type="button" onClick={() => {
                          const newItems = formData.items!.filter((_, i) => i !== idx);
                          setFormData({...formData, items: newItems});
                        }} className="text-rose-400 hover:text-rose-600 transition-colors">✕</button>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              <div className="pt-4 border-t border-slate-100">
                <div className="flex justify-between items-center mb-6">
                  <span className="text-xs font-black uppercase text-slate-400">Final Total</span>
                  <span className="text-2xl font-black text-slate-900">₹{(formData.items?.reduce((s, i) => s + i.amount, 0) || 0).toLocaleString()}</span>
                </div>
                <button type="submit" className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-indigo-200 hover:bg-indigo-700 hover:scale-[1.01] transition-all">
                  {editingInvoice ? 'Update & Save Changes' : 'Finalize & Record'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';

interface LoginProps {
