          <p className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">Authorized Access Only</p>
        </div>

        <div className="pt-4">
          <p className="text-slate-600 text-[10px] font-medium opacity-50 uppercase tracking-[0.2em]">
            &copy; 2024 Queens Chambers Real Estate Management
          </p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Tenant, Property } from '../types';

interface TenantsProps {
  tenants: Tenant[];
  properties: Property[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
}

export const Tenants: React.FC<TenantsProps> = ({ tenants, properties, setTenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState<Partial<Tenant>>({ name: '', email: '', phone: '', address: '', propertyId: '', status: 'Active' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newTenant: Tenant = {
      ...formData as Tenant,
      id: `T-${Date.now().toString().slice(-4)}`
    };
    setTenants(prev => [...prev, newTenant]);
    setIsModalOpen(false);
    setFormData({ name: '', email: '', phone: '', address: '', propertyId: '', status: 'Active' });
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const importedData = JSON.parse(event.target?.result as string);
        if (Array.isArray(importedData)) {
          setTenants(prev => [...prev, ...importedData]);
          alert(`Successfully imported ${importedData.length} tenants.`);
        }
      } catch (err) {
        alert("Invalid JSON file format.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-900">Tenants</h2>
          <p className="text-sm text-slate-500">Registry of all active and former residents.</p>
        </div>
        <div className="flex gap-3">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImport} 
            accept=".json" 
            className="hidden" 
          />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="bg-white border border-slate-200 text-slate-600 px-6 py-3 rounded-2xl font-bold hover:bg-slate-50 transition-all flex items-center gap-2"
          >
            <span>📥</span> Import
          </button>
          <button onClick={() => setIsModalOpen(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all">
            + Add Tenant
          </button>
        </div>
      </header>

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400">Name</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400">Unit</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400">Contact</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400 text-right">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {tenants.map(t => (
              <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-8 py-5 font-bold text-slate-900">{t.name}</td>
                <td className="px-8 py-5 text-slate-600 font-medium">
                  {properties.find(p => p.id === t.propertyId)?.name || <span className="text-rose-400 italic text-xs">Unassigned</span>}
                </td>
                <td className="px-8 py-5 text-sm text-slate-500">
                  <div className="font-medium text-slate-700">{t.phone}</div>
                  <div className="text-[10px] text-slate-400">{t.email}</div>
                </td>
                <td className="px-8 py-5 text-right">
                  <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${
                    t.status === 'Active' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-500'
                  }`}>{t.status}</span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {tenants.length === 0 && (
          <div className="py-20 text-center">
            <p className="text-4xl mb-4">👥</p>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">No tenants registered</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-in">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-black">Add New Tenant</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-900">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-4">
              <input placeholder="Full Name" required className="w-full p-4 bg-slate-50 rounded-xl outline-none font-medium border border-transparent focus:border-indigo-500 transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
              <input placeholder="Email Address" required type="email" className="w-full p-4 bg-slate-50 rounded-xl outline-none font-medium border border-transparent focus:border-indigo-500 transition-all" onChange={e => setFormData({...formData, email: e.target.value})} />
              <input placeholder="Phone Number" required className="w-full p-4 bg-slate-50 rounded-xl outline-none font-medium border border-transparent focus:border-indigo-500 transition-all" onChange={e => setFormData({...formData, phone: e.target.value})} />
              <textarea placeholder="Billing Address" rows={3} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-medium border border-transparent focus:border-indigo-500 transition-all" onChange={e => setFormData({...formData, address: e.target.value})} />
              <select required className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setFormData({...formData, propertyId: e.target.value})}>
