              <button type="submit" className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-black shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all">Register Tenant</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
