    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.text('ISSUED BY LANDLORD', 15, currentY + 5);
    doc.setFont('helvetica', 'normal');
    doc.text('Mr. Ayyub Bux', 15, currentY + 10);
    doc.text('Mr. Yousuf Bux', 15, currentY + 15);

