      setInvoices(prev => prev.map(inv => inv.id === editingInvoice.id ? {
        ...formData as Invoice,
        totalAmount: total
      } : inv));
    } else {
      const newInvoice: Invoice = {
        ...formData as Invoice,
        id: getNextInvoiceId(),
        totalAmount: total,
        createdAt: new Date().toISOString().split('T')[0],
        dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]
