import React, { useRef } from 'react';
import { CompanyInfo, Tenant, Property, Invoice } from '../types';

interface SystemSettingsProps {
  company: CompanyInfo;
  setCompany: React.Dispatch<React.SetStateAction<CompanyInfo>>;
  onLogout: () => void;
}

export const SystemSettings: React.FC<SystemSettingsProps> = ({ company, setCompany, onLogout }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const downloadBackup = () => {
    const data = {
      company,
      tenants: JSON.parse(localStorage.getItem('tenants') || '[]'),
      properties: JSON.parse(localStorage.getItem('properties') || '[]'),
      invoices: JSON.parse(localStorage.getItem('invoices') || '[]'),
      version: '1.0',
      timestamp: new Date().toISOString()
    };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `QUEENS_CHAMBERS_BACKUP_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (confirm('DANGER: This will delete all current data and replace it with the backup file. This cannot be undone. Proceed?')) {
          if (data.tenants) localStorage.setItem('tenants', JSON.stringify(data.tenants));
          if (data.properties) localStorage.setItem('properties', JSON.stringify(data.properties));
          if (data.invoices) localStorage.setItem('invoices', JSON.stringify(data.invoices));
          if (data.company) localStorage.setItem('company', JSON.stringify(data.company));

          alert('System restored successfully. The portal will now reload to apply changes.');
          window.location.reload();
        }
      } catch (err) {
        alert('Invalid backup file format. Please use a valid .json backup file generated by this software.');
      }
    };
    reader.readAsText(file);
    // Clear input so same file can be selected again
    e.target.value = '';
  };

  const handleResetData = () => {
    const confirmFirst = confirm("CRITICAL WARNING: This will permanently delete all tenants, properties, and invoices. You cannot undo this action. Do you really want to proceed?");
    if (confirmFirst) {
      const confirmSecond = prompt("To confirm deletion of the entire portfolio database, please type 'WIPE' below:");
      if (confirmSecond === 'WIPE') {
        localStorage.removeItem('tenants');
        localStorage.removeItem('properties');
        localStorage.removeItem('invoices');
        localStorage.removeItem('company');
        // We keep 'isLoggedIn' so the user doesn't have to re-login unless they want to, 
        // but often a full wipe should include session. Let's stick to data for now.
        alert('All portfolio data has been cleared. The system will now reset.');
        window.location.reload();
      } else if (confirmSecond !== null) {
        alert('Incorrect confirmation code. Reset cancelled.');
      }
    }
  };

  return (
