  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTenant) {
      setTenants(prev => prev.map(t => t.id === editingTenant.id ? { ...formData as Tenant, id: t.id } : t));
    } else {
      const newTenant: Tenant = {
        ...formData as Tenant,
        id: `T-${Date.now().toString().slice(-4)}`
      };
      setTenants(prev => [...prev, newTenant]);
