import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { Tenants } from './components/Tenants';
import { Invoices } from './components/Invoices';
import { Properties } from './components/Properties';
import { AIAssistant } from './components/AIAssistant';
import { Reports } from './components/Reports';
import { SystemSettings } from './components/SystemSettings';
import { Login } from './components/Login';
import { Tenant, Property, Invoice, CompanyInfo } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('isLoggedIn') === 'true';
  });

  const [tenants, setTenants] = useState<Tenant[]>(() => {
    const saved = localStorage.getItem('tenants');
    return saved ? JSON.parse(saved) : [];
  });

  const [properties, setProperties] = useState<Property[]>(() => {
    const saved = localStorage.getItem('properties');
    return saved ? JSON.parse(saved) : [];
  });

  const [invoices, setInvoices] = useState<Invoice[]>(() => {
    const saved = localStorage.getItem('invoices');
    return saved ? JSON.parse(saved) : [];
  });

  const [company, setCompany] = useState<CompanyInfo>(() => {
    const saved = localStorage.getItem('company');
    return saved ? JSON.parse(saved) : { 
      name: 'QUEENS CHAMBERS', 
      address: '5th Floor, Flat A, 89 Maharshi Karve Road, Marine Lines Mumbai - 400020', 
      email: 'ac.queenschambers@gmail.com' 
    };
  });

  useEffect(() => {
    localStorage.setItem('tenants', JSON.stringify(tenants));
    localStorage.setItem('properties', JSON.stringify(properties));
    localStorage.setItem('invoices', JSON.stringify(invoices));
    localStorage.setItem('company', JSON.stringify(company));
    localStorage.setItem('isLoggedIn', isAuthenticated.toString());
  }, [tenants, properties, invoices, company, isAuthenticated]);

  if (!isAuthenticated) return <Login onLogin={() => setIsAuthenticated(true)} />;

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
      case 'tenants': return <Tenants tenants={tenants} properties={properties} setTenants={setTenants} />;
      case 'invoices': return <Invoices invoices={invoices} tenants={tenants} properties={properties} company={company} setInvoices={setInvoices} />;
      case 'properties': return <Properties properties={properties} setProperties={setProperties} />;
      case 'reports': return <Reports tenants={tenants} properties={properties} invoices={invoices} company={company} />;
      case 'assistant': return <AIAssistant tenants={tenants} invoices={invoices} properties={properties} />;
      case 'settings': return (
        <SystemSettings 
          company={company} 
          setCompany={setCompany} 
          tenants={tenants}
          setTenants={setTenants}
          properties={properties}
          setProperties={setProperties}
          invoices={invoices}
          setInvoices={setInvoices}
          onLogout={() => setIsAuthenticated(false)} 
        />
      );
      default: return <Dashboard tenants={tenants} properties={properties} invoices={invoices} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} onLogout={() => setIsAuthenticated(false)}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useRef } from 'react';
import { CompanyInfo, Tenant, Property, Invoice } from '../types';

interface SystemSettingsProps {
  company: CompanyInfo;
  setCompany: React.Dispatch<React.SetStateAction<CompanyInfo>>;
  tenants: Tenant[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
  invoices: Invoice[];
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
  onLogout: () => void;
}

export const SystemSettings: React.FC<SystemSettingsProps> = ({ 
  company, 
  setCompany, 
  tenants,
  setTenants,
  properties,
  setProperties,
  invoices,
  setInvoices,
  onLogout 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const downloadBackup = () => {
    const data = {
      company,
      tenants,
      properties,
      invoices,
      version: '1.1',
      timestamp: new Date().toISOString()
    };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `QUEENS_CHAMBERS_BACKUP_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // Basic validation that it's a valid backup
        if (!data.tenants && !data.properties && !data.invoices && !data.company) {
          throw new Error("Invalid backup format");
        }

        if (confirm('DANGER: This will delete all current data and replace it with the backup file contents. Proceed?')) {
          // Update state directly. This triggers the persistence useEffect in App.tsx
          if (data.tenants) setTenants(data.tenants);
          if (data.properties) setProperties(data.properties);
          if (data.invoices) setInvoices(data.invoices);
          if (data.company) setCompany(data.company);

          alert('System restored successfully. The dashboard will now update with your restored data.');
        }
      } catch (err) {
        alert('Invalid backup file. Please ensure you are using a .json file exported from this portal.');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleResetData = () => {
    const confirmFirst = confirm("CRITICAL WARNING: This will permanently delete all tenants, properties, and invoices. You cannot undo this action.");
    if (confirmFirst) {
      const confirmSecond = prompt("To confirm deletion of the entire database, please type 'WIPE' below:");
      if (confirmSecond === 'WIPE') {
        setTenants([]);
        setProperties([]);
        setInvoices([]);
        setCompany({ 
          name: 'QUEENS CHAMBERS', 
          address: '5th Floor, Flat A, 89 Maharshi Karve Road, Marine Lines Mumbai - 400020', 
          email: 'ac.queenschambers@gmail.com' 
        });
        alert('All portfolio data has been cleared.');
      } else if (confirmSecond !== null) {
        alert('Incorrect confirmation code. Reset cancelled.');
      }
    }
  };

  return (
    <div className="space-y-8 animate-in">
      <header>
        <h2 className="text-3xl font-black text-slate-900 tracking-tight">System Settings</h2>
        <p className="text-slate-500 font-medium">Portfolio configuration and data safety.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-6">
          <h3 className="text-lg font-black uppercase tracking-widest text-slate-400">Company Information</h3>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Company Name</label>
              <input value={company.name} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, name: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Billing Email</label>
              <input value={company.email} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, email: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Primary Address</label>
              <textarea value={company.address} rows={3} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, address: e.target.value})} />
            </div>
          </div>
        </div>

        <div className="space-y-8">
          <div className="bg-indigo-50 p-8 rounded-[2.5rem] border border-indigo-100 space-y-4">
            <h3 className="text-lg font-black uppercase tracking-widest text-indigo-400">One-Click Backup</h3>
            <p className="text-xs text-indigo-700 font-medium leading-relaxed">
              Download your data to keep a permanent record. It is recommended to save a copy to cloud storage regularly.
            </p>
            <div className="flex flex-col gap-3 pt-2">
              <button 
                onClick={downloadBackup}
                className="w-full bg-white text-indigo-600 border border-indigo-200 p-4 rounded-2xl font-black shadow-sm hover:bg-indigo-100 transition-all flex items-center justify-center gap-2"
              >
                📥 Download Full Backup
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleRestore} 
              />
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-black shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all"
              >
                📤 Restore / Upload Backup
              </button>
            </div>
          </div>

          <div className="bg-rose-50 p-8 rounded-[2.5rem] border border-rose-100 space-y-6">
            <h3 className="text-lg font-black uppercase tracking-widest text-rose-400">Danger Zone</h3>
            <p className="text-sm text-rose-700 font-medium">Perform destructive actions or end your session. <strong>Be careful.</strong></p>
            <div className="space-y-3">
              <button 
                onClick={onLogout}
