  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
  invoices: Invoice[];
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
  onLogout: () => void;
}

export const SystemSettings: React.FC<SystemSettingsProps> = ({ 
  company, 
  setCompany, 
  tenants,
  setTenants,
  properties,
  setProperties,
  invoices,
  setInvoices,
  onLogout 
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const downloadBackup = () => {
    const data = {
      company,
      tenants,
      properties,
      invoices,
      version: '1.2',
      timestamp: new Date().toISOString()
    };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `QUEENS_CHAMBERS_BACKUP_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const fileContent = event.target?.result as string;
        const data = JSON.parse(fileContent);

        // Validation: Ensure it is a valid backup object
        if (!data || typeof data !== 'object') {
          throw new Error("Invalid file format.");
        }

        const hasAnyData = data.tenants || data.properties || data.invoices || data.company;
        if (!hasAnyData) {
          throw new Error("Backup file appears to be empty or invalid.");
        }

        const confirmRestore = confirm(
          "⚠️ RESTORE BACKUP\n\n" +
          "This will replace all current tenants, properties, and invoices with the data from the backup file.\n\n" +
          "Do you want to proceed?"
        );

        if (confirmRestore) {
          // UPDATE REACT STATE DIRECTLY
          // This triggers the useEffect in App.tsx to save to localStorage automatically
          if (data.tenants) setTenants(data.tenants);
          if (data.properties) setProperties(data.properties);
          if (data.invoices) setInvoices(data.invoices);
          if (data.company) setCompany(data.company);

          alert('✅ System Restored Successfully!\n\nYour portfolio data has been updated. You do not need to reload the page.');
