      } catch (err) {
        console.error("Restore Error:", err);
        alert('❌ Restore Failed: The file is either corrupted or not a valid QUEENS CHAMBERS backup JSON.');
      }
    };
    reader.readAsText(file);
    // Reset the input value so the same file can be uploaded again if needed
    e.target.value = '';
  };

  const handleResetData = () => {
    const confirmFirst = confirm("CRITICAL WARNING: This will permanently delete all tenants, properties, and invoices. You cannot undo this action.");
    if (confirmFirst) {
      const confirmSecond = prompt("To confirm deletion of the entire database, please type 'WIPE' below:");
      if (confirmSecond === 'WIPE') {
        // Use state setters to clear data, which will sync to localStorage via App.tsx
        setTenants([]);
        setProperties([]);
        setInvoices([]);
        setCompany({ 
          name: 'QUEENS CHAMBERS', 
          address: '5th Floor, Flat A, 89 Maharshi Karve Road, Marine Lines Mumbai - 400020', 
