import React, { useRef } from 'react';
import { CompanyInfo, Tenant, Property, Invoice, Expense } from '../types';

interface SystemSettingsProps {
  company: CompanyInfo;
  setCompany: React.Dispatch<React.SetStateAction<CompanyInfo>>;
  tenants: Tenant[];
  setTenants: React.Dispatch<React.SetStateAction<Tenant[]>>;
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
  invoices: Invoice[];
  setInvoices: React.Dispatch<React.SetStateAction<Invoice[]>>;
  expenses: Expense[];
  setExpenses: React.Dispatch<React.SetStateAction<Expense[]>>;
  onLogout: () => void;
  setActiveTab: (tab: string) => void;
}

export const SystemSettings: React.FC<SystemSettingsProps> = ({ 
  company, 
  setCompany, 
  tenants,
  setTenants,
  properties,
  setProperties,
  invoices,
  setInvoices,
  expenses,
  setExpenses,
  onLogout,
  setActiveTab
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const downloadBackup = () => {
    const data = {
      company,
      tenants,
      properties,
      invoices,
      expenses,
      version: '1.3',
      timestamp: new Date().toISOString()
    };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `QUEENS_CHAMBERS_BACKUP_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const fileContent = event.target?.result as string;
        const data = JSON.parse(fileContent);

        // Validation and Counts
        const tCount = data.tenants?.length || 0;
        const pCount = data.properties?.length || 0;
        const iCount = data.invoices?.length || 0;
        const eCount = data.expenses?.length || 0;
        const hasCompany = !!data.company;

        if (tCount === 0 && pCount === 0 && iCount === 0 && eCount === 0 && !hasCompany) {
          throw new Error("The selected file does not contain any valid portfolio data.");
        }

        const confirmRestore = confirm(
          "⚠️ SYSTEM RESTORE INITIATED\n\n" +
          "Found in Backup:\n" +
          `• ${tCount} Tenants\n` +
          `• ${pCount} Properties/Units\n` +
          `• ${iCount} Invoices\n` +
          `• ${eCount} Expenses\n` +
          `• Company Profile: ${hasCompany ? 'Yes' : 'No'}\n\n` +
          "DANGER: This will delete ALL current data and replace it with this backup.\n\n" +
          "Do you want to proceed?"
        );

        if (confirmRestore) {
          // Perform state updates
          if (data.tenants) setTenants(data.tenants);
          if (data.properties) setProperties(data.properties);
          if (data.invoices) setInvoices(data.invoices);
          if (data.expenses) setExpenses(data.expenses);
          if (data.company) setCompany(data.company);

          alert('✅ System Restored Successfully!\n\nPortfolio data updated. Navigating to Dashboard...');
          setActiveTab('dashboard');
        }
      } catch (err) {
        console.error("Restore Error:", err);
        alert(`❌ Restore Failed: ${err instanceof Error ? err.message : 'Invalid file format.'}`);
      }
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleResetData = () => {
    const confirmFirst = confirm("CRITICAL WARNING: This will permanently delete all tenants, properties, invoices, and expenses. You cannot undo this action.");
    if (confirmFirst) {
      const confirmSecond = prompt("To confirm deletion of the entire database, please type 'WIPE' below:");
      if (confirmSecond === 'WIPE') {
        setTenants([]);
        setProperties([]);
        setInvoices([]);
        setExpenses([]);
        setCompany({ 
          name: 'QUEENS CHAMBERS', 
          address: '5th Floor, Flat A, 89 Maharshi Karve Road, Marine Lines Mumbai - 400020', 
          email: 'ac.queenschambers@gmail.com' 
        });
        alert('All portfolio data has been cleared.');
        setActiveTab('dashboard');
      } else if (confirmSecond !== null) {
        alert('Incorrect confirmation code. Reset cancelled.');
      }
    }
  };

  return (
    <div className="space-y-8 animate-in">
      <header>
        <h2 className="text-3xl font-black text-slate-900 tracking-tight">System Settings</h2>
        <p className="text-slate-500 font-medium">Portfolio configuration and data safety.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-6">
          <h3 className="text-lg font-black uppercase tracking-widest text-slate-400">Company Information</h3>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Company Name</label>
              <input value={company.name} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, name: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Billing Email</label>
              <input value={company.email} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, email: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Primary Address</label>
              <textarea value={company.address} rows={3} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, address: e.target.value})} />
            </div>
          </div>
        </div>

        <div className="space-y-8">
          <div className="bg-indigo-50 p-8 rounded-[2.5rem] border border-indigo-100 space-y-4">
            <h3 className="text-lg font-black uppercase tracking-widest text-indigo-400">Data Management</h3>
            <p className="text-xs text-indigo-700 font-medium leading-relaxed">
              Maintain full ownership of your data. Exports include all tenants, properties, invoices, and expense logs.
            </p>
            <div className="flex flex-col gap-3 pt-2">
              <button 
                onClick={downloadBackup}
                className="w-full bg-white text-indigo-600 border border-indigo-200 p-4 rounded-2xl font-black shadow-sm hover:bg-indigo-100 transition-all flex items-center justify-center gap-2"
              >
                📥 Download Full Backup
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleRestore} 
              />
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-black shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all"
              >
                📤 Restore / Upload Backup
              </button>
            </div>
          </div>

          <div className="bg-rose-50 p-8 rounded-[2.5rem] border border-rose-100 space-y-6">
            <h3 className="text-lg font-black uppercase tracking-widest text-rose-400">Danger Zone</h3>
            <p className="text-sm text-rose-700 font-medium">Perform destructive actions or end your session. <strong>Be careful.</strong></p>
            <div className="space-y-3">
              <button 
                onClick={onLogout}
                className="w-full bg-white text-rose-600 border border-rose-200 p-4 rounded-2xl font-black shadow-sm hover:bg-rose-100 transition-all"
              >
                Log Out Securely
              </button>
              <button 
                onClick={handleResetData}
                className="w-full bg-rose-600 text-white p-4 rounded-2xl font-black shadow-xl shadow-rose-200 hover:bg-rose-700 transition-all"
              >
                Wipe All Portfolio Data
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

