  const [reportType, setReportType] = useState<ReportType>('tenants');

  const printReport = () => {
    window.print();
  };

  const exportToCSV = () => {
    let csvContent = "";
    let filename = `report_${reportType}_${new Date().toISOString().split('T')[0]}.csv`;

    if (reportType === 'tenants') {
      csvContent = "Name,Address,Property,Email,Phone\n";
      tenants.forEach(t => {
        const prop = properties.find(p => p.id === t.propertyId);
        csvContent += `"${t.name}","${t.address || ''}","${prop ? `${prop.type} ${prop.name}` : ''}","${t.email}","${t.phone}"\n`;
      });
    } else if (reportType === 'properties') {
      csvContent = "Name,Type,Status\n";
      properties.forEach(p => {
        const status = tenants.some(t => t.propertyId === p.id) ? "Occupied" : "Vacant";
        csvContent += `"${p.name}","${p.type}","${status}"\n`;
      });
    } else if (reportType === 'invoices') {
      csvContent = "ID,Date,Receipt Date,Tenant,Amount,Period,Status\n";
      invoices.forEach(i => {
        const tName = tenants.find(t => t.id === i.tenantId)?.name || 'Unknown';
        csvContent += `"${i.id}","${formatDate(i.createdAt)}","${formatDate(i.dateOfReceipt)}","${tName}","${i.totalAmount}","${i.billingPeriod}","${i.status}"\n`;
      });
    }

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportToPDF = () => {
    const doc = new jsPDF();
    const title = `${reportType.toUpperCase()} REPORT`;
    const date = formatDate(new Date().toISOString().split('T')[0]);

    doc.setFontSize(20);
    doc.setTextColor(79, 70, 229);
    doc.text(company.name, 14, 20);
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139);
    doc.text(title, 14, 28);
    doc.text(`Generated: ${date}`, 14, 33);

    let head: string[][] = [];
    let body: string[][] = [];

    if (reportType === 'tenants') {
      head = [['Name', 'Address', 'Property', 'Contact']];
      body = tenants.map(t => {
        const prop = properties.find(p => p.id === t.propertyId);
        return [
          t.name, 
          t.address || 'N/A', 
          prop ? `${prop.type} ${prop.name}` : 'N/A', 
          `${t.email}\n${t.phone}`
        ];
      });
    } else if (reportType === 'properties') {
      head = [['Name', 'Type', 'Status']];
      body = properties.map(p => {
        const status = tenants.some(t => t.propertyId === p.id) ? "Occupied" : "Vacant";
        return [p.name, p.type, status];
      });
    } else if (reportType === 'invoices') {
      head = [['ID', 'Date', 'Receipt Date', 'Tenant', 'Amount', 'Status']];
      body = invoices.map(i => [
        i.id,
        formatDate(i.createdAt),
        formatDate(i.dateOfReceipt),
        tenants.find(t => t.id === i.tenantId)?.name || 'Unknown',
        `Rs. ${i.totalAmount.toLocaleString()}`,
        i.status
      ]);
    }

    autoTable(doc, {
      startY: 40,
      head: head,
      body: body,
      theme: 'striped',
      headStyles: { fillColor: [79, 70, 229] },
      styles: { fontSize: 9 }
    });

    doc.save(`${reportType}_report_${date}.pdf`);
  };

  const renderReportTable = () => {
    switch (reportType) {
      case 'tenants':
        return (
          <table className="w-full text-left border-collapse border border-slate-200">
            <thead className="bg-slate-100">
              <tr>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Name</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Address</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase whitespace-nowrap">Property</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Contact</th>
              </tr>
            </thead>
            <tbody>
              {tenants.map(t => {
                const prop = properties.find(p => p.id === t.propertyId);
                return (
                  <tr key={t.id}>
                    <td className="p-3 border border-slate-200 text-sm font-bold">{t.name}</td>
                    <td className="p-3 border border-slate-200 text-sm">{t.address || 'N/A'}</td>
                    <td className="p-3 border border-slate-200 text-sm whitespace-nowrap">{prop ? `${prop.type} ${prop.name}` : 'N/A'}</td>
                    <td className="p-3 border border-slate-200 text-sm">{t.email}<br/><span className="text-xs text-slate-400">{t.phone}</span></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        );
      case 'properties':
        return (
          <table className="w-full text-left border-collapse border border-slate-200">
            <thead className="bg-slate-100">
              <tr>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Name</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Type</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase text-center">Status</th>
              </tr>
            </thead>
            <tbody>
              {properties.map(p => (
                <tr key={p.id}>
                  <td className="p-3 border border-slate-200 text-sm font-bold">{p.name}</td>
                  <td className="p-3 border border-slate-200 text-sm">{p.type}</td>
                  <td className="p-3 border border-slate-200 text-sm text-center">
                    {tenants.some(t => t.propertyId === p.id) ? (
                      <span className="text-emerald-600 font-bold uppercase text-[10px]">Occupied</span>
                    ) : (
                      <span className="text-amber-600 font-bold uppercase text-[10px]">Vacant</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        );
      case 'invoices':
        return (
          <table className="w-full text-left border-collapse border border-slate-200">
            <thead className="bg-slate-100">
              <tr>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">ID</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Date</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Receipt Date</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Tenant</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase text-right">Amount</th>
                <th className="p-3 border border-slate-200 text-xs font-bold uppercase">Status</th>
              </tr>
            </thead>
            <tbody>
              {invoices.map(i => (
                <tr key={i.id}>
                  <td className="p-3 border border-slate-200 text-xs font-mono">{i.id}</td>
                  <td className="p-3 border border-slate-200 text-sm">{formatDate(i.createdAt)}</td>
                  <td className="p-3 border border-slate-200 text-sm font-bold text-indigo-600">{formatDate(i.dateOfReceipt)}</td>
                  <td className="p-3 border border-slate-200 text-sm">{tenants.find(t => t.id === i.tenantId)?.name || 'Unknown'}</td>
                  <td className="p-3 border border-slate-200 text-sm font-bold text-right">₹{i.totalAmount.toLocaleString()}</td>
                  <td className="p-3 border border-slate-200 text-sm">
                    <span className={`px-2 py-0.5 rounded text-[9px] font-black uppercase ${
                      i.status === 'Paid' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-500'
                    }`}>
                      {i.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        );
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <style>{`
        @media print {
          body * { visibility: hidden; }
          #printable-report, #printable-report * { visibility: visible; }
          #printable-report { position: absolute; left: 0; top: 0; width: 100%; }
          .no-print { display: none !important; }
        }
      `}</style>

      <header className="no-print flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Reports</h2>
          <p className="text-slate-500 mt-1">Generate management reports for your portfolio.</p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <button 
            onClick={exportToCSV}
            className="bg-white text-slate-700 border border-slate-200 px-5 py-2.5 rounded-xl font-bold hover:bg-slate-50 transition-all flex items-center gap-2"
          >
            📊 Excel (CSV)
          </button>
          <button 
            onClick={exportToPDF}
            className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2"
          >
            📄 PDF Export
          </button>
          <button 
            onClick={printReport}
            className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-slate-800 transition-all flex items-center gap-2"
          >
            🖨️ Print
          </button>
        </div>
      </header>

      <div className="no-print flex gap-2 p-1 bg-slate-100 rounded-xl border border-slate-200 w-fit">
        {(['tenants', 'properties', 'invoices'] as const).map((type) => (
          <button
            key={type}
            onClick={() => setReportType(type)}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all capitalize ${
              reportType === type ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            {type}
          </button>
        ))}
      </div>

      <div id="printable-report" className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
        <div className="mb-8 flex justify-between items-start">
          <div>
            <h1 className="text-2xl font-bold text-slate-900">{company.name}</h1>
            <p className="text-sm text-slate-500">5th Floor, Flat A, 89 Maharshi Karve Road,</p>
            <p className="text-sm text-slate-500">Marine Lines, Mumbai - 400020</p>
            <p className="text-sm text-slate-500">{company.email}</p>
          </div>
          <div className="text-right">
            <h2 className="text-xl font-bold text-indigo-600 uppercase tracking-widest">{reportType} Report</h2>
            <p className="text-sm text-slate-500">Generated: {formatDate(new Date().toISOString().split('T')[0])}</p>
          </div>
        </div>

        {renderReportTable()}

        <div className="mt-8 text-xs text-slate-400 border-t border-slate-100 pt-4">
          Report generated by QUEENS CHAMBERS Management Portal.
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { Tenants } from './components/Tenants';
import { Invoices } from './components/Invoices';
import { Properties } from './components/Properties';
import { Expenses } from './components/Expenses';
import { AIAssistant } from './components/AIAssistant';
import { Reports } from './components/Reports';
import { SystemSettings } from './components/SystemSettings';
import { Login } from './components/Login';
import { Tenant, Property, Invoice, CompanyInfo, Expense } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('isLoggedIn') === 'true';
  });

  const [tenants, setTenants] = useState<Tenant[]>(() => {
    const saved = localStorage.getItem('tenants');
    return saved ? JSON.parse(saved) : [];
  });

  const [properties, setProperties] = useState<Property[]>(() => {
    const saved = localStorage.getItem('properties');
    return saved ? JSON.parse(saved) : [];
  });

  const [invoices, setInvoices] = useState<Invoice[]>(() => {
    const saved = localStorage.getItem('invoices');
    return saved ? JSON.parse(saved) : [];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [company, setCompany] = useState<CompanyInfo>(() => {
    const saved = localStorage.getItem('company');
    return saved ? JSON.parse(saved) : { 
      name: 'QUEENS CHAMBERS', 
      address: '5th Floor, Flat A, 89 Maharshi Karve Road, Marine Lines Mumbai - 400020', 
      email: 'ac.queenschambers@gmail.com' 
    };
  });

  useEffect(() => {
    localStorage.setItem('tenants', JSON.stringify(tenants));
    localStorage.setItem('properties', JSON.stringify(properties));
    localStorage.setItem('invoices', JSON.stringify(invoices));
    localStorage.setItem('expenses', JSON.stringify(expenses));
    localStorage.setItem('company', JSON.stringify(company));
    localStorage.setItem('isLoggedIn', isAuthenticated.toString());
  }, [tenants, properties, invoices, expenses, company, isAuthenticated]);

  if (!isAuthenticated) return <Login onLogin={() => setIsAuthenticated(true)} />;

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard tenants={tenants} properties={properties} invoices={invoices} expenses={expenses} />;
      case 'tenants': return <Tenants tenants={tenants} properties={properties} setTenants={setTenants} />;
      case 'invoices': return <Invoices invoices={invoices} tenants={tenants} properties={properties} company={company} setInvoices={setInvoices} />;
      case 'properties': return <Properties properties={properties} setProperties={setProperties} tenants={tenants} />;
      case 'expenses': return <Expenses expenses={expenses} properties={properties} setExpenses={setExpenses} />;
      case 'reports': return <Reports tenants={tenants} properties={properties} invoices={invoices} company={company} />;
      case 'assistant': return <AIAssistant tenants={tenants} invoices={invoices} properties={properties} />;
      case 'settings': return (
        <SystemSettings 
          company={company} 
          setCompany={setCompany} 
          tenants={tenants}
          setTenants={setTenants}
          properties={properties}
          setProperties={setProperties}
          invoices={invoices}
          setInvoices={setInvoices}
          expenses={expenses}
          setExpenses={setExpenses}
          onLogout={() => setIsAuthenticated(false)} 
          setActiveTab={setActiveTab}
        />
      );
      default: return <Dashboard tenants={tenants} properties={properties} invoices={invoices} expenses={expenses} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} onLogout={() => setIsAuthenticated(false)}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Property, PropertyType, Tenant } from '../types';

interface PropertiesProps {
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
  tenants: Tenant[];
}

export const Properties: React.FC<PropertiesProps> = ({ properties, setProperties, tenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [formData, setFormData] = useState<Partial<Property>>({ name: '', type: 'Flat' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleEditClick = (prop: Property) => {
    setEditingProperty(prop);
    setFormData(prop);
    setIsModalOpen(true);
  };

  const handleDelete = (propertyId: string) => {
    // Check if any tenant is assigned to this property
    const isOccupied = tenants.some(t => t.propertyId === propertyId);

    if (isOccupied) {
      alert("⚠️ CANNOT DELETE UNIT\n\nThis unit is currently assigned to a tenant. Please unassign or remove the tenant before deleting this property.");
      return;
    }

    if (confirm('Are you sure you want to delete this property? This action cannot be undone.')) {
      setProperties(prev => prev.filter(p => p.id !== propertyId));
    }
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingProperty(null);
    setFormData({ name: '', type: 'Flat' });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProperty) {
      setProperties(prev => prev.map(p => p.id === editingProperty.id ? { ...formData as Property, id: p.id } : p));
    } else {
      const newProp: Property = {
        ...formData as Property,
        id: `P-${Date.now().toString().slice(-4)}`
      };
      setProperties(prev => [...prev, newProp]);
    }
    closeModal();
  };

  const parseCSV = (text: string) => {
    const lines = text.split('\n').filter(line => line.trim() !== '');
    if (lines.length < 2) return [];

    const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
    return lines.slice(1).map(line => {
      const values = line.split(',').map(v => v.trim().replace(/^"|"$/g, ''));
      const obj: any = {};
      headers.forEach((header, i) => {
        obj[header] = values[i];
      });
      return obj;
    });
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const csvText = event.target?.result as string;
        const rows = parseCSV(csvText);

        const mappedData: Property[] = rows.map((row, index) => ({
          id: `P-IMP-${Date.now()}-${index}`,
          name: row.name || 'Unnamed Unit',
          type: (row.type || 'Flat') as PropertyType,
          address: row.address || ''
        }));

        if (mappedData.length > 0) {
          setProperties(prev => [...prev, ...mappedData]);
          alert(`Successfully imported ${mappedData.length} properties.`);
        }
      } catch (err) {
        alert("Error parsing file. Please ensure it is a valid CSV/Excel export with headers: Name, Type");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  return (
    <div className="space-y-6 animate-in">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-900">Properties</h2>
          <p className="text-sm text-slate-500">Asset portfolio and unit inventory.</p>
        </div>
        <div className="flex gap-3">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImport} 
            accept=".csv" 
            className="hidden" 
          />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="bg-white border border-slate-200 text-slate-600 px-6 py-3 rounded-2xl font-bold hover:bg-slate-50 transition-all flex items-center gap-2"
          >
            <span>📊</span> Import CSV
          </button>
          <button onClick={() => setIsModalOpen(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition-all">
            + Add Unit
          </button>
        </div>
      </header>

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400">ID</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400">Unit Name</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400">Category</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400 text-center">Occupancy</th>
              <th className="px-8 py-4 text-[10px] font-black uppercase text-slate-400 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {properties.map(p => {
              const isOccupied = tenants.some(t => t.propertyId === p.id);
              return (
                <tr key={p.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-8 py-5 text-xs font-mono text-slate-400">{p.id}</td>
                  <td className="px-8 py-5 font-bold text-slate-900">{p.name}</td>
                  <td className="px-8 py-5">
                    <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${
                      p.type === 'Flat' ? 'bg-indigo-50 text-indigo-600' : 
                      p.type === 'Garage' ? 'bg-amber-50 text-amber-600' : 'bg-emerald-50 text-emerald-600'
                    }`}>
                      {p.type}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-center">
                    {isOccupied ? (
                      <span className="text-[10px] font-black text-indigo-500 bg-indigo-50 px-2 py-1 rounded uppercase tracking-widest">Occupied</span>
                    ) : (
                      <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Vacant</span>
                    )}
                  </td>
                  <td className="px-8 py-5 text-right space-x-2">
                    <button 
                      onClick={() => handleEditClick(p)}
                      className="bg-indigo-50 text-indigo-600 hover:bg-indigo-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all"
                    >
                      Edit
                    </button>
                    <button 
                      onClick={() => handleDelete(p.id)} 
                      className="bg-rose-50 text-rose-400 hover:bg-rose-600 hover:text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {properties.length === 0 && (
          <div className="py-20 text-center">
            <p className="text-4xl mb-4">🏠</p>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">No properties registered</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl animate-in">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-black">{editingProperty ? 'Edit Unit' : 'Add New Unit'}</h3>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-900 font-bold">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div>
                <label className="text-xs font-black uppercase text-slate-400 block mb-2">Unit Identifier</label>
                <input value={formData.name} placeholder="e.g. Flat 101" required className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
              </div>
              <div>
                <label className="text-xs font-black uppercase text-slate-400 block mb-2">Category</label>
                <select value={formData.type} required className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setFormData({...formData, type: e.target.value as PropertyType})}>
                  <option value="Flat">Flat</option>
                  <option value="Garage">Garage</option>
                  <option value="Godown">Godown</option>
                </select>
              </div>
              <button type="submit" className="w-full bg-indigo-600 text-white p-4 rounded-2xl font-black shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all">
                {editingProperty ? 'Save Changes' : 'Register Unit'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Property, PropertyType, Tenant } from '../types';

interface PropertiesProps {
  properties: Property[];
  setProperties: React.Dispatch<React.SetStateAction<Property[]>>;
  tenants: Tenant[];
}

export const Properties: React.FC<PropertiesProps> = ({ properties, setProperties, tenants }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [formData, setFormData] = useState<Partial<Property>>({ name: '', type: 'Flat' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleEditClick = (prop: Property) => {
    setEditingProperty(prop);
    setFormData(prop);
    setIsModalOpen(true);
  };

  const handleDelete = (propertyId: string) => {
    // Robust check for occupancy - string match after trimming
    const isOccupied = tenants.some(t => t.propertyId?.toString().trim() === propertyId?.toString().trim());

    if (isOccupied) {
      alert("⚠️ CANNOT DELETE UNIT\n\nThis unit is currently assigned to a tenant. Please unassign or remove the tenant before deleting this property.");
      return;
    }

    const confirmMessage = `Are you sure you want to delete property "${properties.find(p => p.id === propertyId)?.name}"?`;
    if (window.confirm(confirmMessage)) {
      setProperties(prev => prev.filter(p => p.id !== propertyId));
    }
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingProperty(null);
    setFormData({ name: '', type: 'Flat' });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProperty) {
      setProperties(prev => prev.map(p => p.id === editingProperty.id ? { ...formData as Property, id: p.id } : p));
    } else {
      const newProp: Property = {
        ...formData as Property,
        id: `P-${Date.now().toString().slice(-4)}-${Math.floor(Math.random() * 1000)}`
      };
      setProperties(prev => [...prev, newProp]);
    }
    closeModal();
  };

  const parseCSV = (text: string) => {
    const lines = text.split('\n').filter(line => line.trim() !== '');
    if (lines.length < 2) return [];

    const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
    return lines.slice(1).map(line => {
      const values = line.split(',').map(v => v.trim().replace(/^"|"$/g, ''));
      const obj: any = {};
      headers.forEach((header, i) => {
        obj[header] = values[i];
      });
      return obj;
    });
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const csvText = event.target?.result as string;
        const rows = parseCSV(csvText);

        const mappedData: Property[] = rows.map((row, index) => ({
          id: `P-IMP-${Date.now()}-${index}`,
          name: row.name || 'Unnamed Unit',
          type: (row.type || 'Flat') as PropertyType,
          address: row.address || ''
        }));

        if (mappedData.length > 0) {
          setProperties(prev => [...prev, ...mappedData]);
          alert(`Successfully imported ${mappedData.length} properties.`);
        }
      } catch (err) {
        alert("Error parsing file. Please ensure it is a valid CSV/Excel export with headers: Name, Type");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  return (
    <div className="space-y-6 animate-in">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-900">Properties</h2>
          <p className="text-sm text-slate-500">Asset portfolio and unit inventory.</p>
        </div>
        <div className="flex gap-3">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImport} 
            accept=".csv" 
            className="hidden" 
          />
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="bg-white border border-slate-200 text-slate-600 px-6 py-3 rounded-2xl font-bold hover:bg-slate-50 transition-all flex items-center gap-2 cursor-pointer"
          >
            <span>📊</span> Import CSV
          </button>
          <button 
            type="button"
