    // 2. Tenants
    csv += "SECTION: TENANTS\n";
    csv += "ID,Name,Email,Phone,Address,PropertyID,Status\n";
    tenants.forEach(t => {
      csv += `"${t.id}","${t.name}","${t.email}","${t.phone}","${t.address}","${t.propertyId}","${t.status}"\n`;
    });
    csv += "\n";

    // 3. Invoices
    csv += "SECTION: INVOICES\n";
    csv += "ID,TenantID,TotalAmount,CreatedAt,DateOfReceipt,Status,BillingPeriod,Notes\n";
    invoices.forEach(i => {
      csv += `"${i.id}","${i.tenantId}","${i.totalAmount}","${i.createdAt}","${i.dateOfReceipt}","${i.status}","${i.billingPeriod}","${i.notes || ''}"\n`;
    });
    csv += "\n";

    // 4. Expenses
    csv += "SECTION: EXPENSES\n";
    csv += "ID,PropertyID,Amount,Category,Date,Description\n";
    expenses.forEach(e => {
      csv += `"${e.id}","${e.propertyId}","${e.amount}","${e.category}","${e.date}","${e.description}"\n`;
    });

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Portfolio_Excel_Master_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleExcelRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split(/\r?\n/);

        const restoredData: any = {
          properties: [],
          tenants: [],
          invoices: [],
          expenses: [],
          company: { ...company }
        };

        let currentSection = '';

        const parseCSVLine = (line: string) => {
          const result = [];
          let current = '';
          let inQuotes = false;
          for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') inQuotes = !inQuotes;
            else if (char === ',' && !inQuotes) {
              result.push(current.trim());
              current = '';
            } else current += char;
          }
          result.push(current.trim());
          return result;
        };

        lines.forEach(line => {
          if (!line.trim()) return;
          if (line.startsWith("SECTION: PROPERTIES")) { currentSection = 'properties'; return; }
          if (line.startsWith("SECTION: TENANTS")) { currentSection = 'tenants'; return; }
          if (line.startsWith("SECTION: INVOICES")) { currentSection = 'invoices'; return; }
          if (line.startsWith("SECTION: EXPENSES")) { currentSection = 'expenses'; return; }

          if (line.startsWith("ID,") || line.startsWith("Export Date") || line.startsWith("QUEENS")) return;

          const values = parseCSVLine(line);

          if (currentSection === 'properties') {
            restoredData.properties.push({ id: values[0], name: values[1], type: values[2] as PropertyType, address: values[3] });
