  tenants,
  properties,
  invoices,
  expenses,
  onLogout,
  setActiveTab,
  onRestore
}) => {
  const csvInputRef = useRef<HTMLInputElement>(null);
  const jsonInputRef = useRef<HTMLInputElement>(null);

  // --- EXCEL (CSV) LOGIC ---

  const exportToExcel = () => {
    let csv = `QUEENS CHAMBERS MASTER PORTFOLIO EXPORT\n`;
    csv += `Export Date: ${new Date().toLocaleString()}\n\n`;

    // 1. Properties
    csv += "SECTION: PROPERTIES\n";
    csv += "ID,Name,Type,Address\n";
    properties.forEach(p => {
      csv += `"${p.id}","${p.name}","${p.type}","${(p.address || '').replace(/"/g, '""')}"\n`;
