      csv += `"${e.id}","${e.propertyId}","${e.amount}","${e.category}","${e.date}","${e.description.replace(/"/g, '""')}"\n`;
    });

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Portfolio_Excel_Master_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleExcelRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split(/\r?\n/);

        const restoredData: any = {
          properties: [],
          tenants: [],
          invoices: [],
          expenses: [],
          company: { ...company }
        };

        let currentSection = '';

        const parseCSVLine = (line: string) => {
          const result = [];
          let current = '';
          let inQuotes = false;
          for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') {
              // Handle escaped quotes ""
              if (inQuotes && line[i+1] === '"') {
                current += '"';
                i++;
              } else {
                inQuotes = !inQuotes;
              }
            }
            else if (char === ',' && !inQuotes) {
              result.push(current.trim());
              current = '';
            } else current += char;
          }
          result.push(current.trim());
          return result;
        };

        lines.forEach(line => {
          const trimmed = line.trim();
          if (!trimmed) return;
          if (trimmed.startsWith("SECTION: PROPERTIES")) { currentSection = 'properties'; return; }
          if (trimmed.startsWith("SECTION: TENANTS")) { currentSection = 'tenants'; return; }
          if (trimmed.startsWith("SECTION: INVOICES")) { currentSection = 'invoices'; return; }
          if (trimmed.startsWith("SECTION: EXPENSES")) { currentSection = 'expenses'; return; }

          if (trimmed.startsWith("ID,") || trimmed.startsWith("Export Date") || trimmed.startsWith("QUEENS")) return;

          const values = parseCSVLine(line);
          if (values.length < 2) return;

          if (currentSection === 'properties') {
            restoredData.properties.push({ id: values[0], name: values[1], type: values[2] as PropertyType, address: values[3] });
          } else if (currentSection === 'tenants') {
            restoredData.tenants.push({ id: values[0], name: values[1], email: values[2], phone: values[3], address: values[4], propertyId: values[5], status: values[6] as any });
