            restoredData.invoices.push({ id: values[0], tenantId: values[1], totalAmount: Number(values[2]), createdAt: values[3], dateOfReceipt: values[4], status: values[5] as InvoiceStatus, billingPeriod: values[6], notes: values[7], items: [] });
          } else if (currentSection === 'expenses') {
            restoredData.expenses.push({ id: values[0], propertyId: values[1], amount: Number(values[2]), category: values[3], date: values[4], description: values[5] });
          }
        });

        const totalRecords = restoredData.properties.length + restoredData.tenants.length + restoredData.invoices.length + restoredData.expenses.length;

        if (totalRecords === 0) {
          alert("❌ Error: The selected CSV file doesn't seem to contain valid portfolio data in the required format.");
          return;
        }

        const confirmRestore = confirm(
          `⚠️ CSV/EXCEL DATA RESTORE\n\n` +
          `Found in File:\n` +
          `• ${restoredData.properties.length} Properties\n` +
          `• ${restoredData.tenants.length} Tenants\n` +
          `• ${restoredData.invoices.length} Invoices\n` +
          `• ${restoredData.expenses.length} Expenses\n\n` +
          `WARNING: This will replace your current database and restart the application.\n\nProceed?`
        );

        if (confirmRestore) onRestore(restoredData);

      } catch (err) {
        console.error(err);
        alert("❌ Excel Restore Failed: Please ensure you are using the exact file format from the export.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleResetData = () => {
    const confirmFirst = confirm("🚨 CRITICAL ACTION: This will PERMANENTLY WIPE all your tenants, properties, invoices, and expenses. You will start with a blank software registry.");
    if (confirmFirst) {
      const confirmFinal = prompt("To confirm the total reset, please type 'WIPE' below (Case sensitive):");
      if (confirmFinal === 'WIPE') {
        onRestore({
          tenants: [],
          properties: [],
          invoices: [],
          expenses: [],
          company: { 
            name: 'QUEENS CHAMBERS', 
            address: '5th Floor, Flat A, 89 Maharshi Karve Road, Marine Lines Mumbai - 400020', 
            email: 'ac.queenschambers@gmail.com' 
          }
        });
      } else if (confirmFinal !== null) {
        alert("Reset cancelled. Confirmation phrase did not match.");
      }
    }
  };

  const downloadJSONBackup = () => {
    const data = {
      company,
      tenants,
      properties,
      invoices,
      expenses,
      version: '1.7',
      timestamp: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SYSTEM_BACKUP_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleJSONRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (confirm("Replace all system data from JSON backup? The app will reload.")) {
          onRestore(data);
        }
      } catch (err) {
        alert("Invalid JSON backup file format.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  return (
    <div className="space-y-8 animate-in">
      <header>
        <h2 className="text-3xl font-black text-slate-900 tracking-tight">System Settings</h2>
        <p className="text-slate-500 font-medium">Software configuration and portfolio data management.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-6">
          <h3 className="text-lg font-black uppercase tracking-widest text-slate-400">Company Information</h3>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Company Name</label>
              <input value={company.name} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, name: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Billing Email</label>
              <input value={company.email} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, email: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Primary Address</label>
              <textarea value={company.address} rows={3} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500 transition-all" onChange={e => setCompany({...company, address: e.target.value})} />
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-emerald-50 p-8 rounded-[2.5rem] border border-emerald-100 space-y-4">
            <h3 className="text-lg font-black uppercase tracking-widest text-emerald-500">Excel Data Sync</h3>
            <p className="text-xs text-emerald-700 font-medium leading-relaxed">
              Use Excel (CSV) for easy editing and restoration. Download the master record to open in Excel, or re-import a previously exported CSV.
            </p>
            <div className="grid grid-cols-1 gap-3">
              <button 
                onClick={exportToExcel}
                className="w-full bg-white text-emerald-600 border border-emerald-200 p-4 rounded-2xl font-black shadow-sm hover:bg-emerald-100 transition-all flex items-center justify-center gap-2 cursor-pointer active:scale-95"
              >
                📊 Download Master Excel (CSV)
              </button>
              <input type="file" ref={csvInputRef} className="hidden" accept=".csv" onChange={handleExcelRestore} />
              <button 
                onClick={() => csvInputRef.current?.click()}
                className="w-full bg-emerald-600 text-white p-4 rounded-2xl font-black shadow-lg shadow-emerald-200 hover:bg-emerald-700 transition-all cursor-pointer active:scale-95 flex items-center justify-center gap-2"
              >
                📥 Restore from Excel (CSV)
              </button>
            </div>
          </div>

          <div className="bg-indigo-50 p-6 rounded-[2rem] border border-indigo-100 space-y-3">
            <h3 className="text-sm font-black uppercase tracking-widest text-indigo-400">Technical Backup</h3>
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={downloadJSONBackup}
                className="bg-white text-indigo-600 border border-indigo-200 p-3 rounded-xl font-black text-[10px] uppercase hover:bg-indigo-100 transition-all cursor-pointer"
              >
                Backup (JSON)
              </button>
              <input type="file" ref={jsonInputRef} className="hidden" accept=".json" onChange={handleJSONRestore} />
              <button 
                onClick={() => jsonInputRef.current?.click()}
                className="bg-indigo-600 text-white p-3 rounded-xl font-black text-[10px] uppercase shadow-lg hover:bg-indigo-700 transition-all cursor-pointer"
              >
                Restore (JSON)
              </button>
            </div>
          </div>

          <div className="bg-rose-50 p-8 rounded-[2.5rem] border border-rose-100 space-y-4">
            <h3 className="text-lg font-black uppercase tracking-widest text-rose-500">Danger Zone</h3>
            <div className="grid grid-cols-1 gap-3">
              <button 
                onClick={handleResetData}
                className="w-full bg-rose-600 text-white p-4 rounded-2xl font-black shadow-xl shadow-rose-200 hover:bg-rose-700 transition-all cursor-pointer active:scale-95 flex items-center justify-center gap-2"
              >
                ⚠️ Reset Software Data
              </button>
              <button 
                onClick={onLogout}
                className="w-full bg-white text-rose-600 border border-rose-200 p-4 rounded-2xl font-black shadow-sm hover:bg-rose-100 transition-all cursor-pointer active:scale-95 flex items-center justify-center gap-2"
              >
                🚪 Sign Out
              </button>
            </div>
          </div>
