import React, { useRef, useState, useEffect } from 'react';
import { CompanyInfo, Tenant, Property, Invoice, Expense, PropertyType, InvoiceStatus } from '../types';

interface SystemSettingsProps {
  company: CompanyInfo;
  setCompany: React.Dispatch<React.SetStateAction<CompanyInfo>>;
  tenants: Tenant[];
  properties: Property[];
  invoices: Invoice[];
  expenses: Expense[];
  onLogout: () => void;
  setActiveTab: (tab: string) => void;
  onRestore: (data: any) => void;
}

export const SystemSettings: React.FC<SystemSettingsProps> = ({ 
  company, 
  setCompany, 
  tenants,
  properties,
  invoices,
  expenses,
  onLogout,
  setActiveTab,
  onRestore
}) => {
  const csvInputRef = useRef<HTMLInputElement>(null);
  const jsonInputRef = useRef<HTMLInputElement>(null);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    window.addEventListener('beforeinstallprompt', (e) => {
      e.preventDefault();
      setInstallPrompt(e);
    });
  }, []);

  const handleInstallClick = () => {
    if (installPrompt) {
      installPrompt.prompt();
      installPrompt.userChoice.then((choiceResult: any) => {
        if (choiceResult.outcome === 'accepted') {
          setInstallPrompt(null);
        }
      });
    } else {
      alert("To install this as an offline PC app, click the 'Install' icon in your browser's address bar (top right).");
    }
  };

  const exportToExcel = () => {
    let csv = `QUEENS CHAMBERS MASTER PORTFOLIO EXPORT\n`;
    csv += `Export Date: ${new Date().toLocaleString()}\n\n`;

    csv += "SECTION: PROPERTIES\n";
    csv += "ID,Name,Type,Address\n";
    properties.forEach(p => {
      csv += `"${p.id}","${p.name}","${p.type}","${(p.address || '').replace(/"/g, '""')}"\n`;
    });
    csv += "\n";

    csv += "SECTION: TENANTS\n";
    csv += "ID,Name,Email,Phone,Address,PropertyID,Status\n";
    tenants.forEach(t => {
      csv += `"${t.id}","${t.name}","${t.email}","${t.phone}","${t.address.replace(/"/g, '""')}","${t.propertyId}","${t.status}"\n`;
    });
    csv += "\n";

    csv += "SECTION: INVOICES\n";
    csv += "ID,TenantID,TotalAmount,CreatedAt,DateOfReceipt,Status,BillingPeriod,Notes\n";
    invoices.forEach(i => {
      csv += `"${i.id}","${i.tenantId}","${i.totalAmount}","${i.createdAt}","${i.dateOfReceipt}","${i.status}","${i.billingPeriod}","${(i.notes || '').replace(/"/g, '""')}"\n`;
    });
    csv += "\n";

    csv += "SECTION: EXPENSES\n";
    csv += "ID,PropertyID,Amount,Category,Date,Description\n";
    expenses.forEach(e => {
      csv += `"${e.id}","${e.propertyId}","${e.amount}","${e.category}","${e.date}","${e.description.replace(/"/g, '""')}"\n`;
    });

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Portfolio_Master_Save_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleExcelRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split(/\r?\n/);
        const restoredData: any = { properties: [], tenants: [], invoices: [], expenses: [], company: { ...company } };
        let currentSection = '';

        const parseCSVLine = (line: string) => {
          const result = [];
          let current = '';
          let inQuotes = false;
          for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') inQuotes = !inQuotes;
            else if (char === ',' && !inQuotes) { result.push(current.trim()); current = ''; }
            else current += char;
          }
          result.push(current.trim());
          return result;
        };

        lines.forEach(line => {
          const trimmed = line.trim();
          if (!trimmed) return;
          if (trimmed.startsWith("SECTION: PROPERTIES")) { currentSection = 'properties'; return; }
          if (trimmed.startsWith("SECTION: TENANTS")) { currentSection = 'tenants'; return; }
          if (trimmed.startsWith("SECTION: INVOICES")) { currentSection = 'invoices'; return; }
          if (trimmed.startsWith("SECTION: EXPENSES")) { currentSection = 'expenses'; return; }
          if (trimmed.startsWith("ID,") || trimmed.startsWith("Export Date") || trimmed.startsWith("QUEENS")) return;

          const values = parseCSVLine(line);
          if (values.length < 2) return;

          if (currentSection === 'properties') restoredData.properties.push({ id: values[0], name: values[1], type: values[2] as PropertyType, address: values[3] });
          else if (currentSection === 'tenants') restoredData.tenants.push({ id: values[0], name: values[1], email: values[2], phone: values[3], address: values[4], propertyId: values[5], status: values[6] as any });
          else if (currentSection === 'invoices') restoredData.invoices.push({ id: values[0], tenantId: values[1], totalAmount: Number(values[2]), createdAt: values[3], dateOfReceipt: values[4], status: values[5] as InvoiceStatus, billingPeriod: values[6], notes: values[7], items: [] });
          else if (currentSection === 'expenses') restoredData.expenses.push({ id: values[0], propertyId: values[1], amount: Number(values[2]), category: values[3], date: values[4], description: values[5] });
        });

        if (confirm(`RESTORE DATA?\n\nThis will replace your current local database with the file content and restart the app.`)) {
          onRestore(restoredData);
        }
      } catch (err) {
        alert("Restore failed. Invalid file format.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  return (
    <div className="space-y-8 animate-in">
      <header className="flex justify-between items-start">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">PC App Settings</h2>
          <p className="text-slate-500 font-medium">Data is saved locally to your hard drive at: <code className="bg-slate-100 px-1 rounded">browser/localstorage</code></p>
        </div>
        <button 
          onClick={handleInstallClick}
          className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black shadow-lg hover:bg-indigo-700 transition-all flex items-center gap-2"
        >
          🖥️ Install to PC Desktop
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-6">
          <h3 className="text-lg font-black uppercase tracking-widest text-slate-400">Company Information</h3>
          <div className="space-y-4">
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Name</label>
              <input value={company.name} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500" onChange={e => setCompany({...company, name: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Email</label>
              <input value={company.email} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500" onChange={e => setCompany({...company, email: e.target.value})} />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-slate-400 block mb-1 ml-2">Address</label>
              <textarea value={company.address} rows={3} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500" onChange={e => setCompany({...company, address: e.target.value})} />
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-emerald-50 p-8 rounded-[2.5rem] border border-emerald-100 space-y-4">
            <h3 className="text-lg font-black uppercase tracking-widest text-emerald-500">Manual Save to Hard Drive</h3>
            <p className="text-xs text-emerald-700 font-medium leading-relaxed">
              Data is automatically saved to this PC. Use the "Save to File" button below to create a portable physical backup on your hard drive.
            </p>
            <div className="grid grid-cols-1 gap-3">
              <button onClick={exportToExcel} className="w-full bg-white text-emerald-600 border border-emerald-200 p-4 rounded-2xl font-black shadow-sm hover:bg-emerald-100 transition-all active:scale-95">
                💾 Save Portfolio to Hard Drive (CSV)
              </button>
              <input type="file" ref={csvInputRef} className="hidden" accept=".csv" onChange={handleExcelRestore} />
              <button onClick={() => csvInputRef.current?.click()} className="w-full bg-emerald-600 text-white p-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition-all active:scale-95">
                📥 Restore from Hard Drive File
              </button>
            </div>
          </div>

          <div className="bg-rose-50 p-8 rounded-[2.5rem] border border-rose-100 space-y-4">
            <h3 className="text-lg font-black uppercase tracking-widest text-rose-500">Danger Zone</h3>
            <button 
              onClick={onLogout}
              className="w-full bg-white text-rose-600 border border-rose-200 p-4 rounded-2xl font-black shadow-sm hover:bg-rose-100 transition-all"
            >
              🚪 Sign Out of PC App
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

