              <div>
                <h3 className="text-xl font-black">{editingInvoice ? 'Edit Document' : 'Generate Document'}</h3>
                <p className="text-xs text-slate-400 mt-1 uppercase tracking-widest font-bold">Protocol compliant processing</p>
