                <button type="submit" className="w-full bg-indigo-600 text-white p-5 rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all">
                  {editingInvoice ? 'Save Changes' : 'Generate Document'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { Tenant, Property, Invoice, Expense } from '../types';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend 
} from 'recharts';

interface DashboardProps {
  tenants: Tenant[];
  properties: Property[];
  invoices: Invoice[];
  expenses: Expense[];
}

const formatDateDDMMYYYY = (dateStr?: string): string => {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return dateStr;
  const day = String(date.getDate()).padStart(2, '0');
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = date.getFullYear();
  return `${day}-${month}-${year}`;
};

export const Dashboard: React.FC<DashboardProps> = ({ tenants, properties, invoices, expenses }) => {
  const totalRevenue = invoices.reduce((s, i) => s + i.totalAmount, 0);
  const totalExpenses = expenses.reduce((s, e) => s + e.amount, 0);
  const netIncome = totalRevenue - totalExpenses;
  const occupancy = properties.length > 0 ? (tenants.length / properties.length) * 100 : 0;

  const pendingRevenue = invoices
    .filter(inv => inv.status !== 'Paid')
    .reduce((s, i) => s + i.totalAmount, 0);

  const getMonthlyData = () => {
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const currentYear = new Date().getFullYear();
    const data: any[] = [];

    const monthlyRevenue = invoices.reduce((acc: any, inv) => {
      const date = new Date(inv.createdAt);
      if (date.getFullYear() === currentYear) {
        const month = months[date.getMonth()];
        acc[month] = (acc[month] || 0) + inv.totalAmount;
      }
      return acc;
    }, {});

    months.forEach(m => {
      data.push({ name: m, revenue: monthlyRevenue[m] || 0 });
    });

    return data;
  };

  const getExpenseCategoryData = () => {
    const categories = expenses.reduce((acc: any, exp) => {
      acc[exp.category] = (acc[exp.category] || 0) + exp.amount;
      return acc;
    }, {});

    return Object.keys(categories).map(cat => ({
      name: cat,
      value: categories[cat]
    }));
  };

  const chartData = getMonthlyData();
  const expensePieData = getExpenseCategoryData();
  const unitPieData = [
    { name: 'Occupied', value: tenants.length },
    { name: 'Vacant', value: Math.max(0, properties.length - tenants.length) }
  ];

  const COLORS = ['#6366f1', '#f43f5e', '#10b981', '#f59e0b', '#8b5cf6'];
  const STATUS_COLORS = ['#6366f1', '#e2e8f0'];

  return (
    <div className="space-y-8 animate-in">
      <header>
        <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase">Portfolio Dashboard</h2>
        <p className="text-slate-500 font-medium">Global summary of assets, receivables, and expenditures.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard title="Total Revenue" value={`₹${totalRevenue.toLocaleString()}`} icon="💰" color="text-indigo-600" />
        <StatCard title="Total Expenses" value={`₹${totalExpenses.toLocaleString()}`} icon="💸" color="text-rose-600" />
        <StatCard title="Pending Collections" value={`₹${pendingRevenue.toLocaleString()}`} icon="⏳" color="text-amber-600" />
        <StatCard title="Occupancy" value={`${occupancy.toFixed(0)}%`} icon="🏢" color="text-slate-900" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-lg font-black mb-6 uppercase tracking-wider text-slate-400">Revenue Trend ({new Date().getFullYear()})</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 'bold'}}
                />
                <Bar dataKey="revenue" fill="#6366f1" radius={[6, 6, 0, 0]} barSize={32} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col">
          <h3 className="text-lg font-black mb-6 uppercase tracking-wider text-slate-400">Unit Occupancy</h3>
          <div className="flex-1 h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={unitPieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {unitPieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={STATUS_COLORS[index % STATUS_COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36} />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 pt-4 border-t border-slate-50 text-center">
             <p className="text-xs font-black uppercase tracking-widest text-slate-400">Total Units Managed</p>
             <p className="text-2xl font-black text-slate-900">{properties.length}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-lg font-black mb-6 uppercase tracking-wider text-slate-400">Expense Breakdown</h3>
          <div className="h-[300px]">
            {expensePieData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={expensePieData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    outerRadius={100}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {expensePieData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-300 font-bold uppercase tracking-widest text-xs">
                No Expenses Logged
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-lg font-black mb-6 uppercase tracking-wider text-slate-400">Recent Invoices</h3>
          <div className="space-y-4">
            {invoices.length > 0 ? (
              invoices.slice(0, 5).map(inv => (
                <div key={inv.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl hover:bg-slate-100 transition-colors cursor-default">
                  <div>
                    <p className="font-bold text-slate-900">{inv.id}</p>
                    <div className="flex items-center gap-2">
                      <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">{formatDateDDMMYYYY(inv.createdAt)}</p>
                      <span className="text-[10px] text-indigo-300">/</span>
                      <p className="text-[10px] font-black uppercase tracking-widest text-indigo-500">Rec: {formatDateDDMMYYYY(inv.dateOfReceipt)}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-indigo-600">₹{inv.totalAmount.toLocaleString()}</p>
                    <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-md ${
                      inv.status === 'Paid' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'
                    }`}>
                      {inv.status}
                    </span>
                  </div>
                </div>
              ))
            ) : (
              <div className="py-12 text-center text-slate-300">
                <p className="text-sm font-bold uppercase tracking-widest">No activity</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color }: { title: string, value: string, icon: string, color: string }) => (
  <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-4">
    <div className="text-3xl bg-slate-50 w-12 h-12 flex items-center justify-center rounded-2xl">{icon}</div>
    <div>
      <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">{title}</p>
      <p className={`text-xl font-black mt-0.5 ${color}`}>{value}</p>
    </div>
  </div>
);

import React, { useState } from 'react';
import { Tenant, Property, Invoice, CompanyInfo } from '../types';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

interface ReportsProps {
  tenants: Tenant[];
  properties: Property[];
  invoices: Invoice[];
  company: CompanyInfo;
}

type ReportType = 'tenants' | 'properties' | 'invoices' | 'ledger';

const formatDate = (dateStr?: string) => {
  if (!dateStr) return 'N/A';
  const dateParts = dateStr.split('-');
  if (dateParts.length !== 3) return dateStr;
  const [year, month, day] = dateParts;
  return `${day}-${month}-${year}`;
};

export const Reports: React.FC<ReportsProps> = ({ tenants, properties, invoices, company }) => {
  const [reportType, setReportType] = useState<ReportType>('tenants');
  const [selectedTenantId, setSelectedTenantId] = useState<string>('');

  const printReport = () => {
    window.print();
  };

  const exportToCSV = () => {
    let csvContent = "";
    let filename = `report_${reportType}_${new Date().toISOString().split('T')[0]}.csv`;

    if (reportType === 'tenants') {
      csvContent = "Name,Address,Property,Email,Phone,Rent,Maintenance\n";
      tenants.forEach(t => {
        const prop = properties.find(p => p.id === t.propertyId);
        csvContent += `"${t.name}","${t.address || ''}","${prop ? `${prop.type} ${prop.name}` : ''}","${t.email}","${t.phone}","${t.rentAmount}","${t.maintenanceAmount}"\n`;
      });
    } else if (reportType === 'properties') {
      csvContent = "Name,Type,Status\n";
      properties.forEach(p => {
        const status = tenants.some(t => t.propertyId === p.id) ? "Occupied" : "Vacant";
        csvContent += `"${p.name}","${p.type}","${status}"\n`;
      });
    } else if (reportType === 'invoices') {
      csvContent = "ID,Date,Receipt Date,Tenant,Amount,Period,Status\n";
      invoices.forEach(i => {
        const tName = tenants.find(t => t.id === i.tenantId)?.name || 'Unknown';
        csvContent += `"${i.id}","${formatDate(i.createdAt)}","${formatDate(i.dateOfReceipt)}","${tName}","${i.totalAmount}","${i.billingPeriod}","${i.status}"\n`;
      });
    } else if (reportType === 'ledger' && selectedTenantId) {
      const tenant = tenants.find(t => t.id === selectedTenantId);
      const tenantInvoices = invoices.filter(inv => inv.tenantId === selectedTenantId);
      csvContent = `Statement for ${tenant?.name}\nID,Date,Amount,Status\n`;
      tenantInvoices.forEach(i => {
        csvContent += `"${i.id}","${formatDate(i.createdAt)}","${i.totalAmount}","${i.status}"\n`;
      });
    }

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportToPDF = () => {
    const doc = new jsPDF();
    const date = formatDate(new Date().toISOString().split('T')[0]);

    // Header
    doc.setFillColor(15, 23, 42);
    doc.rect(0, 0, 210, 40, 'F');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text(company.name, 14, 20);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`STATEMENT OF ACCOUNT - ${reportType.toUpperCase()}`, 14, 30);
    doc.text(`Generated: ${date}`, 160, 30);

    let head: string[][] = [];
    let body: string[][] = [];
    let startY = 50;

    if (reportType === 'ledger' && selectedTenantId) {
      const tenant = tenants.find(t => t.id === selectedTenantId);
      const prop = properties.find(p => p.id === tenant?.propertyId);
      const tenantInvoices = invoices.filter(inv => inv.tenantId === selectedTenantId);

      doc.setTextColor(15, 23, 42);
      doc.setFontSize(12);
      doc.text(`Tenant: ${tenant?.name}`, 14, 50);
      doc.setFontSize(10);
      doc.text(`Unit: ${prop ? `${prop.type} ${prop.name}` : 'N/A'}`, 14, 56);

      const totalBilled = tenantInvoices.reduce((s, i) => s + i.totalAmount, 0);
      const totalPaid = tenantInvoices.filter(i => i.status === 'Paid').reduce((s, i) => s + i.totalAmount, 0);
      const balance = totalBilled - totalPaid;

      doc.text(`Total Billed: Rs. ${totalBilled.toLocaleString()}`, 140, 50);
      doc.text(`Total Paid: Rs. ${totalPaid.toLocaleString()}`, 140, 56);
      doc.setFont('helvetica', 'bold');
      doc.text(`Outstanding: Rs. ${balance.toLocaleString()}`, 140, 62);

      head = [['Invoice ID', 'Date', 'Billing Period', 'Amount', 'Status']];
      body = tenantInvoices.map(i => [
        i.id,
        formatDate(i.createdAt),
        i.billingPeriod,
        `Rs. ${i.totalAmount.toLocaleString()}`,
        i.status
      ]);
      startY = 70;
    } else if (reportType === 'tenants') {
      head = [['Name', 'Address', 'Property', 'Contact']];
      body = tenants.map(t => {
        const prop = properties.find(p => p.id === t.propertyId);
        return [t.name, t.address || 'N/A', prop ? `${prop.type} ${prop.name}` : 'N/A', `${t.email}\n${t.phone}`];
      });
    } else if (reportType === 'properties') {
      head = [['Name', 'Type', 'Status']];
      body = properties.map(p => {
        const status = tenants.some(t => t.propertyId === p.id) ? "Occupied" : "Vacant";
        return [p.name, p.type, status];
      });
    } else if (reportType === 'invoices') {
      head = [['ID', 'Date', 'Tenant', 'Amount', 'Status']];
      body = invoices.map(i => [
        i.id,
        formatDate(i.createdAt),
        tenants.find(t => t.id === i.tenantId)?.name || 'Unknown',
        `Rs. ${i.totalAmount.toLocaleString()}`,
        i.status
      ]);
    }

    autoTable(doc, {
      startY: startY,
      head: head,
      body: body,
      theme: 'grid',
      headStyles: { fillColor: [79, 70, 229] },
      styles: { fontSize: 9 }
    });

    doc.save(`${reportType}_report_${date}.pdf`);
  };

  return (
    <div className="space-y-6 animate-in">
      <header className="no-print flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight">Account Reports</h2>
          <p className="text-slate-500 font-medium">Financial transparency for your rental portfolio.</p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <button onClick={exportToCSV} className="bg-white text-slate-700 border border-slate-200 px-5 py-2.5 rounded-xl font-bold hover:bg-slate-50 transition-all">📊 CSV</button>
          <button onClick={exportToPDF} className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all">📄 PDF Export</button>
          <button onClick={printReport} className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-slate-800 transition-all">🖨️ Print</button>
        </div>
      </header>

      <div className="flex flex-wrap items-center gap-4 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
        <div className="flex gap-2 p-1 bg-slate-100 rounded-xl border border-slate-200">
          {(['tenants', 'properties', 'invoices', 'ledger'] as const).map((type) => (
            <button
              key={type}
              onClick={() => setReportType(type)}
              className={`px-4 py-2 rounded-lg text-xs font-black uppercase transition-all ${
                reportType === type ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              {type}
            </button>
          ))}
        </div>

        {reportType === 'ledger' && (
          <select 
            className="p-2.5 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none focus:border-indigo-500"
            value={selectedTenantId}
            onChange={(e) => setSelectedTenantId(e.target.value)}
          >
            <option value="">Select Tenant for Statement...</option>
            {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
          </select>
        )}
      </div>

      <div id="printable-report" className="bg-white rounded-[2.5rem] p-10 shadow-sm border border-slate-100">
        <div className="mb-10 flex justify-between items-start border-b border-slate-50 pb-8">
          <div>
            <h1 className="text-3xl font-black text-indigo-600 tracking-tighter uppercase">{company.name}</h1>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Management Division</p>
            <div className="mt-4 text-xs text-slate-500 font-medium leading-relaxed">
              <p>5th Floor, Flat A, 89 Maharshi Karve Road,</p>
              <p>Marine Lines, Mumbai - 400020</p>
              <p className="text-indigo-500">{company.email}</p>
            </div>
          </div>
          <div className="text-right">
            <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest">{reportType} REPORT</h2>
            <p className="text-xs font-black text-slate-400 mt-1">GEN: {formatDate(new Date().toISOString().split('T')[0])}</p>
          </div>
        </div>

        <div className="overflow-x-auto">
          {reportType === 'ledger' && !selectedTenantId ? (
            <div className="py-20 text-center">
              <p className="text-4xl mb-4">🔦</p>
