                  {reportType === 'ledger' && (
                    <>
                      <th className="p-4 text-[10px] font-black uppercase text-slate-400">Invoice ID</th>
                      <th className="p-4 text-[10px] font-black uppercase text-slate-400">Date</th>
                      <th className="p-4 text-[10px] font-black uppercase text-slate-400">Period</th>
                      <th className="p-4 text-[10px] font-black uppercase text-slate-400 text-right">Amount</th>
                      <th className="p-4 text-[10px] font-black uppercase text-slate-400">Status</th>
                    </>
                  )}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {reportType === 'ledger' && invoices.filter(inv => inv.tenantId === selectedTenantId).map(i => (
                  <tr key={i.id} className="hover:bg-slate-50/50">
                    <td className="p-4 text-xs font-bold text-slate-900">{i.id}</td>
                    <td className="p-4 text-xs font-medium text-slate-500">{formatDate(i.createdAt)}</td>
                    <td className="p-4 text-xs font-medium text-slate-500">{i.billingPeriod}</td>
                    <td className="p-4 text-xs font-black text-indigo-600 text-right">₹{i.totalAmount.toLocaleString()}</td>
                    <td className="p-4">
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-md ${
                        i.status === 'Paid' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'
                      }`}>
                        {i.status}
                      </span>
                    </td>
                  </tr>
                ))}
                {reportType === 'tenants' && tenants.map(t => {
                   const prop = properties.find(p => p.id === t.propertyId);
                   return (
                     <tr key={t.id} className="hover:bg-slate-50/50">
                       <td className="p-4 text-xs font-bold text-slate-900">{t.name}</td>
                       <td className="p-4 text-xs font-medium text-slate-500">{prop ? `${prop.type} ${prop.name}` : 'N/A'}</td>
                       <td className="p-4 text-xs font-black text-indigo-600">₹{(t.rentAmount + t.maintenanceAmount).toLocaleString()}</td>
                       <td className="p-4 text-[10px] font-medium text-slate-400">{t.phone}</td>
                     </tr>
                   )
                })}
                {/* ... other standard table rows ... */}
              </tbody>
            </table>
          )}
        </div>

        <div className="mt-12 text-[10px] text-slate-400 font-black uppercase tracking-widest border-t border-slate-50 pt-6 flex justify-between items-center">
          <span>QUEENS CHAMBERS Management Portal</span>
          <span className="text-slate-200">System Signature Code: QC-AUTH-{Date.now().toString().slice(-4)}</span>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

export const generateWhatsAppReminder = async (tenantName: string, amount: number, id: string, dueDate: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Draft a very short, polite WhatsApp message for a tenant named ${tenantName} regarding Invoice ${id}. 
  The amount is ₹${amount.toLocaleString()} and it was due on ${dueDate}. 
  Keep it professional, friendly, and under 40 words. Mention the bank details are in the PDF.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are an assistant for Queens Chambers property management. Tone: Respectful, professional, firm."
      }
    });
    return response.text || "";
  } catch (error) {
    console.error("Gemini Error:", error);
    return `Dear ${tenantName}, friendly reminder for invoice ${id} of ₹${amount}. Please check your email for the PDF. Thanks!`;
  }
};

export const generateCommunication = async (tenantName: string, amount: number) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Write a polite and professional message to a tenant named ${tenantName} regarding their latest rental invoice of ₹${amount}. Format as a short email.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Failed to generate message.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error generating AI response.";
  }
};

export const getFinancialInsights = async (data: any) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Analyze this property data and provide 3 key insights. Data: ${JSON.stringify(data)}. Use ₹ for currency.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a property financial advisor. Provide concise, actionable insights."
      }
    });
    return response.text || "No insights available.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error generating insights.";
  }
};

import React, { useRef, useState, useEffect } from 'react';
import { CompanyInfo, Tenant, Property, Invoice, Expense } from '../types';

interface SystemSettingsProps {
  company: CompanyInfo;
  setCompany: React.Dispatch<React.SetStateAction<CompanyInfo>>;
  tenants: Tenant[];
  properties: Property[];
  invoices: Invoice[];
  expenses: Expense[];
  onLogout: () => void;
  setActiveTab: (tab: string) => void;
  onRestore: (data: any) => void;
}

export const SystemSettings: React.FC<SystemSettingsProps> = ({ 
  company, 
  setCompany, 
  tenants,
  properties,
  invoices,
  expenses,
  onLogout,
  onRestore
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [storageUsage, setStorageUsage] = useState<string>('0 KB');

  useEffect(() => {
    let _lsTotal = 0;
    for (let x in localStorage) {
      if (!localStorage.hasOwnProperty(x)) continue;
      _lsTotal += ((localStorage[x].length + x.length) * 2);
    }
    setStorageUsage((_lsTotal / 1024).toFixed(2) + " KB");
  }, []);

  const exportRollbackSnapshot = () => {
    const data = { 
      company, 
      tenants, 
      properties, 
      invoices, 
      expenses, 
      snapshotDate: new Date().toISOString() 
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `QC_ROLLBACK_POINT_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleRestoreFromFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (confirm("⚠️ ROLL BACK TO PREVIOUS STATE?\n\nThis will overwrite all current data with the contents of this snapshot. This cannot be undone.")) {
          onRestore(data);
        }
      } catch (err) {
        alert("Invalid snapshot file.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  return (
    <div className="space-y-8 animate-in">
      <header>
        <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">System Management</h2>
        <p className="text-slate-500 font-medium">Control cloud sync, snapshots, and data security.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white space-y-6 shadow-2xl relative overflow-hidden">
          <div className="flex justify-between items-center">
            <h3 className="text-sm font-black uppercase tracking-widest text-indigo-400">Data Safety Center</h3>
            <span className="bg-indigo-500/20 text-indigo-300 text-[10px] px-3 py-1 rounded-full font-black uppercase tracking-widest border border-indigo-500/30">Secured</span>
          </div>

          <div className="space-y-4">
            <div className="p-4 bg-slate-800/50 rounded-2xl border border-slate-700">
              <p className="text-[10px] text-slate-400 font-black uppercase mb-1">Local Cache Weight</p>
              <p className="text-xl font-mono font-black text-indigo-300">{storageUsage}</p>
            </div>

            <button 
              onClick={exportRollbackSnapshot}
              className="w-full bg-white text-slate-900 p-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all hover:bg-indigo-50 flex items-center justify-center gap-2"
            >
              📥 Download Rollback Snapshot
            </button>

            <div className="pt-4 border-t border-slate-800">
              <input type="file" ref={fileInputRef} onChange={handleRestoreFromFile} className="hidden" accept=".json" />
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full bg-slate-800 border border-slate-700 text-slate-300 p-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all hover:text-white"
              >
                🔄 Restore to Previous Point
              </button>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-6">
             <h3 className="text-lg font-black uppercase tracking-widest text-slate-400">Branding</h3>
             <div className="space-y-4">
               <div>
                 <label className="text-[10px] font-black uppercase text-slate-400 ml-2 mb-1 block">Full Legal Name</label>
                 <input value={company.name} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500" onChange={e => setCompany({...company, name: e.target.value})} />
               </div>
               <div>
                 <label className="text-[10px] font-black uppercase text-slate-400 ml-2 mb-1 block">Support Email</label>
                 <input value={company.email} className="w-full p-4 bg-slate-50 rounded-xl outline-none font-bold border border-transparent focus:border-indigo-500" onChange={e => setCompany({...company, email: e.target.value})} />
               </div>
             </div>
          </div>

          <button onClick={onLogout} className="w-full bg-rose-50 text-rose-600 border border-rose-100 p-6 rounded-[2rem] font-black shadow-sm hover:bg-rose-600 hover:text-white transition-all uppercase tracking-widest">
            Logout & Lock System
          </button>
        </div>
      </div>
    </div>
  );
};
